-- Poems batch 37
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('ee7331d3-f67c-4339-8071-0dff54723b5e','山中','司空圖','唐','唐诗','tang','','[]','全家與我戀孤岑，蹋得蒼苔一徑深。',64,'全唐诗/poet.tang.34000.json','["全家與我戀孤岑，蹋得蒼苔一徑深。", "逃難人多分隙地，放生麋大出寒林。", "名應不朽輕仙骨，理到忘機近佛心。", "昨夜前溪驟雷雨，晚晴閑步數峰吟。"]'),
('486407cc-1e55-4d48-9ec4-a114294100da','寄贈詩僧秀公','司空圖','唐','唐诗','tang','','[]','靈一心傳清塞心，可公吟後礎公吟。',64,'全唐诗/poet.tang.34000.json','["靈一心傳清塞心，可公吟後礎公吟。", "近來雅道相親少，惟仰吾師所得深。", "好句未停無暇日，舊山歸老有東林。", "冷曹孤宦甘寥落，多謝攜筇數訪尋。"]'),
('47dd5e5a-784c-4887-807f-0f11239b63fa','重陽日訪元秀上人','司空圖','唐','唐诗','tang','','[]','紅葉黃花秋景寬，醉吟朝夕在樊川。',64,'全唐诗/poet.tang.34000.json','["紅葉黃花秋景寬，醉吟朝夕在樊川。", "却嫌今日登山俗，且共高僧對榻眠。", "別畫長懷吳寺壁，宜茶偏賞霅溪泉。", "歸來童穉爭相笑，何事無人與酒船。"]'),
('191a514d-cf9d-4a6d-b5e6-d80e34e324b9','丁未歲歸王官谷','司空圖','唐','唐诗','tang','','[]','家山牢落戰塵西，匹馬偷歸路已迷。',64,'全唐诗/poet.tang.34000.json','["家山牢落戰塵西，匹馬偷歸路已迷。", "塚上卷旗人簇立，花邊移寨鳥驚啼。", "本來薄俗輕文字，却致中原動鼓鼙。", "將取一壺閑日月，長歌深入武陵溪。"]'),
('b98a2b0e-47b3-4b61-bfdb-ed90e776418e','書懷','司空圖','唐','唐诗','tang','','[]','病來猶強引雛行，力上東原欲試耕。',64,'全唐诗/poet.tang.34000.json','["病來猶強引雛行，力上東原欲試耕。", "幾處馬嘶春麥長，一川人喜雪峰晴。", "閑知有味心難肯，道貴謀安迹易平。", "陶令若能兼不飲，無弦琴亦是沽名。"]'),
('86178605-1edd-42bd-be95-27e83bd73670','退棲','司空圖','唐','唐诗','tang','','[]','宦遊蕭索爲無能，移住中條最上層。',64,'全唐诗/poet.tang.34000.json','["宦遊蕭索爲無能，移住中條最上層。", "得劒乍如添健僕，亡書久似失良朋。", "燕昭不是空憐馬，支遁何妨亦愛鷹。", "自此致身繩檢外，肯教世路日兢兢。"]'),
('d9fd7852-b42a-4812-bf67-b5e8c8016eb9','五十','司空圖','唐','唐诗','tang','','[]','閑身事少只題詩，五十今來覺陡衰。',64,'全唐诗/poet.tang.34000.json','["閑身事少只題詩，五十今來覺陡衰。", "清秩偶叨非養望，丹方頻試更堪疑。", "髭鬚強染三分折，弦管遙聽一半悲。", "漉酒有巾無黍釀，負他黃菊滿東籬。"]'),
('c55d268f-15d6-4e13-b0b1-f4a7ae60729a','新歲對寫真','司空圖','唐','唐诗','tang','','[]','得見明時下壽身，須甘歲酒更移巡。',64,'全唐诗/poet.tang.34000.json','["得見明時下壽身，須甘歲酒更移巡。", "生情暗結千重恨，寒勢常欺一半春。", "文武輕銷丹竈火，市朝偏貴黑頭人。", "自傷衰颯慵開鏡，擬與兒童別寫真。"]'),
('4eef68a3-594a-4f31-b0d7-97096d3ecac7','華下','司空圖','唐','唐诗','tang','','[]','籜冠新帶步池塘，逸韻偏宜夏景長。',64,'全唐诗/poet.tang.34000.json','["籜冠新帶步池塘，逸韻偏宜夏景長。", "扶起綠荷承早露，驚迴白鳥入殘陽。", "久無書去干時貴，時有僧來自故鄉。", "不用名山訪真訣，退休便是養生方。"]'),
('4798e715-e669-4f0f-b63c-650c15095569','重陽山居','司空圖','唐','唐诗','tang','','[]','詩人自古恨難窮，暮節登臨且喜同。',64,'全唐诗/poet.tang.34000.json','["詩人自古恨難窮，暮節登臨且喜同。", "四望交親兵亂後，一川風物笛聲中。", "菊殘深處迴幽蝶，陂動晴光下早鴻。", "明日更期來此醉，不堪寂寞對衰翁。"]'),
('de3837af-569a-4108-b84b-690ef095c674','爭名','司空圖','唐','唐诗','tang','','[]','爭名豈在更搜奇，不朽纔消一句詩。',64,'全唐诗/poet.tang.34000.json','["爭名豈在更搜奇，不朽纔消一句詩。", "窮辱未甘英氣阻，乖疎還有正人知。", "荷香浥露侵衣潤，松影和風傍枕移。", "只此共棲塵外境，無妨亦戀好文時。"]'),
('06857fee-89de-4dd0-9da7-c337450a5be4','光啓四年春戊申','司空圖','唐','唐诗','tang','','[]','亂後燒殘數架書，峰前猶自戀吾廬。',64,'全唐诗/poet.tang.34000.json','["亂後燒殘數架書，峰前猶自戀吾廬。", "忘機漸喜逢人少，覽鏡空憐待鶴疎。", "孤嶼池痕春漲滿，小闌花韻午晴初。", "酣歌自適逃名久，不必門多長者車。"]'),
('5b5605e1-f5a3-459a-916c-5121b03f1b93','丁巳重陽','司空圖','唐','唐诗','tang','','[]','重陽未到已登臨，探得黃花且獨斟。',64,'全唐诗/poet.tang.34000.json','["重陽未到已登臨，探得黃花且獨斟。", "客舍喜逢連日雨，家山似響隔河砧。", "亂來已失耕桑計，病後休論濟活心。", "自賀逢時能自棄，歸鞭唯拍馬韉吟。"]'),
('b9fc1bf6-82ba-4faa-8a47-f4fb0c9b72ca','喜王駕小儀重陽相訪','司空圖','唐','唐诗','tang','','[]','白菊初開臥內明，聞君相訪病身輕。',64,'全唐诗/poet.tang.34000.json','["白菊初開臥內明，聞君相訪病身輕。", "樽前且撥傷心事，谿上還隨覓句行。", "幽鶴傍人疑舊識，殘蟬向日噪新晴。", "擬將寂寞同留住，且勸康時立大名。"]'),
('311fbc4b-0fa4-41ae-a87d-8c80e6ab9ea1','酬張芬赦後見寄','司空圖','唐','唐诗','tang','','[]','紫鳳朝銜五色書，陽春忽布網羅除。',64,'全唐诗/poet.tang.34000.json','["紫鳳朝銜五色書，陽春忽布網羅除。", "已將心變寒灰後，豈料光生腐草餘。", "建水風煙收客淚，杜陵花燭夢郊居。", "勞君故有詩相贈，欲報瓊瑤愧不如。"]'),
('3780be15-71e7-4891-b170-b6ea710d9e79','上元放二雉','司空圖','唐','唐诗','tang','','[]','嬰網雖皆困，搴籠喜共歸。',24,'全唐诗/poet.tang.34000.json','["嬰網雖皆困，搴籠喜共歸。", "無心期爾報，相見莫驚飛。"]'),
('3319c91e-c9de-4525-bf10-f4e20620460b','中秋','司空圖','唐','唐诗','tang','','["\u4e2d\u79cb\u8282", "\u79cb\u5929"]','閑吟秋景外，萬事覺悠悠。',24,'全唐诗/poet.tang.34000.json','["閑吟秋景外，萬事覺悠悠。", "此夜若無月，一年虛過秋。"]'),
('2f641475-5695-4fad-b613-2e1ebba9a655','偶題','司空圖','唐','唐诗','tang','','[]','水榭花繁處，春晴日午前。',24,'全唐诗/poet.tang.34000.json','["水榭花繁處，春晴日午前。", "鳥窺臨檻鏡，馬過隔墻鞭。"]'),
('a0a92319-5a60-4ab0-b00d-ada73b9aa429','閑步','司空圖','唐','唐诗','tang','','[]','幾處白煙斷，一川紅樹時。',24,'全唐诗/poet.tang.34000.json','["幾處白煙斷，一川紅樹時。", "壞橋侵轍水，殘照背邨碑。"]'),
('31065db0-80c1-472a-b746-e6e6547ce025','春中','司空圖','唐','唐诗','tang','','[]','伏溜侵堦潤，繁花隔竹香。',24,'全唐诗/poet.tang.34000.json','["伏溜侵堦潤，繁花隔竹香。", "嬌鶯方曉聽，無事過南塘。"]'),
('a6ee39cd-082e-4a6d-b9e6-8eb4c59b0fd8','獨望','司空圖','唐','唐诗','tang','','["\u6625\u5929", "\u5199\u666f"]','綠樹連邨暗，黃花出陌稀。',24,'全唐诗/poet.tang.34000.json','["綠樹連邨暗，黃花出陌稀。", "遠陂春草綠，猶有水禽飛。"]'),
('05a1f262-ccbc-4fc2-9d56-2ef38a836e7e','雜題','司空圖','唐','唐诗','tang','','[]','孤枕聞鶯起，幽懷獨悄然。',24,'全唐诗/poet.tang.34000.json','["孤枕聞鶯起，幽懷獨悄然。", "地融春力潤，花泛曉光鮮。"]'),
('49a3f7b0-2a46-4f86-b8d1-0163b7ef8333','漫題三首 一','司空圖','唐','唐诗','tang','','[]','亂後他鄉節，燒殘故國春。',24,'全唐诗/poet.tang.34000.json','["亂後他鄉節，燒殘故國春。", "自憐垂白首，猶伴踏青人。"]'),
('07ec9936-6a2f-4279-bd89-b6f98a88e0a5','漫題三首 二','司空圖','唐','唐诗','tang','','[]','齒落傷情久，心驚健忘頻。',24,'全唐诗/poet.tang.34000.json','["齒落傷情久，心驚健忘頻。", "蝸廬經歲客，蠶市異鄉人。"]'),
('b144bf27-207a-4850-8ebe-2146dd09c47b','漫題三首 三','司空圖','唐','唐诗','tang','','[]','率怕人言謹，閑宜酒韻高。',24,'全唐诗/poet.tang.34000.json','["率怕人言謹，閑宜酒韻高。", "山林若無慮，名利不難逃。"]'),
('280ea713-4b90-40a5-abde-b4da4f41e038','河上二首 一','司空圖','唐','唐诗','tang','','[]','慘慘日將暮，驅羸獨到莊。',24,'全唐诗/poet.tang.34000.json','["慘慘日將暮，驅羸獨到莊。", "沙痕傍墟落，風色入牛羊。"]'),
('7a52c449-1a0a-4aa0-894a-9e0adb611ca9','河上二首 二','司空圖','唐','唐诗','tang','','[]','新霽田園處，夕陽禾黍明。',24,'全唐诗/poet.tang.34000.json','["新霽田園處，夕陽禾黍明。", "沙邨平見水，深巷有鷗聲。"]'),
('b8a17e69-5eb2-435e-9c5b-2cf161a0f166','早朝','司空圖','唐','唐诗','tang','','[]','白日新年好，青春上國多。',24,'全唐诗/poet.tang.34000.json','["白日新年好，青春上國多。", "街平雙闕近，塵起五雲和。"]'),
('717745d8-0e3c-445b-a0f0-156c33154365','即事二首 一','司空圖','唐','唐诗','tang','','[]','茶爽添詩句，天清瑩道心。',24,'全唐诗/poet.tang.34000.json','["茶爽添詩句，天清瑩道心。", "只留鶴一隻，此外是空林。"]'),
('617d8bb0-d736-4c4e-a5d6-a9a0be6dd30e','即事二首 二','司空圖','唐','唐诗','tang','','[]','御禮徵奇策，人心注盛時。',24,'全唐诗/poet.tang.34000.json','["御禮徵奇策，人心注盛時。", "從來留振滯，只待濟臨危。"]'),
('7050c522-8aa5-4448-aaaf-973b8ae92e2f','永夜','司空圖','唐','唐诗','tang','','[]','永夜疑無日，危時只賴山。',24,'全唐诗/poet.tang.34000.json','["永夜疑無日，危時只賴山。", "曠懷休戚外，孤跡是非間。"]'),
('4292c5dd-41ce-4d02-9217-92be3c63ec3f','秦關','司空圖','唐','唐诗','tang','','[]','形勝今雖在，荒涼恨不窮。',24,'全唐诗/poet.tang.34000.json','["形勝今雖在，荒涼恨不窮。", "虎狼秦國破，狐兔漢陵空。"]'),
('944a15cc-9601-4597-b386-0321203bba65','渡江','司空圖','唐','唐诗','tang','','[]','秋江共僧渡，鄉淚滴船回。',24,'全唐诗/poet.tang.34000.json','["秋江共僧渡，鄉淚滴船回。", "一夜吳船夢，家書立馬開。"]'),
('3fff0b93-48bd-4150-bbca-3b0b4361c708','退居漫題七首 一','司空圖','唐','唐诗','tang','','[]','花缺傷難綴，鶯喧奈細聽。',24,'全唐诗/poet.tang.34000.json','["花缺傷難綴，鶯喧奈細聽。", "惜春春已晚，珍重草青青。"]'),
('25119b26-d21f-4e1e-bf06-0f1f95756dbb','退居漫題七首 二','司空圖','唐','唐诗','tang','','[]','堤柳自綿綿，幽人無恨牽。',24,'全唐诗/poet.tang.34000.json','["堤柳自綿綿，幽人無恨牽。", "只憂詩病發，莫寄校書牋。"]'),
('642434a5-f200-4aeb-8e5a-ebbc865b7388','退居漫題七首 三','司空圖','唐','唐诗','tang','','[]','燕語曾來客，花催欲別人。',24,'全唐诗/poet.tang.34000.json','["燕語曾來客，花催欲別人。", "莫愁春又過，看著又新春。"]'),
('396d028e-3b74-4aa6-9dc6-3925946fb683','退居漫題七首 四','司空圖','唐','唐诗','tang','','[]','身外都無事，山中久避喧。',24,'全唐诗/poet.tang.34000.json','["身外都無事，山中久避喧。", "破巢看乳燕，留果待啼猨。"]'),
('1461e938-82d2-49d2-aa04-5b73297345cb','退居漫題七首 五','司空圖','唐','唐诗','tang','','[]','詩家通籍美，工部與司勳。',24,'全唐诗/poet.tang.34000.json','["詩家通籍美，工部與司勳。", "高賈雖難敵，微官偶勝君。"]'),
('deae5910-8623-45d8-89af-a575d1375064','退居漫題七首 六','司空圖','唐','唐诗','tang','','[]','努力省前非，人生上壽稀。',24,'全唐诗/poet.tang.34000.json','["努力省前非，人生上壽稀。", "青雲無直道，暗室有危機。"]'),
('5f3f3134-b1eb-491d-bde2-70d1bedcc008','退居漫題七首 七','司空圖','唐','唐诗','tang','','[]','燕拙營巢苦，魚貪觸網驚。',24,'全唐诗/poet.tang.34000.json','["燕拙營巢苦，魚貪觸網驚。", "豈緣身外事，亦似我勞形。"]'),
('bb908820-e2ba-4788-9750-8bf7eb1430f7','即事九首 一','司空圖','唐','唐诗','tang','','[]','宿雨川原霽，憑高景物新。',24,'全唐诗/poet.tang.34000.json','["宿雨川原霽，憑高景物新。", "陂痕侵牧馬，雲影帶耕人。"]'),
('35829ea4-b74c-40b2-8752-f567b510952c','即事九首 二','司空圖','唐','唐诗','tang','','[]','十年深隱地，一雨太平心。',24,'全唐诗/poet.tang.34000.json','["十年深隱地，一雨太平心。", "匣澀休看劒，窗明復上琴。"]'),
('d343c673-5610-4d3b-90b0-aabab2e55652','即事九首 三','司空圖','唐','唐诗','tang','','[]','明時那棄置，多病自遲留。',24,'全唐诗/poet.tang.34000.json','["明時那棄置，多病自遲留。", "疎磬和吟斷，殘燈照臥幽。"]'),
('8e835e0a-55bf-4543-95f5-01226f0a4178','即事九首 四','司空圖','唐','唐诗','tang','','[]','衰鬢閑生少，丹梯望覺危。',24,'全唐诗/poet.tang.34000.json','["衰鬢閑生少，丹梯望覺危。", "松須依石長，鶴不傍人卑。"]'),
('47aada3f-adea-49a9-8a3a-d8bb68d0dd0e','即事九首 五','司空圖','唐','唐诗','tang','','[]','落葉頻驚鹿，連峰欲映鵰。',24,'全唐诗/poet.tang.34000.json','["落葉頻驚鹿，連峰欲映鵰。", "此生詩病苦，此病更蕭條。"]'),
('fdeb6658-1969-42fb-a884-c04a37a751c6','即事九首 六','司空圖','唐','唐诗','tang','','[]','旅思又驚夏，庭前長小松。',24,'全唐诗/poet.tang.34000.json','["旅思又驚夏，庭前長小松。", "遠峰生貴氣，殘月歛衰容。"]'),
