('7b8b9f5e-95de-44e7-8659-e4f60090292a','山鵲','司空圖','唐','唐诗','tang','','[]','多驚本爲好毛衣，只賴人憐始却歸。',32,'全唐诗/poet.tang.35000.json','["多驚本爲好毛衣，只賴人憐始却歸。", "衆鳥自知顏色減，妬他偏向眼前飛。"]'),
('19935893-8dc1-47a4-b7ce-4637321baa65','李居士','司空圖','唐','唐诗','tang','','[]','高風只在五峰前，應是精靈降作賢。',32,'全唐诗/poet.tang.35000.json','["高風只在五峰前，應是精靈降作賢。", "萬里無雲惟一鶴，鄉中同看却昇天。"]'),
('c8fd429d-5cdf-4bda-9d0f-e04f12f224af','杏花','司空圖','唐','唐诗','tang','','[]','詩家偏爲此傷情，品韻由來莫與爭。',32,'全唐诗/poet.tang.35000.json','["詩家偏爲此傷情，品韻由來莫與爭。", "解笑亦應兼解語，只應慵語倩鶯聲。"]'),
('0df27fd6-291b-49e4-9e42-94afbbbae717','白菊三首 一','司空圖','唐','唐诗','tang','','[]','不疑陶令是狂生，作賦其如有定情。',32,'全唐诗/poet.tang.35000.json','["不疑陶令是狂生，作賦其如有定情。", "猶勝江南隱居士，詩魔終嫋負孤名。"]'),
('f2218791-f432-4923-a93b-129a18f62b01','白菊三首 二','司空圖','唐','唐诗','tang','','[]','自古詩人少顯榮，逃名何用更題名。',32,'全唐诗/poet.tang.35000.json','["自古詩人少顯榮，逃名何用更題名。", "詩中有慮猶須戒，莫向詩中著不平。"]'),
('7132b3db-7589-4865-aea2-d616d82d73c9','白菊三首 三','司空圖','唐','唐诗','tang','','[]','登高可羨少年場，白菊堆邊鬢似霜。',32,'全唐诗/poet.tang.35000.json','["登高可羨少年場，白菊堆邊鬢似霜。", "益算更希沾上藥，今朝第七十重陽。"]'),
('2a0c9721-e1cf-417b-bc69-775f13936a4c','聽雨','司空圖','唐','唐诗','tang','','[]','半夜思家睡裏愁，雨聲落落屋簷頭。',32,'全唐诗/poet.tang.35000.json','["半夜思家睡裏愁，雨聲落落屋簷頭。", "照泥星出依前黑，淹爛庭花不肯休。"]'),
('88c1d03c-457c-4f61-a7ee-0a896c02606a','楊柳枝二首 一','司空圖','唐','唐诗','tang','','[]','陶家五柳簇衡門，還有高情愛此君。',32,'全唐诗/poet.tang.35000.json','["陶家五柳簇衡門，還有高情愛此君。", "何處更添詩境好，新蟬欹枕每先聞。"]'),
('6da4721a-bf15-4aac-895e-db29bbadccd6','楊柳枝二首 二','司空圖','唐','唐诗','tang','','[]','數枝珍重蘸滄浪，無限塵心暫免忙。',32,'全唐诗/poet.tang.35000.json','["數枝珍重蘸滄浪，無限塵心暫免忙。", "煩暑若和煙露裛，便同佛手灑清涼。"]'),
('35c4388a-1d08-4c2f-a78d-da44e522ce40','修史亭二首 一','司空圖','唐','唐诗','tang','','[]','少年已慣擲年光，時節催驅獨不忙。',32,'全唐诗/poet.tang.35000.json','["少年已慣擲年光，時節催驅獨不忙。", "今日無疑亦無病，前程無事擾醫王。"]'),
('50b9e489-4ffe-4b5b-aad3-b4a6d274e4fe','修史亭二首 二','司空圖','唐','唐诗','tang','','[]','籬落輕寒整頓新，雪晴步屣會諸鄰。',32,'全唐诗/poet.tang.35000.json','["籬落輕寒整頓新，雪晴步屣會諸鄰。", "自從南至歌風頂，始見人煙外有人。"]'),
('aa67069a-e4c0-4249-948b-a2e29418896e','漫書','司空圖','唐','唐诗','tang','','[]','樂退安貧知是分，成家報國亦何慚。',32,'全唐诗/poet.tang.35000.json','["樂退安貧知是分，成家報國亦何慚。", "到還僧院心期在，瑟瑟澄鮮百丈潭。"]'),
('9c2e1267-c71b-4f73-ab65-ae7eda3c3870','雜題二首 一','司空圖','唐','唐诗','tang','','[]','棋局長攜上釣船，殺中棋殺勝絲牽。',32,'全唐诗/poet.tang.35000.json','["棋局長攜上釣船，殺中棋殺勝絲牽。", "洪鑪任鑄千鈞鼎，只在磻溪一縷懸。"]'),
('5f6a9b54-b12d-4b55-b209-a82b4cacb0b5','雜題二首 二','司空圖','唐','唐诗','tang','','[]','曉鏡高窗氣象深，自憐清格笑塵心。',32,'全唐诗/poet.tang.35000.json','["曉鏡高窗氣象深，自憐清格笑塵心。", "世間不爲蛾眉誤，海上方應鶴背吟。"]'),
('77fb33d6-6073-4147-b1c8-1673dfdd6856','題休休亭','司空圖','唐','唐诗','tang','','[]','咄，諾。',80,'全唐诗/poet.tang.35000.json','["咄，諾。", "休休休，莫莫莫。", "伎兩雖多性靈惡，賴是長教閑處著。", "休休休，莫莫莫。", "一局棋，一爐藥。", "天意時情可料度，白日偏催快活人。", "黃金難買堪騎鶴，若曰爾何能，荅言耐辱莫。"]'),
('8fbb614c-d10f-4780-a112-b37130fbbc02','馮燕歌','司空圖','唐','唐诗','tang','','["\u9ec4\u6cb3"]','魏中義士有馮燕，遊俠幽幷最少年。',386,'全唐诗/poet.tang.35000.json','["魏中義士有馮燕，遊俠幽幷最少年。", "避讐偶作滑臺客，嘶風躍馬來翩翩。", "此時恰遇鶯花月，堤上軒車晝不絕。", "兩面高樓語笑聲，指點行人情暗結。", "擲果潘郎誰不慕，朱門別見紅妝露。", "故故推門掩不開，似教歐軋傳言語。", "馮生敲鐙袖籠鞭，半拂垂楊半惹煙。", "樹間春鳥知人意，的的心期暗與傳。", "傳道張嬰偏嗜酒，從此香閨爲我有。", "梁間客燕正相欺，屋上鳴鳩空自鬬。", "嬰歸醉臥非讐汝，豈知負過人懷懼。", "燕依戶扇欲潛逃，巾在枕傍指令取。", "誰言狼戾心能忍，待我情深情不隱。", "回身本謂取巾難，倒柄方知授霜刅。", "馮君撫劒即遲疑，自顧平生心不欺。", "爾能負彼必相負，假手他人復在誰。", "窗間紅豔猶可掬，熟視花鈿情不足。", "唯將大義斷胸襟，粉頸初迴如切玉。", "鳳皇釵碎各分飛，怨魄嬌魂何處追。", "凌波如喚遊金谷，羞彼[揶揄]淚滿衣。", "新人藏匿舊人起，白晝喧呼駭鄰里。", "誣執張嬰不自明，貴免生前遭考捶。", "官將赴市擁紅塵，掉臂人來擗看人。", "傳聲莫遣有冤濫，盜殺嬰家即我身。"]'),
('02a1128d-e315-4e89-8450-b3e7dca1029d','寄薛起居','司空圖','唐','唐诗','tang','','[]','小域新銜賀聖朝，亦知蹇分巧難拋。',32,'全唐诗/poet.tang.35000.json','["小域新銜賀聖朝，亦知蹇分巧難拋。", "麤才自合無岐路，不破工夫漫解嘲。"]'),
('d1cac948-8ede-4d0e-9bd9-c6f99763542a','月下留丹竈','司空圖','唐','唐诗','tang','','[]','月下留丹竈，壇邊樹羽衣。',48,'全唐诗/poet.tang.35000.json','["月下留丹竈，壇邊樹羽衣。", "異香人不覺，殘夜鶴分飛。", "朝會初元盛，蓬瀛舊侶稀。", "瑤函真跡在，妖魅敢揚威。"]'),
('11e600f4-b6e0-4caf-b752-3442cad3291b','元日','司空圖','唐','唐诗','tang','','[]','甲子今重數，生涯只自憐。',24,'全唐诗/poet.tang.35000.json','["甲子今重數，生涯只自憐。", "殷勤元日日，欹午又明年。"]'),
('989b140b-b6be-4437-abc8-427d0cfae843','洛陽詠古','司空圖','唐','唐诗','tang','','[]','石勒童年有戰機，洛陽長嘯倚門時。',32,'全唐诗/poet.tang.35000.json','["石勒童年有戰機，洛陽長嘯倚門時。", "晉朝不是王夷甫，大智何由得預知。"]'),
('b5a93088-0dcb-49d7-baa0-38d17360acb4','詩品二十四則 雄渾','司空圖','唐','唐诗','tang','','[]','大用外腓，真體內充。',60,'全唐诗/poet.tang.35000.json','["大用外腓，真體內充。", "返虛入渾，積健爲雄。", "具備萬物，橫絕太空。", "荒荒油雲，寥寥長風。", "超以象外，得其環中。", "持之匪強，來之無窮。"]'),
('c73e26d9-454f-4413-8acd-906d1aa3e662','詩品二十四則 沖淡','司空圖','唐','唐诗','tang','','[]','素處以默，妙機其微。',60,'全唐诗/poet.tang.35000.json','["素處以默，妙機其微。", "飲之太和，獨鶴與飛。", "猶之惠風，苒苒在衣。", "閱音修篁，美曰載歸。", "遇之匪深，即之愈稀。", "脫有形似，握手已違。"]'),
('f83171b8-7a62-4eaf-b2cc-470914576177','詩品二十四則 纖穠','司空圖','唐','唐诗','tang','','[]','采采流水，蓬蓬遠春。',60,'全唐诗/poet.tang.35000.json','["采采流水，蓬蓬遠春。", "窈窕深谷，時見美人。", "碧桃滿樹，風日水濱。", "柳陰路曲，流鶯比鄰。", "乘之愈往，識之愈真。", "如將不盡，與古爲新。"]'),
('2f60329c-6fbf-4e79-b001-933f90311d37','詩品二十四則 沈著','司空圖','唐','唐诗','tang','','[]','綠杉野屋，落日氣清。',60,'全唐诗/poet.tang.35000.json','["綠杉野屋，落日氣清。", "脫巾獨步，時聞鳥聲。", "鴻鴈不來，之子遠行。", "所思不遠，若爲平生。", "海風碧雲，夜渚月明。", "如有佳語，大河前橫。"]'),
('96104c85-c9df-4967-8fd3-a33d09cd71cb','詩品二十四則 高古','司空圖','唐','唐诗','tang','','[]','畸人乘真，手把芙蓉。',60,'全唐诗/poet.tang.35000.json','["畸人乘真，手把芙蓉。", "泛彼浩劫，窅然空縱。", "月出東斗，好風相從。", "太華夜碧，人聞清鐘。", "虛佇神素，脫然畦封。", "黃唐在獨，落落玄宗。"]'),
('0d555cb2-83cb-4962-9048-867be0255a3d','詩品二十四則 典雅','司空圖','唐','唐诗','tang','','[]','玉壺買春，賞雨茆屋。',60,'全唐诗/poet.tang.35000.json','["玉壺買春，賞雨茆屋。", "坐中佳士，左右修竹。", "白雲初晴，幽鳥相逐。", "眠琴綠陰，上有飛瀑。", "落花無言，人淡如菊。", "書之歲華，其曰可讀。"]'),
('ef2f3ad2-6df1-4519-ab0e-ae19a456cb6b','詩品二十四則 洗煉','司空圖','唐','唐诗','tang','','[]','猶鑛出金，如鉛出銀。',62,'全唐诗/poet.tang.35000.json','["猶鑛出金，如鉛出銀。", "超心煉冶，絕愛[緇]磷。", "空潭瀉春，古鏡照神。", "體素儲潔，乘月返真。", "載瞻星辰，載歌幽人。", "流水今日，明月前身。"]'),
('5dbdddda-95ab-4546-bd08-654ef2d08586','詩品二十四則 勁健','司空圖','唐','唐诗','tang','','[]','行神如空，行氣如虹。',60,'全唐诗/poet.tang.35000.json','["行神如空，行氣如虹。", "巫峽千尋，走雲連風。", "飲真茹強，蓄素守中。", "喻彼行健，是謂存雄。", "天地與立，神化攸同。", "期之以實，御之以終。"]'),
('b406fec9-9888-4ba7-bcc1-44aea1fb1d2a','詩品二十四則 綺麗','司空圖','唐','唐诗','tang','','[]','神存富貴，始輕黃金。',60,'全唐诗/poet.tang.35000.json','["神存富貴，始輕黃金。", "濃盡必枯，淺者屢深。", "露餘山青，紅杏在林。", "月明華屋，畫橋碧陰。", "金尊酒滿，共客彈琴。", "取之自足，良殫美襟。"]'),
('026db8ed-2a59-495f-a4e5-25556b033624','詩品二十四則 自然','司空圖','唐','唐诗','tang','','[]','俯拾即是，不取諸鄰。',60,'全唐诗/poet.tang.35000.json','["俯拾即是，不取諸鄰。", "俱道適往，著手成春。", "如逢花開，如瞻歲新。", "真予不奪，強得易貧。", "幽人空山，過水采蘋。", "薄言情晤，悠悠天鈞。"]'),
('4c871d1f-0985-4ae8-b0d3-9f0ba929a0ec','詩品二十四則 含蓄','司空圖','唐','唐诗','tang','','[]','不著一字，盡得風流。',60,'全唐诗/poet.tang.35000.json','["不著一字，盡得風流。", "語不涉難，已不堪憂。", "是有真宰，與之沈浮。", "如淥滿酒，花時返秋。", "悠悠空塵，忽忽海漚。", "淺深聚散，萬取一收。"]'),
('1e802371-0491-47f3-8981-97898b118867','詩品二十四則 豪放','司空圖','唐','唐诗','tang','','[]','觀花匪禁，吞吐大荒。',60,'全唐诗/poet.tang.35000.json','["觀花匪禁，吞吐大荒。", "由道返氣，處得以狂。", "天風浪浪，海山蒼蒼。", "真力彌滿，萬象在旁。", "前招三辰，後引鳳皇。", "曉策六鼇，濯足扶桑。"]'),
('b23d4003-2d86-43a6-b3a5-d8167828d08f','詩品二十四則 精神','司空圖','唐','唐诗','tang','','[]','欲返不盡，相期與來。',60,'全唐诗/poet.tang.35000.json','["欲返不盡，相期與來。", "明漪絕底，奇花初胎。", "青春鸚鵡，楊柳池臺。", "碧山人來，清酒滿杯。", "生氣遠出，不著死灰。", "妙造自然，伊誰與裁。"]'),
('72ad7b55-75ba-419d-8dd1-26f9d4db11ef','詩品二十四則 縝密','司空圖','唐','唐诗','tang','','[]','是有真跡，如不可知。',60,'全唐诗/poet.tang.35000.json','["是有真跡，如不可知。", "意象欲生，造化已奇。", "水流花開，清露未晞。", "要路愈遠，幽行爲遲。", "語不欲犯，思不欲癡。", "猶春於綠，明月雪時。"]'),
('6bf0d96c-74c2-4f65-b53d-c50571102a1d','詩品二十四則 疎野','司空圖','唐','唐诗','tang','','[]','惟性所宅，真取弗羈。',60,'全唐诗/poet.tang.35000.json','["惟性所宅，真取弗羈。", "拾物自富，與率爲期。", "築屋松下，脫帽看詩。", "但知旦暮，不辨何時。", "倘然適意，豈必有爲。", "若其天放，如是得之。"]'),
('2fb29e78-7a6d-494c-83b5-cfdbc6d1a4fe','詩品二十四則 清奇','司空圖','唐','唐诗','tang','','[]','娟娟羣松，下有漪流。',60,'全唐诗/poet.tang.35000.json','["娟娟羣松，下有漪流。", "晴雪滿汀，隔溪漁舟。", "可人如玉，步屧尋幽。", "載行載止，空碧悠悠。", "神出古異，淡不可收。", "如月之曙，如氣之秋。"]'),
('5c940e34-3fda-4ef2-9268-45524a413e02','詩品二十四則 委曲','司空圖','唐','唐诗','tang','','[]','登彼太行，翠遶羊腸。',60,'全唐诗/poet.tang.35000.json','["登彼太行，翠遶羊腸。", "杳靄流玉，悠悠花香。", "力之於時，聲之於羌。", "似往已迴，如幽匪藏。", "水理漩洑，鵬風翱翔。", "道不自器，與之圓方。"]'),
('d21d01c8-0d64-4d33-a827-2533ed66331a','詩品二十四則 實境','司空圖','唐','唐诗','tang','','[]','取語甚直，計思匪深。',60,'全唐诗/poet.tang.35000.json','["取語甚直，計思匪深。", "忽逢幽人，如見道心。", "晴磵之曲，碧松之陰。", "一客荷樵，一客聽琴。", "情性所至，妙不自尋。", "遇之自天，冷然希音。"]'),
('077e468a-ec52-468b-b76f-2024c7bb8924','詩品二十四則 悲慨','司空圖','唐','唐诗','tang','','[]','大風捲水，林木爲摧。',60,'全唐诗/poet.tang.35000.json','["大風捲水，林木爲摧。", "意苦若死，招憩不來。", "百歲如流，富貴冷灰。", "大道日往，若爲雄才。", "壯士拂劒，浩然彌哀。", "蕭蕭落葉，漏雨蒼苔。"]'),
('2f623830-7ea6-45f5-9a9c-35724dd4c1ef','詩品二十四則 形容','司空圖','唐','唐诗','tang','','[]','絕佇靈素，少迴清真。',60,'全唐诗/poet.tang.35000.json','["絕佇靈素，少迴清真。", "如覓水影，如寫陽春。", "風雲變態，花草精神。", "海之波瀾，山之嶙峋。", "俱似大道，妙契同塵。", "離形得似，庶幾斯人。"]'),
('f4442282-304d-4418-a7b2-683aa859e9e2','詩品二十四則 超詣','司空圖','唐','唐诗','tang','','[]','匪神之靈，匪機之微。',60,'全唐诗/poet.tang.35000.json','["匪神之靈，匪機之微。", "如將白雲，清風與歸。", "遠引若至，臨之已非。", "少有道契，終與俗違。", "亂山高木，碧苔芳暉。", "誦之思之，其聲愈稀。"]'),
('09aa04f9-1153-4c1b-8b67-ac9c905fdc74','詩品二十四則 飄逸','司空圖','唐','唐诗','tang','','[]','落落欲往，矯矯不羣。',60,'全唐诗/poet.tang.35000.json','["落落欲往，矯矯不羣。", "緱山之鶴，華頂之雲。", "高人畫中，令色絪緼。", "御風蓬葉，泛彼無垠。", "如不可執，如將有聞。", "識者已領，期之愈分。"]'),
('2c9e4874-a933-4ae0-ac01-4c0bfc39d6c5','詩品二十四則 曠達','司空圖','唐','唐诗','tang','','[]','生者百歲，相去幾何。',60,'全唐诗/poet.tang.35000.json','["生者百歲，相去幾何。", "歡樂苦短，憂愁實多。", "何如尊酒，日往烟蘿。", "花覆茆簷，疎雨相過。", "倒酒既盡，杖藜行過。", "孰不有古，南山峨峨。"]'),
('130fc4ff-8f1d-4785-8e4f-8f2417d9ecda','詩品二十四則 流動','司空圖','唐','唐诗','tang','','[]','若納水輨，如轉丸珠。',60,'全唐诗/poet.tang.35000.json','["若納水輨，如轉丸珠。", "夫豈可道，假體遺愚。", "荒荒坤軸，悠悠天樞。", "載要其端，載同其符。", "超超神明，返返冥無。", "來往千載，是之謂乎。"]'),
('313efe5c-4f68-48c6-9ee1-d85613a4c47c','句','司空圖','唐','唐诗','tang','','[]','忍事敵災星，物望傾心久。',198,'全唐诗/poet.tang.35000.json','["忍事敵災星，物望傾心久。", "兇渠破膽頻。", "鼎飫和方濟，台階潤欲平。", "夜短猨悲減，風和鵲喜虛。", "驊騮思故第，鸚鵡失佳人。", "鯨鯢人海涸，魑魅棘林幽。", "棋聲花院閉，幡影石壇高。", "地涼清鶴夢，林靜肅僧儀。", "晚妝留拜月，春睡更生香。", "隔谷見雞犬，山苗接楚田。", "人家寒食月，花影午時天。", "官路好禽聲，軒車駐晚程。", "南樓山最秀，北路邑偏清。", "多病形容五十三，誰鄰借笏趂朝參。", "十年太華無知己，只得虛中兩首詩。", "看師逸蹟兩師宜，高適歌行李白詩。"]'),
('6b74a409-0c54-4a99-a245-972e4189538a','送邊上從事','周繇','唐','唐诗','tang','','["\u9ec4\u6cb3"]','戎裝佩鏌鎁，走馬逐輕車。',48,'全唐诗/poet.tang.35000.json','["戎裝佩鏌鎁，走馬逐輕車。", "衰草城邊路，殘陽壟上笳。", "黃河穿漢界，青塚出胡沙。", "提筆男兒事，功名立可誇。"]'),
('90fa4bcb-cd80-4581-9b9a-b3585352f32b','送洛陽崔員外','周繇','唐','唐诗','tang','','[]','塞詔除嵩洛，觀圖見廢興。',48,'全唐诗/poet.tang.35000.json','["塞詔除嵩洛，觀圖見廢興。", "城遷周古鼎，地列漢諸陵。", "日送歸朝客，時招住嶽僧。", "郡齋臺閣滿，公退即吟登。"]'),
('e46e44bb-4ccd-4871-96c0-12f553308737','送人尉黔中','周繇','唐','唐诗','tang','','[]','盤山行幾驛，水路復通巴。',48,'全唐诗/poet.tang.35000.json','["盤山行幾驛，水路復通巴。", "峽漲三川雪，園開四季花。", "公庭飛白鳥，官俸請丹砂。", "知尉黔中後，高吟採物華。"]'),
('5778262b-2266-4763-bc02-3a4c6755d703','送宇文虞','周繇','唐','唐诗','tang','','[]','此別欲何往，未言歸故林。',48,'全唐诗/poet.tang.35000.json','["此別欲何往，未言歸故林。", "行車新歲近，落日亂山深。", "野店寒無客，風巢動有禽。", "潛知經目事，大半是愁吟。"]'),
('4bc8ad07-4f52-416f-b7f3-cc2e4d90874e','題東林寺虎掊泉','周繇','唐','唐诗','tang','','[]','勝致通幽感，靈泉有虎掊。',48,'全唐诗/poet.tang.35000.json','["勝致通幽感，靈泉有虎掊。", "爪擡山脉斷，掌託石心抝。", "竹藹疑相近，松陰蓋亦交。", "轉令棲遁者，真境逾難拋。"]'),
('b5175c34-da87-4de6-b3bc-a935b346fa8e','登甘露寺','周繇','唐','唐诗','tang','','[]','盤江上幾層，峭壁半垂藤。',48,'全唐诗/poet.tang.35000.json','["盤江上幾層，峭壁半垂藤。", "殿鎖南朝像，龕禪外國僧。", "海濤摏砌檻，山雨灑窗燈。", "日暮疎鐘起，聲聲徹廣陵。"]'),
('18de435e-9774-4859-827c-0bcf1d6532ea','甘露寺東軒','周繇','唐','唐诗','tang','','[]','每日憐晴眺，閑吟只自娛。',48,'全唐诗/poet.tang.35000.json','["每日憐晴眺，閑吟只自娛。", "山從平地有，水到遠天無。", "老樹多封楚，輕烟暗染吳。", "雖居此廊下，入戶亦躊躕。"]'),
('f301fd18-267d-4f8a-90c6-e047caaad7bd','甘露寺北軒','周繇','唐','唐诗','tang','','[]','曉色宜閑望，山風遠益清。',48,'全唐诗/poet.tang.35000.json','["曉色宜閑望，山風遠益清。", "白雲連晉閣，碧樹盡蕪城。", "水靜沙痕出，煙消野火平。", "最堪佳此境，爲我長詩情。"]'),
('a4dea634-027d-45fc-908b-5372ec05fc91','詠螢','周繇','唐','唐诗','tang','','[]','熠熠與娟娟，池塘竹樹邊。',48,'全唐诗/poet.tang.35000.json','["熠熠與娟娟，池塘竹樹邊。", "亂飛同曳火，成聚却無煙。", "微雨灑不滅，清風吹欲燃。", "舊曾書按上，頻把作囊懸。"]'),
('8bae582b-62ab-47f6-8d66-2f05b9594c1b','望海','周繇','唐','唐诗','tang','','[]','蒼茫空泛日，四顧絕人煙。',48,'全唐诗/poet.tang.35000.json','["蒼茫空泛日，四顧絕人煙。", "半浸中華岸，旁通異域船。", "島間應有國，波外恐無天。", "欲作乘槎客，翻愁去隔年。"]'),
('e89ddbad-2fc3-4151-870e-cda45036116c','送楊環校書歸廣南','周繇','唐','唐诗','tang','','[]','天南行李半波濤，灘樹枝枝拂戲猱。',64,'全唐诗/poet.tang.35000.json','["天南行李半波濤，灘樹枝枝拂戲猱。", "初著藍衫從遠嶠，乍辭雲署泊輕艘。", "山村象踏桄榔葉，海外人收翡翠毛。", "名宦兩成歸舊隱，徧尋親友興何饒。"]'),
('e7d21ab1-31ff-4123-a86d-b1fdba206429','經故宅有感','周繇','唐','唐诗','tang','','[]','身沒南荒雨露賒，朱門空鎖舊繁華。',64,'全唐诗/poet.tang.35000.json','["身沒南荒雨露賒，朱門空鎖舊繁華。", "池塘鑿就方通水，桃杏栽成未見花。", "異代圖書藏幾篋，傾城羅綺散誰家。", "昔年埏埴生靈地，今日生人爲歎嗟。"]'),
('76c5af8f-e68d-45fe-a0b0-3f1f0f029dc4','送入蕃使','周繇','唐','唐诗','tang','','[]','獵獵旗幡過大荒，敕書猶帶御烟香。',64,'全唐诗/poet.tang.35000.json','["獵獵旗幡過大荒，敕書猶帶御烟香。", "滹沱河凍軍迴探，邏逤城孤雁著行。", "遠寨風狂移帳幕，平沙日晚臥牛羊。", "早終冊禮朝天闕，莫遣虬髭染塞霜。"]'),
('ee815980-f7ce-4628-bd99-698fff712372','白石潭秋霽作','周繇','唐','唐诗','tang','','[]','潭心烟霧破斜暉，殷殷雷聲隔翠微。',64,'全唐诗/poet.tang.35000.json','["潭心烟霧破斜暉，殷殷雷聲隔翠微。", "崖蹙盤渦翻蜃窟，灘吹白石上漁磯。", "陵風舴艋謳啞去，出水鸕鷀薄泊飛。", "秋霽更誰同此望，遠鐘時見一僧歸。"]'),
('b104e53e-499e-4cc7-9366-789933cd7f7a','題金陵栖霞寺贈月公','周繇','唐','唐诗','tang','','[]','明家不要買山錢，施作清池種白蓮。',64,'全唐诗/poet.tang.35000.json','["明家不要買山錢，施作清池種白蓮。", "松檜老依雲外地，樓臺深鎖洞中天。", "風經絕頂迴疎雨，石倚危屏挂落泉。", "欲結茅菴伴師住，肯饒多少薜蘿煙。"]'),
('0ae94ce0-264f-41e6-9b8e-e3e19bbe52d9','嘲段成式','周繇','唐','唐诗','tang','','[]','蹙鞠且徒爲，寧如目送時。',72,'全唐诗/poet.tang.35000.json','["蹙鞠且徒爲，寧如目送時。", "報讐慙選耎，存想恨逶遲。", "促坐疑辟咡，銜盃強朵頤。", "恣情窺窈窕，曾恃好風姿。", "色授應難奪，神交願莫辭。", "請君看曲譜，不負少年期。"]'),
('04daf8cf-e075-4739-9ad3-e8e092d9e8aa','送江州薛尚書','周繇','唐','唐诗','tang','','["\u5e90\u5c71"]','匡廬千萬峯，影匝郡城中。',72,'全唐诗/poet.tang.35000.json','["匡廬千萬峯，影匝郡城中。", "忽佩虎符去，遙疑鳥道通。", "煙霞時滿郭，波浪暮連空。", "樹翳樓臺月，帆飛鼓角風。", "郡齋多嶽客，鄉戶半漁翁。", "王事行春外，題詩寄遠公。"]'),
('b4ae1def-f4ff-45f2-a4a8-2d3ba4745b2b','津頭望白水','周繇','唐','唐诗','tang','','[]','晴江暗漲岸吹沙，山畔船衝樹杪斜。',32,'全唐诗/poet.tang.35000.json','["晴江暗漲岸吹沙，山畔船衝樹杪斜。", "城郭半淹橋市鬧，鷺鷥繚繞入人家。"]'),
('3f0c0e40-3073-468f-9804-5586aced00dc','公子行','周繇','唐','唐诗','tang','','[]','青山薄薄漏春風，日暮鳴鞭柳影中。',32,'全唐诗/poet.tang.35000.json','["青山薄薄漏春風，日暮鳴鞭柳影中。", "回望玉樓人不見，酒旗深處勒花驄。"]'),
('614d4b1d-0e9d-4f5e-a27e-30698fea9150','看牡丹贈段成式','周繇','唐','唐诗','tang','','[]','金蘂霞英疊彩香，初疑少女出蘭房。',32,'全唐诗/poet.tang.35000.json','["金蘂霞英疊彩香，初疑少女出蘭房。", "逡巡又是一年別，寄語集仙呼索郎。"]'),
('65458e44-c424-4a6b-a163-653449878f4a','以人葠遺段成式','周繇','唐','唐诗','tang','','[]','人形上品傳方志，我得真英自紫團。',32,'全唐诗/poet.tang.35000.json','["人形上品傳方志，我得真英自紫團。", "慙非叔子空持藥，更請伯言審細看。"]'),
('765d2cc2-4974-4991-91b4-ba2d5e8a173c','和段成式 一','周繇','唐','唐诗','tang','','[]','迴簪轉黛喜猜防，粉署裁詩助酒狂。',32,'全唐诗/poet.tang.35000.json','["迴簪轉黛喜猜防，粉署裁詩助酒狂。", "若遇仙丹偕羽化，便隨蕭史亦何傷。"]'),
('b4a55f02-b115-481b-a44d-ebac1bb22af3','和段成式 二','周繇','唐','唐诗','tang','','[]','玉樹瓊筵映彩霞，澄虛樓閣似仙家。',32,'全唐诗/poet.tang.35000.json','["玉樹瓊筵映彩霞，澄虛樓閣似仙家。", "只緣存想歸蘭室，不向春風看夜花。"]'),
('8c867101-ade7-4ee6-b24b-d2eaa77eae09','雜興','聶夷中','唐','唐诗','tang','','[]','兩葉能蔽目，雙豆能塞聰。',48,'全唐诗/poet.tang.35000.json','["兩葉能蔽目，雙豆能塞聰。", "理身不知道，將爲天地聾。", "擾擾造化內，茫茫天地中。", "苟或有所願，毛髪亦不容。"]'),
('5df61077-fba8-4222-8053-1fa969c5adab','雜怨 一','聶夷中','唐','唐诗','tang','','[]','生在綺羅下，豈識漁陽道。',48,'全唐诗/poet.tang.35000.json','["生在綺羅下，豈識漁陽道。", "良人自戍來，夜夜夢中到。", "漁陽萬里遠，近於中門限。", "中門踰有時，漁陽常在眼。"]'),
('85f79dbe-389c-4381-9917-9d33cbf921ba','雜怨 二','聶夷中','唐','唐诗','tang','','[]','君淚濡羅巾，妾淚滴路塵。',36,'全唐诗/poet.tang.35000.json','["君淚濡羅巾，妾淚滴路塵。", "羅巾今在手，日得隨妾身。", "路塵如因風，得上君車輪。"]'),
('1d8e2ba7-ba52-44c7-83d4-06dfaa2339d1','行路難','聶夷中','唐','唐诗','tang','','[]','莫言行路難，夷狄如中國。',48,'全唐诗/poet.tang.35000.json','["莫言行路難，夷狄如中國。", "謂言骨肉親，中門如異域。", "出處全在人，路亦無通塞。", "門前兩條轍，何處去不得。"]'),
('c5763b85-5f21-41dd-ba9b-42e79993afed','大垂手','聶夷中','唐','唐诗','tang','','[]','金刀翦輕雲，盤用黃金縷。',36,'全唐诗/poet.tang.35000.json','["金刀翦輕雲，盤用黃金縷。", "裝束趙飛燕，教來掌上舞。", "舞罷飛燕死，片片隨風去。"]'),
('469e6a93-d96f-45a9-90db-e131187c4c4a','空城雀','聶夷中','唐','唐诗','tang','','[]','一雀入官倉，所食能損幾。',48,'全唐诗/poet.tang.35000.json','["一雀入官倉，所食能損幾。", "所慮往復頻，官倉乃害爾。", "魚網不在天，鳥網不在水。", "飲啄要自然，何必空城裏。"]'),
('4a3e9cc5-e2a2-412d-a884-4c17d072c5a2','胡無人行','聶夷中','唐','唐诗','tang','','[]','男兒徇大義，立節不沽名。',96,'全唐诗/poet.tang.35000.json','["男兒徇大義，立節不沽名。", "腰間懸陸離，大歌胡無行。", "不讀戰國書，不覽黃石經。", "醉臥咸陽樓，夢入受降城。", "更願生羽翼，飛身入青冥。", "請攜天子劒，斫下旄頭星。", "自然胡無人，雖有無戰爭。", "悠哉典屬國，驅羊老一生。"]'),
('0eea5bcf-1f67-4a9f-b70f-d60dcea99111','詠田家','聶夷中','唐','唐诗','tang','','[]','二月賣新絲，五月糶新穀。',48,'全唐诗/poet.tang.35000.json','["二月賣新絲，五月糶新穀。", "醫得眼前瘡，剜却心頭肉。", "我願君王心，化作光明燭。", "不照綺羅筵，只照逃亡屋。"]'),
('be65fed3-3677-4f79-84fb-4dd6cfdc19c4','燕臺二首 一','聶夷中','唐','唐诗','tang','','[]','燕臺累黃金，上欲招儒雅。',48,'全唐诗/poet.tang.35000.json','["燕臺累黃金，上欲招儒雅。", "貴得賢士來，更下於隗者。", "自然樂毅徒，趨風走天下。", "何必馳鳳書，旁求向林野。"]'),
('afc32e5a-8518-496b-a4a5-b4c995251763','燕臺二首 二','聶夷中','唐','唐诗','tang','','[]','燕臺高百尺，燕滅臺亦平。',36,'全唐诗/poet.tang.35000.json','["燕臺高百尺，燕滅臺亦平。", "一種是亡國，猶得禮賢名。", "何似章華畔，空餘禾黍生。"]'),
('bc6c2eb5-4930-4b60-a227-7f94fb6a28a8','古興','聶夷中','唐','唐诗','tang','','[]','片玉一塵輕，粒粟山丘重。',48,'全唐诗/poet.tang.35000.json','["片玉一塵輕，粒粟山丘重。", "唐虞貴民食，秪是勤播種。", "前聖後聖同，今人古人共。", "一歲如苦饑，金玉何所用。"]'),
('c0f81a43-5b23-4871-a06e-8660db415ad8','勸酒二首 一','聶夷中','唐','唐诗','tang','','["\u7ec8\u5357\u5c71"]','白日無定影，清江無定波。',72,'全唐诗/poet.tang.35000.json','["白日無定影，清江無定波。", "人無百年壽，百年復如何。", "堂上陳美酒，堂下列笙歌。", "與君入醉鄉，醉鄉樂天和。", "歲歲松栢茂，日日丘陵多。", "君看終南山，萬古青峨峨。"]'),
('200b9d38-5f06-453f-83cb-197fdceeb8c1','勸酒二首 二','聶夷中','唐','唐诗','tang','','[]','灞上送行客，聽唱行客歌。',60,'全唐诗/poet.tang.35000.json','["灞上送行客，聽唱行客歌。", "適來橋下水，已作渭川波。", "人間榮樂少，四海別離多。", "但恐別離淚，自成苦水河。", "勸爾一杯酒，所贈無餘多。"]'),
('12e75828-7908-4a38-bfdf-d491496721d1','飲酒樂','聶夷中','唐','唐诗','tang','','[]','日月似有事，一夜行一周。',72,'全唐诗/poet.tang.35000.json','["日月似有事，一夜行一周。", "草木猶須老，人生得無愁。", "一飲解百結，再飲破百憂。", "白髮欺貧賤，不入醉人頭。", "我願東海水，盡向杯中流。", "安得阮步兵，同入醉鄉遊。"]'),
('c6d6f052-2dcf-4a7b-be9e-773e4c6f6dd1','公子行二首 一','聶夷中','唐','唐诗','tang','','[]','漢代多豪族，恩深益驕逸。',96,'全唐诗/poet.tang.35000.json','["漢代多豪族，恩深益驕逸。", "走馬踏殺人，街吏不敢詰。", "紅樓宴青春，數里望雲蔚。", "金缸焰勝畫，不畏落暉疾。", "美人盡如月，南威莫能匹。", "芙蓉自天來，不向水中出。", "飛瓊奏雲和，碧簫吹鳳質。", "唯恨魯陽死，無人駐白日。"]'),
('2805b567-edfc-4bf4-8f9a-964906968b1c','公子行二首 二','聶夷中','唐','唐诗','tang','','[]','花樹出墻頭，花裏誰家樓。',36,'全唐诗/poet.tang.35000.json','["花樹出墻頭，花裏誰家樓。", "一行書不讀，身封萬戶侯。", "美人樓上歌，不是古涼州。"]'),
('99d0dee6-3e15-4931-9984-4c7b1e1f8583','短歌','聶夷中','唐','唐诗','tang','','[]','八月木陰薄，十葉三墮枝。',120,'全唐诗/poet.tang.35000.json','["八月木陰薄，十葉三墮枝。", "人生過五十，亦已同此時。", "朝出東郭門，嘉樹鬱參差。", "暮出西郭門，原草已離披。", "南鄰好臺榭，北鄰善歌吹。", "榮華忽銷歇，四顧令人悲。", "生死與榮辱，四者乃常期。", "古人耻其名，沒世無人知。", "無言鬢似霜，勿謂事如絲。", "耆年無一善，何殊食乳兒。"]'),
('366e820c-e3bb-4276-bc10-c8daa92aad19','過比干墓','聶夷中','唐','唐诗','tang','','[]','殷辛帝天下，厭爲天下尊。',96,'全唐诗/poet.tang.35000.json','["殷辛帝天下，厭爲天下尊。", "乾綱既一斷，賢愚無二門。", "佞是福身本，忠作喪己源。", "餓虎不食子，人無骨肉恩。", "日影不入地，下埋冤死魂。", "腐骨不爲土，應作石木根。", "余來過此鄉，下馬弔此墳。", "靜念君臣間，有道誰敢論。"]'),
('2f3dd335-205d-45dc-9818-8413ff9dc59d','住京寄同志','聶夷中','唐','唐诗','tang','','[]','在京如在道，日日先雞起。',96,'全唐诗/poet.tang.35000.json','["在京如在道，日日先雞起。", "不離十二街，日行一百里。", "役役大塊上，周朝復秦市。", "貴賤與賢愚，古今同一軌。", "白兔落天西，赤鵶飛海底。", "一日復一日，日日無終始。", "自嫌性如石，不達榮辱理。", "試問九十翁，吾今尚如此。"]'),
('932552dc-b1e3-45cd-a80f-309b37db4acf','贈農','聶夷中','唐','唐诗','tang','','[]','勸爾勤耕田，盈爾倉中粟。',60,'全唐诗/poet.tang.35000.json','["勸爾勤耕田，盈爾倉中粟。", "勸爾無伐桑，減爾身上服。", "清霜一委地，萬草色不綠。", "狂風一飄林，萬葉不著木。", "青春如不耕，何以自拘束。"]'),
('a6e4458c-f82c-4c43-a3ca-b08f0c8f7e46','客有追歎後時者作詩勉之','聶夷中','唐','唐诗','tang','','[]','後達多晚榮，速得多疾傾。',108,'全唐诗/poet.tang.35000.json','["後達多晚榮，速得多疾傾。", "君看構大廈，何曾一日成。", "在暖須在桑，在飽須在耕。", "君子貴弘道，道弘無不亨。", "太陽垂好光，毛髪悉見形。", "我亦二十年，直似戴盆行。", "荆山產美玉，石石皆堅貞。", "未必盡有玉，玉且間石生。", "精衛一微物，猶恐填海平。"]'),
('1ea71c69-cbd6-4e16-bdbc-29876ca356d5','訪嵩陽道士不遇','聶夷中','唐','唐诗','tang','','[]','先生五岳遊，文焰滅金鼎。',48,'全唐诗/poet.tang.35000.json','["先生五岳遊，文焰滅金鼎。", "日下鶴過時，人間空落影。", "常言一粒藥，不隨死生境。", "何當列禦寇，去問仙人請。"]'),
('9efa9734-5a13-4087-a59c-49a4f0fb63c3','早發鄴北經古城','聶夷中','唐','唐诗','tang','','[]','微月東南明，雙牛耕古城。',96,'全唐诗/poet.tang.35000.json','["微月東南明，雙牛耕古城。", "但耕古城地，不知古城名。", "當昔置此城，豈料今日耕。", "蔓草已離披，狐兔何縱橫。", "秋雲零落散，秋風蕭條生。", "對古良可歎，念今轉傷情。", "古人已冥冥，今人又營營。", "不知馬蹄下，誰家舊臺亭。"]'),
('a4ba9d47-b06b-4146-a0f7-ffbb67a35705','題賈氏林泉','聶夷中','唐','唐诗','tang','','[]','市朝束名利，林泉繫清通。',120,'全唐诗/poet.tang.35000.json','["市朝束名利，林泉繫清通。", "豈知黃塵內，迥有白雲蹤。", "輕流逗密蓧，直榦入寬空。", "高吟五君詠，疑對九華峰。", "我知種竹心，欲扇清涼風。", "我知決泉意，將明濟物功。", "有琴不張弦，衆星列梧桐。", "須知澹泊聽，聲在無聲中。", "地非樵者路，武陵又何逢。", "祗慮迷所歸，池上日西東。"]'),
('75e09623-9ab1-4f2f-8d40-0888d8bd88f1','送友人歸江南','聶夷中','唐','唐诗','tang','','[]','皇州五更鼓，月落西南維。',36,'全唐诗/poet.tang.35000.json','["皇州五更鼓，月落西南維。", "此時有行客，別我孤舟歸。", "上國身無主，下第誠可悲。"]'),
('65a22f40-7a74-4c1a-9cf8-b113db2acc92','秋夕','聶夷中','唐','唐诗','tang','','[]','日往無復見，秋堂暮乃學。',48,'全唐诗/poet.tang.35000.json','["日往無復見，秋堂暮乃學。", "玄髪不知白，曉入寒銅覺。", "爲才未離羣，有玉猶在璞。", "誰把碧桐枝，刻作雲門樂。"]'),
('2f3b4935-f037-41ba-b264-2732c514a28e','哭劉駕博士','聶夷中','唐','唐诗','tang','','[]','出門四顧望，此日何徘徊。',72,'全唐诗/poet.tang.35000.json','["出門四顧望，此日何徘徊。", "終南舊山色，夫子安在哉。", "君詩如門戶，夕閉晝還開。", "君名如四時，春盡夏復來。", "原野多丘陵，纍纍如高臺。", "君墳須數尺，誰與夫子偕。"]'),
('ba1417d6-912a-4606-a798-d8971da31a7e','公子家','聶夷中','唐','唐诗','tang','','["\u5199\u4eba", "\u8bbd\u523a", "\u5199\u4eba\u8bd7"]','種花滿西園，花發青樓道。',24,'全唐诗/poet.tang.35000.json','["種花滿西園，花發青樓道。", "花下一禾生，去之爲惡草。"]'),
('91276d5a-1844-40ec-a102-a41eaab21c12','田家二首 一','聶夷中','唐','唐诗','tang','','["\u5fe7\u56fd\u5fe7\u6c11", "\u8bbd\u523a"]','父耕原上田，子劚山下荒。',24,'全唐诗/poet.tang.35000.json','["父耕原上田，子劚山下荒。", "六月禾未秀，官家已修倉。"]'),
('78a50612-df8c-44a5-8a19-f455cc185195','田家二首 二','聶夷中','唐','唐诗','tang','','[]','鋤田當日午，汗滴禾下土。',24,'全唐诗/poet.tang.35000.json','["鋤田當日午，汗滴禾下土。", "誰念盤中餐，粒粒皆辛苦。"]'),
('a59d9e42-871a-4d57-8515-aaf7622af1c4','雜怨','聶夷中','唐','唐诗','tang','','[]','良人昨日去，明月又不圓。',24,'全唐诗/poet.tang.35000.json','["良人昨日去，明月又不圓。", "別時各有淚，零落青樓前。"]'),
('f7763540-977d-4290-8d99-2e0ad16af9d6','烏夜啼','聶夷中','唐','唐诗','tang','','[]','衆鳥各歸枝，烏烏爾不棲。',24,'全唐诗/poet.tang.35000.json','["衆鳥各歸枝，烏烏爾不棲。", "還應知妾恨，故向綠窗啼。"]'),
('4e512a19-210d-4612-8dc5-1d9b6ae52610','起夜來','聶夷中','唐','唐诗','tang','','[]','念遠心如燒，不覺中夜起。',24,'全唐诗/poet.tang.35000.json','["念遠心如燒，不覺中夜起。", "桃花帶露泛，立在月明裏。"]'),
('02c52bf9-7672-44a1-a618-92b26b91fde1','古別離','聶夷中','唐','唐诗','tang','','["\u9001\u522b", "\u5973\u5b50", "\u60c5\u90ce"]','欲別牽郎衣，問郎遊何處。',24,'全唐诗/poet.tang.35000.json','["欲別牽郎衣，問郎遊何處。", "不恨歸日遲，莫向臨邛去。"]'),
('5237a4cc-a1d5-48a6-9ec3-72a4b400dea0','長安道','聶夷中','唐','唐诗','tang','','[]','此地無駐馬，夜中猶走輪。',24,'全唐诗/poet.tang.35000.json','["此地無駐馬，夜中猶走輪。", "所以路傍草，少於衣上塵。"]'),
('ab09e37b-0114-49f7-ab82-56480afb3d9e','遊子行','聶夷中','唐','唐诗','tang','','[]','萱草生堂階，遊子行天涯。',24,'全唐诗/poet.tang.35000.json','["萱草生堂階，遊子行天涯。", "慈親倚門望，不見萱草花。"]'),
('d813c029-0b6d-4b89-b4ba-5d6d725e73d9','聞人說海北事有感','聶夷中','唐','唐诗','tang','','[]','故鄉歸路隔高雷，見說年來事可哀。',64,'全唐诗/poet.tang.35000.json','["故鄉歸路隔高雷，見說年來事可哀。", "村落日中眠虎豹，田園雨後長蒿萊。", "海隅久已無春色，地底真成有劫灰。", "荆棘滿山行不得，不知當日是誰栽。"]'),
('c0830243-f9c8-4261-9aeb-888cd8c84283','華清詞','顧雲','唐','唐诗','tang','','[]','祥雲皓鶴盤碧空，喬松稍稍韻微風。',115,'全唐诗/poet.tang.35000.json','["祥雲皓鶴盤碧空，喬松稍稍韻微風。", "絳節影來，朱旛響丁東。", "相公清齋朝蘂宮，太上符籙龍蛇蹤。", "散花天女侍香童，隔煙遙望見雲水。", "彈璈吹鳳清瓏瓏，丹砂黃金世可度。", "願啓一言告仙翁，道門弟子山中客。", "長向山中禮空碧，九色真龍上漢時，願把霓幢引煙策。"]'),
('98e85dbe-1c8f-4964-a82e-d01a8f9ba1e2','天威行','顧雲','唐','唐诗','tang','','[]','蠻嶺高，蠻海闊，去舸迴艘投此歇。',176,'全唐诗/poet.tang.35000.json','["蠻嶺高，蠻海闊，去舸迴艘投此歇。", "一夜舟人得夢間，草草相呼一時發。", "颶風忽起雲顛狂，波濤擺掣魚龍殭。", "海神怕急上岸走，山燕股慄入石藏。", "金蛇飛狀霍閃過，白日倒挂銀繩長。", "轟轟砢砢雷車轉，霹靂一聲天地戰。", "風定雲開始望看，萬里青山分兩片。", "車遙遙，馬闐闐，平如砥，直如弦。", "雲南八國萬部落，皆知此路來朝天。", "耿恭拜出井底水，廣利刺開山上泉。", "若論終古濟物意，二將之功皆小焉。"]'),
('48356297-d07a-48ad-a8cd-d7c91bcfc8b8','築城篇','顧雲','唐','唐诗','tang','','[]','三十六里西川地，圍遶城郭峨天橫。',128,'全唐诗/poet.tang.35000.json','["三十六里西川地，圍遶城郭峨天橫。", "一家人率一口甓，版築纔興城已成。", "役夫登登無倦色，饌飽觴酣方暫息。", "不假神龜出指蹤，盡憑心匠爲籌畫。", "畫閣團團真鐵甕，堵闊巉巖齊石壁。", "風吹四面旌旗動，火焰相燒滿天赤。", "散花樓晚挂殘虹，濯錦秋江澄倒碧。", "西川父老賀子孫，從茲始是中華人。"]'),
('c7a701ec-0276-4364-be88-e02b67c39226','蘇君廳觀韓幹馬障歌','顧雲','唐','唐诗','tang','','[]','杜甫歌詩吟不足，可憐曹霸丹青曲。',212,'全唐诗/poet.tang.35000.json','["杜甫歌詩吟不足，可憐曹霸丹青曲。", "直言弟子韓幹馬，畫馬無骨但有肉。", "今日披圖見筆跡，始知甫也真凡目。", "秦王學士居武功，六印名家聲價雄。", "乃孫屈跡寧百里，好奇學古有祖風。", "竹廳斜日弈碁散，延我直入書齋中。", "屹然六幅古屏上，歘見胡人牽入天廐之神龍。", "麟鬐鳳臆真相似，秋竹慘慘披兩耳。", "輕勻杏蘂糝皮毛，細撚銀絲插騣尾。", "思量動步應千里，誰見初離渥洼水。", "眼前只欠燕雪飛，蹄下如聞朔風起。", "朱崖謫掾從亡歿，更有何人鑒奇物。", "當時若遇燕昭王，肯把千金買枯骨。"]'),
('d7210ac8-7fc6-4374-b555-dfb6d6d3e372','苔歌','顧雲','唐','唐诗','tang','','[]','檻前溪奪秋空色，百丈潭心數砂礫。',178,'全唐诗/poet.tang.35000.json','["檻前溪奪秋空色，百丈潭心數砂礫。", "松筠條條長碧苔，苔色碧於溪水碧。", "波迴梳開孔雀尾，根細貼著盤陀石。", "撥浪輕拈出少時，一髻濃煙三四尺。", "山光日華亂相射，靜縷蘭鬐勻襞積。", "試把臨流抖擻看，琉璃珠子淚雙滴。", "如看玉女洗頭處，解破雲鬟收未得。", "即是仙宮欲製六銖衣，染絲未倩鮫人織。", "採之不敢盈筐篋，苦怕龍神河伯惜。", "瓊蘇玉鹽爛漫煮，嚥入丹田續靈液。", "會待功成插翅飛，蓬萊頂上尋仙客。"]'),
('c56a0c29-f1b5-4190-a0f9-a0ba16776cae','池陽醉歌贈匡廬處士姚巖傑','顧雲','唐','唐诗','tang','','["\u5e90\u5c71"]','九華太守行春罷，高絳紅筵壓花榭。',306,'全唐诗/poet.tang.35000.json','["九華太守行春罷，高絳紅筵壓花榭。", "四面繁英拂檻開，帖雪團霞墜枝亞。", "空中焰若燒藍天，萬里滑靜無纖煙。", "弦索緊快管聲脆，急曲碎拍聲相連。", "主人憐才多傾興，許客酣歌露真性。", "春酎香濃枝盞黏，一醉有時三日病。", "黿潭鱗粉解不去，鴉嶺蘂花澆不醒。", "肺枯似著爐鞲煽，腦熱如遭鎚鑿釘。", "蒙溪先生梁公孫，忽然示我十軸文。", "展開一卷讀一首，四顧特地無涯垠。", "又開一軸讀一帙，酒病豁若風驅雲。", "文鋒斡破造化窟，心刃掘出興亡根。", "經疾史恙萬片恨，墨炙筆針如有神。", "呵叱潘陸鄙瑣屑，提挈揚孟歸孔門。", "時時說及開元理，家風颯颯吹人耳。", "吳[兢]纂出升平源，十事分明鋪在紙。", "裔孫才業今如此，誰人爲奏明天子。", "鑾駕何當獵左馮，神鷹一擲望千里。", "戲操狂翰涴蠻牋，傍人莫笑我率然。"]'),
('95477829-6273-4f85-a0b8-d5bf3c07e507','詠柳二首 一','顧雲','唐','唐诗','tang','','[]','帶露含煙處處垂，綻黃搖綠嫩參差。',64,'全唐诗/poet.tang.35000.json','["帶露含煙處處垂，綻黃搖綠嫩參差。", "長堤未見風飄絮，廣陌初憐日映絲。", "斜傍畫筵偷舞態，低臨粧閣學愁眉。", "離亭不放到春暮，折盡拂簷千萬枝。"]'),
('f496ea26-55a4-4871-9124-1686c08a4ae4','詠柳二首 二','顧雲','唐','唐诗','tang','','[]','閑花野草總爭新，眉皺絲乾獨不勻。',32,'全唐诗/poet.tang.35000.json','["閑花野草總爭新，眉皺絲乾獨不勻。", "乞取東風殘氣力，莫教虛度一年春。"]'),
('755f481e-df48-4cc6-a457-f376783f11f6','宴邊將','張喬','唐','唐诗','tang','','[]','一曲梁州金石清，邊風蕭颯動江城。',32,'全唐诗/poet.tang.35000.json','["一曲梁州金石清，邊風蕭颯動江城。", "座中有老沙場客，橫笛休吹塞上聲。"]'),
('9ec6ccc2-422a-40f1-8d99-9832cf0b2687','郢州即事','張喬','唐','唐诗','tang','','[]','孤城臨遠水，千里見寒山。',48,'全唐诗/poet.tang.35000.json','["孤城臨遠水，千里見寒山。", "白雪無人唱，滄洲盡日閑。", "鳥歸殘燒外，帆出斷雲間。", "此地秋風起，應隨計吏還。"]'),
('0f41f985-161d-4afb-a4c2-23f1698aa420','送賓貢金夷吾奉使歸本國','張喬','唐','唐诗','tang','','[]','渡海登仙籍，還家備漢儀。',48,'全唐诗/poet.tang.35000.json','["渡海登仙籍，還家備漢儀。", "孤舟無岸泊，萬里有星隨。", "積水浮魂夢，流年半別離。", "東風未迴日，音信杳難期。"]'),
('60a6c96f-4023-4b94-a2b8-24b6c481a28c','華山','張喬','唐','唐诗','tang','','[]','誰將倚天劒，削出倚天峰。',48,'全唐诗/poet.tang.35000.json','["誰將倚天劒，削出倚天峰。", "衆水背流急，他山相向重。", "樹黏青靄合，崖夾白雲濃。", "一夜盆傾雨，前湫起毒龍。"]'),
('3e8f3ce8-4766-4896-9420-ded8b2856a36','滕王閣','張喬','唐','唐诗','tang','','["\u6ed5\u738b\u9601"]','昔人登覽處，遺閣大江隅。',48,'全唐诗/poet.tang.35000.json','["昔人登覽處，遺閣大江隅。", "疊浪有時有，閑雲無日無。", "早涼先燕去，返照後帆孤。", "未得營歸計，菱歌滿舊湖。"]'),
('6c9f6ef2-3e5b-49e9-ae32-b6fdf7b02f80','寄處士梁燭','張喬','唐','唐诗','tang','','[]','賢哉君子風，諷與古人同。',48,'全唐诗/poet.tang.35000.json','["賢哉君子風，諷與古人同。", "採藥楚雲裏，移家湘水東。", "星霜秋野闊，雨雹夜山空。", "早晚相招隱，深耕老此中。"]'),
('5ff5b4d9-d8fe-436b-8126-b6503503244a','送許棠下第遊蜀','張喬','唐','唐诗','tang','','[]','天下猿多處，西南是蜀關。',48,'全唐诗/poet.tang.35000.json','["天下猿多處，西南是蜀關。", "馬登青壁瘦，人宿翠微閑。", "帶雨逢殘日，因江見斷山。", "行歌風月好，莫老錦城間。"]'),
('314ee84c-a03c-409b-b13e-fb0a6daeb283','題終南山白鶴觀','張喬','唐','唐诗','tang','','["\u7ec8\u5357\u5c71"]','上徹鍊丹峰，求玄意未窮。',48,'全唐诗/poet.tang.35000.json','["上徹鍊丹峰，求玄意未窮。", "古壇青草合，往事白雲空。", "仙境日月外，帝鄉煙霧中。", "人間足煩署，欲去戀松風。"]'),
('6c9edfa3-cbb6-47b0-a637-e1cdc52e06f3','贈邊將','張喬','唐','唐诗','tang','','[]','將軍誇膽氣，功在殺人多。',48,'全唐诗/poet.tang.35000.json','["將軍誇膽氣，功在殺人多。", "對酒擎鍾飲，臨風拔劒歌。", "翻師平碎葉，掠地取交河。", "應笑孔門客，年年羨四科。"]'),
('d8ed88d6-e73a-42e1-bc4b-f0c36870e5e7','弔建州李員外','張喬','唐','唐诗','tang','','[]','銘旌歸故里，猿鳥亦悽然。',48,'全唐诗/poet.tang.35000.json','["銘旌歸故里，猿鳥亦悽然。", "已葬桐江月，空迴建水船。", "客傳爲郡日，僧說讀書年。", "恐有吟魂在，深山古木邊。"]'),
('2aa78634-4351-4ccd-86ac-5be70c4a4dd9','送許棠及第歸宣州','張喬','唐','唐诗','tang','','[]','雅調一生吟，誰爲晚達心。',48,'全唐诗/poet.tang.35000.json','["雅調一生吟，誰爲晚達心。", "傍人賀及第，獨自却霑襟。", "宴別喧天樂，家歸礙日岑。", "青門許攀送，故里接雲林。"]'),
('a341fedf-e08f-41a6-a65c-84853ad63ad5','送龐百篇之任青陽縣尉','張喬','唐','唐诗','tang','','[]','都堂公試日，詞翰獨超羣。',48,'全唐诗/poet.tang.35000.json','["都堂公試日，詞翰獨超羣。", "品秩台庭與，篇章聖主聞。", "鄉連三楚樹，縣對九華雲。", "多少青門客，臨岐共羨君。"]'),
('3608fba3-87f4-420d-b1fe-d52a8f4cc7e7','曲江春','張喬','唐','唐诗','tang','','[]','尋春與送春，多遶曲江濱。',48,'全唐诗/poet.tang.35000.json','["尋春與送春，多遶曲江濱。", "一片鳧鷖水，千秋輦轂塵。", "岸涼隨衆木，波影逐遊人。", "自是遊人老，年年管吹新。"]'),
('7e4d8eef-358d-40fa-98d0-8d8fe189fae2','秦原春望','張喬','唐','唐诗','tang','','[]','無窮名利塵，軒蓋逐年新。',48,'全唐诗/poet.tang.35000.json','["無窮名利塵，軒蓋逐年新。", "北闋東堂路，千山萬水人。", "雲離僧榻曙，燕遠鳳樓春。", "荏苒文明代，難歸釣艇身。"]'),
('11bab6c9-81b8-4c27-a60c-9b50385cdf35','遊華山雲際寺','張喬','唐','唐诗','tang','','[]','少華中峰寺，高秋衆景歸。',48,'全唐诗/poet.tang.35000.json','["少華中峰寺，高秋衆景歸。", "地連秦塞起，河隔晉山微。", "晚木蟬相應，涼天鴈並飛。", "殷勤記巖石，秪恐再來稀。"]'),
('e764782e-ad6a-4609-a0b2-ca8a5f877f59','送碁待詔朴球歸新羅','張喬','唐','唐诗','tang','','[]','海東誰敵手，歸去道應孤。',48,'全唐诗/poet.tang.35000.json','["海東誰敵手，歸去道應孤。", "闕下傳新勢，船中覆舊圖。", "窮荒迴日月，積水載寰區。", "故國多年別，桑田復在無。"]'),
('d6ef3f03-4cfe-4448-a6aa-ef8e9e52e3bd','送鄭谷先輩赴汝州辟命','張喬','唐','唐诗','tang','','[]','看花興未休，已散曲江遊。',48,'全唐诗/poet.tang.35000.json','["看花興未休，已散曲江遊。", "載筆離秦甸，從軍過洛州。", "嵩雲將雨去，汝水背城流。", "應念依門客，蒿萊滿徑秋。"]'),
('195092ae-a3d3-462c-8d23-817c811b1357','贈敬亭清越上人','張喬','唐','唐诗','tang','','[]','海上獨隨緣，歸來二十年。',48,'全唐诗/poet.tang.35000.json','["海上獨隨緣，歸來二十年。", "久閑時得句，漸老不離禪。", "砌木欹臨水，窗峰直倚天。", "猶期向雲裏，別掃石床眠。"]'),
('68ccf3ce-0108-4833-a296-f36085ca2d72','題靈山寺','張喬','唐','唐诗','tang','','[]','樹涼清島寺，虛閣敞禪扉。',48,'全唐诗/poet.tang.35000.json','["樹涼清島寺，虛閣敞禪扉。", "四面閑雲入，中流獨鳥歸。", "湖平幽徑近，船泊夜燈微。", "一宿秋風裏，煙波隔擣衣。"]'),
('128d1f2f-9cd5-4d87-9343-87ec666157d7','弔栖白上人','張喬','唐','唐诗','tang','','[]','今古遰相送，幾時無逝波。',48,'全唐诗/poet.tang.35000.json','["今古遰相送，幾時無逝波。", "篇章名不朽，寂滅理如何。", "內殿留真影，閑房落貝多。", "從茲高塔寺，惆悵懶經過。"]'),
('0a26dea0-34f7-4013-97dd-bc4ac5cbf6f3','北山書事','張喬','唐','唐诗','tang','','["\u9ec4\u6cb3"]','黃河一曲山，天半鎖重關。',48,'全唐诗/poet.tang.35000.json','["黃河一曲山，天半鎖重關。", "聖日雄藩靜，秋風老將閑。", "車輿穿谷口，市井響雲間。", "大野無飛鳥，元戎校獵還。"]'),
('93bbdbc5-72a2-4c8f-9ba0-6adc1c0aca56','長安書事','張喬','唐','唐诗','tang','','[]','出送鄉人盡，滄洲未得還。',48,'全唐诗/poet.tang.35000.json','["出送鄉人盡，滄洲未得還。", "秋風五陵樹，晴日六街山。", "有景終年住，無機是處閑。", "何當向雲外，免老別離間。"]'),
('c30fc6ee-bd0f-408f-8a14-a558cf183dd8','送鄭侍御赴汴州辟命','張喬','唐','唐诗','tang','','[]','官從諫署清，暫去佐戎旌。',48,'全唐诗/poet.tang.35000.json','["官從諫署清，暫去佐戎旌。", "朝客多相戀，吟僧欲伴行。", "河冰天際白，嶽雪眼前明。", "即見東風起，梁園聽早鶯。"]'),
('c8acfa02-7294-43f9-a9ab-e3c23603768d','弔造微上人','張喬','唐','唐诗','tang','','[]','至人隨化往，遺路自堪傷。',48,'全唐诗/poet.tang.35000.json','["至人隨化往，遺路自堪傷。", "白塔收真骨，青山閉影堂。", "鐘殘含細韻，煙滅有餘香。", "松上齋烏在，遲遲立夕陽。"]'),
('0b6f6a75-db19-4163-bb99-d542d3c2412a','經隱巖舊居','張喬','唐','唐诗','tang','','[]','夜久村落靜，徘徊楊柳津。',48,'全唐诗/poet.tang.35000.json','["夜久村落靜，徘徊楊柳津。", "青山猶有路，明月已無人。", "夢寐空前事，星霜倦此身。", "嘗期結茅處，來往躡遺塵。"]'),
('0164776b-bf22-4a59-9cc7-58364316c11b','再題敬亭清越上人山房','張喬','唐','唐诗','tang','','[]','重來訪惠休，已是十年遊。',48,'全唐诗/poet.tang.35000.json','["重來訪惠休，已是十年遊。", "向水千松老，空山一磬秋。", "石窗清吹入，河漢夜光流。", "久別多新作，長吟洗俗愁。"]'),
('c10ee032-78a8-46d1-887f-6030197aacbc','浮汴東歸','張喬','唐','唐诗','tang','','[]','日暖泗濱西，無窮岸草齊。',48,'全唐诗/poet.tang.35000.json','["日暖泗濱西，無窮岸草齊。", "薄煙衰草樹，微月迥城雞。", "水近滄浪急，山隨綠野低。", "羞將舊名姓，還向舊遊題。"]'),
('3d94b8b1-d00c-4667-a411-3117ac16e7a4','雨中宿僧院','張喬','唐','唐诗','tang','','[]','千燈有宿因，長老許相親。',48,'全唐诗/poet.tang.35000.json','["千燈有宿因，長老許相親。", "夜永樓臺雨，更深江海人。", "勞生無了日，妄念起微塵。", "不是真如理，何門靜此身。"]'),
('5342aa89-462b-464b-bf6b-120738e8397b','江行至沙浦','張喬','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','煙霞接杳冥，旅泊寄迴汀。',48,'全唐诗/poet.tang.35000.json','["煙霞接杳冥，旅泊寄迴汀。", "夜雨雷電歇，春江蛟蜃腥。", "城侵潮影白，嶠截鳥行青。", "徧欲探泉石，南須過洞庭。"]'),
('e546a15f-e9b2-4e4c-9f89-191579667689','送友人歸江南','張喬','唐','唐诗','tang','','[]','辛勤同失意，迢遞獨還家。',48,'全唐诗/poet.tang.35000.json','["辛勤同失意，迢遞獨還家。", "落日江邊笛，殘春島上花。", "親安誠可喜，道在亦何嗟。", "誰伴高吟處，晴天望九華。"]'),
('57f72189-38fe-4093-91c7-6d40a3689bcc','劉補闕自九華山拜官因以寄獻','張喬','唐','唐诗','tang','','["\u4e5d\u534e\u5c71"]','冥鴻久不羣，徵拜動天文。',48,'全唐诗/poet.tang.35000.json','["冥鴻久不羣，徵拜動天文。", "地主迎過郡，山僧送出雲。", "登車殘月在，宿館亂流分。", "若更思林下，還須共致君。"]'),
('aa6dd000-e39f-40aa-911a-fba3e94d92b3','岳陽即事','張喬','唐','唐诗','tang','','["\u5cb3\u9633\u697c"]','遠色岳陽樓，湘帆數片愁。',48,'全唐诗/poet.tang.35000.json','["遠色岳陽樓，湘帆數片愁。", "竹風山上路，沙月水中洲。", "力學桑田廢，思歸鬢髪秋。", "功名如不立，豈易狎汀鷗。"]'),
('828569ff-c3b9-4408-bb07-9b1dd00b80ce','題興善寺僧道深院','張喬','唐','唐诗','tang','','[]','江峰峰頂人，受法老西秦。',48,'全唐诗/poet.tang.35000.json','["江峰峰頂人，受法老西秦。", "法本無前業，禪非爲後身。", "院栽他國樹，堂展祖師真。", "甚願依宗旨，求閑未有因。"]'),
('b78f17a5-1503-40cd-800b-a8d64d6ca044','送龍門令劉滄','張喬','唐','唐诗','tang','','[]','去宰龍門縣，應思變化年。',48,'全唐诗/poet.tang.35000.json','["去宰龍門縣，應思變化年。", "還將魯儒政，又與晉人傳。", "峭壁開中古，長河落半天。", "幾鄉因勸勉，耕稼滿雲煙。"]'),
('8c95f197-4560-4ceb-8e04-69fdffab85d3','送友人往宜春','張喬','唐','唐诗','tang','','[]','落花兼柳絮，無處不紛紛。',48,'全唐诗/poet.tang.35000.json','["落花兼柳絮，無處不紛紛。", "遠道空歸去，流鶯獨自聞。", "野橋喧磑水，山郭入樓雲。", "故里南陵曲，秋期更送君。"]'),
('8324db66-b75a-40ff-9469-cba276d2f88f','書邊事','張喬','唐','唐诗','tang','','["\u5510\u8bd7\u4e09\u767e\u9996", "\u751f\u6d3b", "\u4e94\u8a00\u5f8b\u8bd7", "\u8fb9\u585e"]','調角斷清秋，征人倚戍樓。',48,'全唐诗/poet.tang.35000.json','["調角斷清秋，征人倚戍樓。", "春風對青塚，白日落梁州。", "大漢無兵阻，窮邊有客遊。", "蕃情似此水，長願向南流。"]'),
('d7ffd49c-a436-4d95-847d-701ae56adf17','送僧雅覺歸東海','張喬','唐','唐诗','tang','','[]','山川心地內，一念即千重。',48,'全唐诗/poet.tang.35000.json','["山川心地內，一念即千重。", "老別關中寺，禪歸海外峰。", "鳥行來有路，帆影去無蹤。", "幾夜波濤息，先聞本國鐘。"]'),
('4796c6d6-5a11-462b-a26a-4497fcd99e14','和薛監察題興善寺古松','張喬','唐','唐诗','tang','','[]','種在法王城，前朝古寺名。',48,'全唐诗/poet.tang.35000.json','["種在法王城，前朝古寺名。", "瘦根盤地遠，香吹入雲清。", "鶴動池臺影，僧禪雨雪聲。", "看來人旋老，因此歎浮生。"]'),
('2d9c9d0b-eb38-4239-a506-d237cd207139','聽琴','張喬','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','清月轉瑤軫，弄中湘水寒。',48,'全唐诗/poet.tang.35000.json','["清月轉瑤軫，弄中湘水寒。", "能令坐來客，不語自相看。", "靜恐鬼神出，急疑風雨殘。", "幾時歸嶺嶠，更過洞庭彈。"]'),
('02f67006-a3bd-43ab-ad7a-6463c1100442','送友人遊蜀','張喬','唐','唐诗','tang','','[]','此心知者稀，欲別倍相依。',48,'全唐诗/poet.tang.35000.json','["此心知者稀，欲別倍相依。", "無食擬同去，有家還未歸。", "巴山開國遠，劒道入天微。", "必恐臨邛客，疑君學賦非。"]'),
('a12530e2-dbb4-4ebd-9b59-0d529b93d1b8','聞仰山禪師往曹溪因贈','張喬','唐','唐诗','tang','','[]','曹溪松下路，猨鳥重相親。',48,'全唐诗/poet.tang.35000.json','["曹溪松下路，猨鳥重相親。", "四海求玄理，千峰遶定身。", "異花天上墮，靈草雪中春。", "自惜經行處，焚香禮舊真。"]'),
('d277b62e-eaa4-4a5e-b051-42e72ab95cd3','藍溪夜坐','張喬','唐','唐诗','tang','','[]','藍水警塵夢，夜吟開草堂。',48,'全唐诗/poet.tang.35000.json','["藍水警塵夢，夜吟開草堂。", "月臨山靄薄，松滴露花香。", "詩外真風遠，人間靜興長。", "明朝訪禪侶，更上翠微房。"]'),
('b948a659-c0db-4ecc-98f5-b88a074c5f12','題鄭侍御藍田別業','張喬','唐','唐诗','tang','','[]','秋山清若水，吟客靜於僧。',48,'全唐诗/poet.tang.35000.json','["秋山清若水，吟客靜於僧。", "小徑通商嶺，高窗見杜陵。", "雲霞朝入鏡，猨鳥夜窺燈。", "許作前峰侶，終來寄上層。"]'),
('3b0a0f97-59ea-469f-a0a8-b0621082b31c','送友人進士許棠','張喬','唐','唐诗','tang','','[]','離鄉積歲年，歸路遠依然。',48,'全唐诗/poet.tang.35000.json','["離鄉積歲年，歸路遠依然。", "夜火山頭市，春江樹杪船。", "干戈愁鬢改，瘴癘喜家全。", "何處營甘旨，潮濤浸薄田。"]'),
('852b7cfa-6c72-433b-b69a-8ce908dc2ed6','秘省伴直','張喬','唐','唐诗','tang','','[]','喬枝聚暝禽，疊閣鎖遙岑。',48,'全唐诗/poet.tang.35000.json','["喬枝聚暝禽，疊閣鎖遙岑。", "待月當秋直，看書廢夜吟。", "殘薪留火細，古井下瓶深。", "縱欲抄前史，貧難遂此心。"]'),
('ebd59254-617d-4217-a59a-6a02ecdc1756','宿昭應','張喬','唐','唐诗','tang','','[]','夜憶開元寺，淒涼里巷間。',48,'全唐诗/poet.tang.35000.json','["夜憶開元寺，淒涼里巷間。", "薄煙通魏闕，明月照驪山。", "半壁空宮閉，連天白道閑。", "清晨更回首，獨向灞陵還。"]'),
('9b653a15-b561-4f8f-903d-33bc4b33234f','送陸處士','張喬','唐','唐诗','tang','','[]','樽前放浩歌，便起泛煙波。',48,'全唐诗/poet.tang.35000.json','["樽前放浩歌，便起泛煙波。", "舟楫故人少，江湖明月多。", "孤峰經宿上，僻寺共雲過。", "若向仙巖住，還應著薜蘿。"]'),
('a7785626-8a80-48d2-b160-4b73d16f11c4','送韓處士歸少室山','張喬','唐','唐诗','tang','','[]','江外歷千岑，還歸少室吟。',48,'全唐诗/poet.tang.35000.json','["江外歷千岑，還歸少室吟。", "地閑緱嶺月，窗迥洛城砧。", "石竇垂寒乳，松枝長別琴。", "他年瀑泉下，亦擬置家林。"]'),
('7ae4cdeb-5f15-4e17-b4a5-1d4a4eea62e4','贈初上人','張喬','唐','唐诗','tang','','[]','竹色覆禪棲，幽禽遶院啼。',48,'全唐诗/poet.tang.35000.json','["竹色覆禪棲，幽禽遶院啼。", "空門無去住，行客自東西。", "井氣春來歇，庭枝雪後低。", "相看念山水，盡日話曹溪。"]'),
('f6d277af-3905-4a1b-98e9-7d57e4a64806','送新羅僧','張喬','唐','唐诗','tang','','[]','東來此學禪，多病念佛緣。',48,'全唐诗/poet.tang.35000.json','["東來此學禪，多病念佛緣。", "把錫離巖寺，收經上海船。", "落帆敲石火，宿島汲瓶泉。", "永向扶桑老，知無再少年。"]'),
('173969ed-0afb-4b36-8f25-de62dbabc1cc','題山僧院','張喬','唐','唐诗','tang','','[]','谿路曾來日，年多與舊同。',48,'全唐诗/poet.tang.35000.json','["谿路曾來日，年多與舊同。", "地寒松影裏，僧老磬聲中。", "遠水清風落，閑雲別院通。", "心源若無礙，何必更論空。"]'),
('68ee25ca-ce4a-45ac-83bc-70f0ca0679cb','書梅福殿壁二首 一','張喬','唐','唐诗','tang','','[]','梅真從羽化，萬古是須臾。',48,'全唐诗/poet.tang.35000.json','["梅真從羽化，萬古是須臾。", "此地名空在，西山雲亦孤。", "井痕平野水，壇級上春蕪。", "縱有雙飛鶴，年多松已枯。"]'),
('36d31cf8-16e6-4ade-91f6-4549375ac632','書梅福殿壁二首 二','張喬','唐','唐诗','tang','','[]','一自白雲去，千秋壇月明。',48,'全唐诗/poet.tang.35000.json','["一自白雲去，千秋壇月明。", "我來思往事，誰更得長生。", "雅韻磬鍾遠，真風樓殿清。", "今來爲尉者，天下有仙名。"]'),
('353cf8af-79e4-4de1-b43f-8add0f481998','荆楚道中','張喬','唐','唐诗','tang','','[]','前程曾未到，岐路擬何爲。',48,'全唐诗/poet.tang.35000.json','["前程曾未到，岐路擬何爲。", "返照行人急，荒郊去鳥遲。", "春宵多旅夢，夏閏遠秋期。", "處處牽愁緒，無窮是柳絲。"]'),
('5839dca5-f3dc-4626-9eac-5d2baca3f55c','送南陵尉李頻','張喬','唐','唐诗','tang','','[]','重作東南尉，生涯尚似僧。',48,'全唐诗/poet.tang.35000.json','["重作東南尉，生涯尚似僧。", "客程淮館月，鄉思海船燈。", "晚霧看春轂，晴天見朗陵。", "不應三考足，先授詔書徵。"]'),
('dc37c875-1e11-4ad6-b196-85581c174787','將歸江淮書','張喬','唐','唐诗','tang','','[]','東風搖衆木，即有看花期。',48,'全唐诗/poet.tang.35000.json','["東風搖衆木，即有看花期。", "紫陌頻來日，滄洲獨去時。", "郡因兵役苦，家爲海翻移。", "未老多如此，那堪鬢不衰。"]'),
('617d3b4d-4282-44b5-88b5-d486ef867a0a','沿漢東歸','張喬','唐','唐诗','tang','','[]','北去窮秦塞，南歸遶漢川。',48,'全唐诗/poet.tang.35000.json','["北去窮秦塞，南歸遶漢川。", "深山逢古跡，遠道見新年。", "絕壁雲銜寺，空江雪灑船。", "縈迴還此景，多坐夜燈前。"]'),
('e240a046-b096-4499-a859-217aa76a48aa','送蜀客','張喬','唐','唐诗','tang','','[]','劒閣緣空去，西南轉幾州。',48,'全唐诗/poet.tang.35000.json','["劒閣緣空去，西南轉幾州。", "丹霄行客語，明月杜鵑愁。", "露帶山花落，雲隨野水流。", "相如曾醉地，莫滯少年遊。"]'),
('ab5a64cc-7b45-4405-ae1b-70a9c2f4a51c','塞上','張喬','唐','唐诗','tang','','[]','勒兵遼水邊，風急卷旌旃。',48,'全唐诗/poet.tang.35000.json','["勒兵遼水邊，風急卷旌旃。", "絕塞寒無樹，平沙勢盡天。", "雪晴迴探騎，月落控鳴弦。", "永定山河誓，南歸改漢年。"]'),
('ba47779b-5e75-4c42-926b-dd0898fb4b04','送友人歸袁州','張喬','唐','唐诗','tang','','[]','袁江猨鳥清，曾向此中行。',48,'全唐诗/poet.tang.35000.json','["袁江猨鳥清，曾向此中行。", "才子登科去，諸侯掃榻迎。", "山藏明月浦，樹遶白雲城。", "遠想安親後，秋風夢不驚。"]'),
('05f0b477-1b49-4a6e-a91a-ddf4d57a07f4','贈別李山人','張喬','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','分合老西秦，年年夢白蘋。',48,'全唐诗/poet.tang.35000.json','["分合老西秦，年年夢白蘋。", "曾爲洞庭客，還送洞庭人。", "語別惜殘夜，思歸愁見春。", "遙知泊舟處，沙月自相親。"]'),
('5ec637d1-43a5-450d-84a4-81656275b759','思宜春寄友人','張喬','唐','唐诗','tang','','[]','勝遊雖隔年，魂夢亦依然。',48,'全唐诗/poet.tang.35000.json','["勝遊雖隔年，魂夢亦依然。", "瀑水喧秋思，孤燈動夜船。", "斷虹全嶺雨，斜月半溪煙。", "舊日吟詩侶，何人更不眠。"]'),
('a57286cf-5bc2-4dc1-ab2c-2ef9b08686a1','江行夜雨','張喬','唐','唐诗','tang','','[]','江風木落天，遊子感流年。',48,'全唐诗/poet.tang.35000.json','["江風木落天，遊子感流年。", "萬里波連蜀，三更雨到船。", "夢殘燈影外，愁積葦業邊。", "不及樵漁客，全家住島田。"]'),
('4bdf10d7-e2df-4a19-897e-8e9da1c37a75','贈仰大師','張喬','唐','唐诗','tang','','[]','仰山因久住，天下仰山名。',48,'全唐诗/poet.tang.35000.json','["仰山因久住，天下仰山名。", "井邑身雖到，林泉性本清。", "野雲居處盡，江月定中明。", "髣髴曾相識，今來隔幾生。"]'),
('9f16a9fd-4043-4d02-80be-1d324e54b96f','江南逢洛下友人','張喬','唐','唐诗','tang','','[]','洛下吟詩侶，南遊只有君。',48,'全唐诗/poet.tang.35000.json','["洛下吟詩侶，南遊只有君。", "波濤歸路見，蟋蟀在船聞。", "曉月江城出，晴霞島樹分。", "無窮懷古意，豈獨遶湘雲。"]'),
('03ce758a-99de-440d-aed3-dacab03880b9','東湖贈僧子蘭','張喬','唐','唐诗','tang','','["\u5e90\u5c71"]','名利了無時，何人暫訪師。',48,'全唐诗/poet.tang.35000.json','["名利了無時，何人暫訪師。", "道情閑外見，心地語來知。", "竹落穿窗葉，松寒蔭井枝。", "匡山許同社，願卜挂帆期。"]'),
('d1d8bfca-75cc-4541-968a-f2f9545dca33','隱巖陪鄭少師夜坐','張喬','唐','唐诗','tang','','[]','幸喜陪騶馭，頻來向此宵。',48,'全唐诗/poet.tang.35000.json','["幸喜陪騶馭，頻來向此宵。", "硯磨清澗石，廚爨白雲樵。", "竹外村煙細，燈中禁漏遙。", "衣冠與文理，靜語對前朝。"]'),
('3fc457c1-ca13-4a0a-9e61-0154efdb3434','送三傳赴長城尉','張喬','唐','唐诗','tang','','[]','登科精魯史，爲尉及良時。',48,'全唐诗/poet.tang.35000.json','["登科精魯史，爲尉及良時。", "高論窮諸國，長才併幾司。", "地傾流水疾，山疊過雲遲。", "暇日琴書畔，何人對手棋。"]'),
('c9e21ba5-d87f-4996-a891-e9877a73b68b','送李道士歸南嶽','張喬','唐','唐诗','tang','','["\u8861\u5c71"]','千峰隔湘水，迢遰挂帆歸。',48,'全唐诗/poet.tang.35000.json','["千峰隔湘水，迢遰挂帆歸。", "掃月眠蒼壁，和雲著褐衣。", "洞虛懸溜滴，徑狹長松圍。", "只恐相尋日，人間舊識稀。"]'),
('02730697-145c-4a61-9ea5-df89de60a46f','延福里秋懷','張喬','唐','唐诗','tang','','[]','終年九陌行，要路跡皆生。',48,'全唐诗/poet.tang.35000.json','["終年九陌行，要路跡皆生。", "苦學猶難至，甘貧豈有成。", "病攜秋卷重，閑著暑衣輕。", "一別林泉久，中宵御水聲。"]'),
('04e0ba93-51db-4633-8b0e-91127e8be054','題玄哲禪師影堂','張喬','唐','唐诗','tang','','[]','吾師視化身，一念即遺塵。',48,'全唐诗/poet.tang.35000.json','["吾師視化身，一念即遺塵。", "巖谷藏虛塔，江湖散學人。", "雲迷禪處石，院掩寫來真。", "寂寞焚香後，閑階細草生。"]'),
('41228ca3-85bf-46fb-8663-a5947e49d78a','登慈恩寺塔','張喬','唐','唐诗','tang','','[]','窗戶幾層風，清涼碧落中。',48,'全唐诗/poet.tang.35000.json','["窗戶幾層風，清涼碧落中。", "世人來往別，煙景古今同。", "列岫橫秦斷，長河極塞空。", "斜陽越鄉思，天末見歸鴻。"]'),
('d0849e88-2e9d-4f70-a3cc-75ebc39c9c79','送友人東歸','張喬','唐','唐诗','tang','','[]','遠涉期秋卷，將行不廢吟。',48,'全唐诗/poet.tang.35000.json','["遠涉期秋卷，將行不廢吟。", "故鄉芳草路，來往別離心。", "挂席春風盡，開齋夏景深。", "子規誰共聽，江月上清岑。"]'),
('96aca1e5-a4e2-4ff0-855d-48732f37b359','送僧鸞歸蜀寧親','張喬','唐','唐诗','tang','','[]','歌詩精外學，天子是知音。',48,'全唐诗/poet.tang.35000.json','["歌詩精外學，天子是知音。", "坐夏宮鍾近，寧親劒閣深。", "高名徹西國，舊跡寄東林。", "自此棲禪者，因師滿蜀今。"]'),
('9691bb64-4889-4a18-9f78-9f174c0305b5','送人歸江南','張喬','唐','唐诗','tang','','[]','貧歸無定程，水宿與山行。',48,'全唐诗/poet.tang.35000.json','["貧歸無定程，水宿與山行。", "未有安親計，難爲去國情。", "島煙孤寺磬，江月遠船箏。", "思苦秋迴日，多應吟更清。"]'),
('0c281e09-5785-4391-af95-21b76e2c35dc','將離江上作','張喬','唐','唐诗','tang','','[]','白衣歸樹下，青草戀江邊。',48,'全唐诗/poet.tang.35000.json','["白衣歸樹下，青草戀江邊。", "三楚足深隱，五陵多少年。", "寂寥聞蜀魄，清絕怨湘弦。", "岐路在何處，西行心渺然。"]'),
('a182fb81-26ca-4766-9faf-a257733106c6','別李參軍','張喬','唐','唐诗','tang','','[]','王孫遊不遇，況我五湖人。',48,'全唐诗/poet.tang.35000.json','["王孫遊不遇，況我五湖人。", "野店難投宿，漁家獨問津。", "嶺分中夜月，江隔兩鄉春。", "靜想青雲路，還應寄此身。"]'),
('b7ccec37-b521-41c0-b040-f2d1dc9165bb','送睦州張參軍','張喬','唐','唐诗','tang','','[]','重祿輕身日，清資近故鄉。',48,'全唐诗/poet.tang.35000.json','["重祿輕身日，清資近故鄉。", "因知送君後，轉自惜年芳。", "遠水分林影，層峰起鳥行。", "扁舟此中去，溪月有餘光。"]'),
('9d82ff7b-35f6-46fc-9d3c-ebfbd55d0b86','贈棋僧侶','張喬','唐','唐诗','tang','','[]','機謀時未有，多向弈棋銷。',48,'全唐诗/poet.tang.35000.json','["機謀時未有，多向弈棋銷。", "已與山僧敵，無令海客饒。", "靜驅雲陣起，疎點鴈行遙。", "夜雨如相憶，松窗更見招。"]'),
('8f671b4c-2385-4887-a332-746988d5f723','題湖上友人居','張喬','唐','唐诗','tang','','[]','豈得戀樵漁，全家湖畔居。',48,'全唐诗/poet.tang.35000.json','["豈得戀樵漁，全家湖畔居。", "遠無潮客信，閑寄嶽僧書。", "野白梅繁後，山明雨散初。", "逍遙向雲水，莫與宦情疎。"]'),
('dc26c5be-a206-44e5-9542-79b12ec9be55','送友人歸宣州','張喬','唐','唐诗','tang','','[]','失計復離愁，君歸我獨遊。',48,'全唐诗/poet.tang.35000.json','["失計復離愁，君歸我獨遊。", "亂花藏道發，春水遶鄉流。", "暝火叢橋市，晴山疊郡樓。", "無爲謝公戀，吟過曉蟬秋。"]'),
('b2f07535-c709-455f-be61-0545617f1e26','題古觀','張喬','唐','唐诗','tang','','[]','急景遰衰老，此經誰養真。',48,'全唐诗/poet.tang.35000.json','["急景遰衰老，此經誰養真。", "松留千載鶴，碑隔六朝人。", "洞水流花早，壺天閉雪春。", "其如爲名利，歸踏五陵塵。"]'),
('c16c9f87-b4f8-4215-803d-ff9460d1f0eb','送友人及第歸江南','張喬','唐','唐诗','tang','','[]','豈易及歸榮，辛勤致此名。',48,'全唐诗/poet.tang.35000.json','["豈易及歸榮，辛勤致此名。", "登車思往事，迴首勉諸生。", "路遶山光曉，帆通海氣清。", "秋期却閑坐，林下聽江聲。"]'),
('4ba684e4-409f-45f9-ae88-676658c27021','送朴充侍御歸海東','張喬','唐','唐诗','tang','','[]','天涯離二紀，闕下歷三朝。',48,'全唐诗/poet.tang.35000.json','["天涯離二紀，闕下歷三朝。", "漲海雖然闊，歸帆不覺遙。", "驚波時失侶，舉火夜相招。", "來往尋遺事，秦皇有斷橋。"]'),
('ca77f48a-68d0-4918-8a41-45255761b316','弔前水部賈員外','張喬','唐','唐诗','tang','','[]','籠中江海禽，日夕有歸心。',48,'全唐诗/poet.tang.35000.json','["籠中江海禽，日夕有歸心。", "魏闕長謠久，吳山獨往深。", "別時羣木落，終處亂猨吟。", "李白墳前路，溪僧送入林。"]'),
('bafba258-a4b0-4583-a2ad-a8f5001968f3','題小松','張喬','唐','唐诗','tang','','[]','松子落何年，纖枝長水邊。',48,'全唐诗/poet.tang.35000.json','["松子落何年，纖枝長水邊。", "斸開深澗雪，移出遠林煙。", "帶月棲幽鳥，兼花灌冷泉。", "微風動清韻，閑聽罷琴眠。"]'),
('910b1225-a0b4-4dd8-be4f-4a8c7c456ad2','寄中岳顓頊先生','張喬','唐','唐诗','tang','','[]','先生顓頊後，得道自何人。',48,'全唐诗/poet.tang.35000.json','["先生顓頊後，得道自何人。", "松柏卑於壽，兒孫老却身。", "夜窗峰頂曙，寒澗洞中春。", "戀此逍遙境，雲間不可親。"]'),
('590acf9b-de49-48bb-a074-102775ec44a0','送沈先輩尉昭應','張喬','唐','唐诗','tang','','[]','餘才不廢詩，佐邑喜閑司。',48,'全唐诗/poet.tang.35000.json','["餘才不廢詩，佐邑喜閑司。", "丹陛終須去，青山未可期。", "葉凋溫谷晚，雲出古宮遲。", "若草東封疏，君王到有時。"]'),
('0b09510c-3df1-49ef-8799-477dd5b415da','送友人遊湖南','張喬','唐','唐诗','tang','','["\u8861\u5c71", "\u957f\u6c5f"]','所投非舊知，亦似有前期。',48,'全唐诗/poet.tang.35000.json','["所投非舊知，亦似有前期。", "路向長江上，帆揚細雨時。", "春生南嶽早，日轉大荒遲。", "盡採瀟湘句，重來會近期。"]'),
('700f7795-49ec-42f6-b5a3-19a520c59336','江上送友人南遊','張喬','唐','唐诗','tang','','[]','何處積鄉愁，天涯聚亂流。',48,'全唐诗/poet.tang.35000.json','["何處積鄉愁，天涯聚亂流。", "岸長羣岫晚，湖闊片帆秋。", "買酒過漁舍，分燈與釣舟。", "瀟湘見來鴈，應念獨邊遊。"]'),
('b85e0394-7595-4662-bf30-4bbed92eb890','江南別友人','張喬','唐','唐诗','tang','','[]','勞生故白頭，頭白未應休。',48,'全唐诗/poet.tang.35000.json','["勞生故白頭，頭白未應休。", "闕下難孤立，天涯尚旅遊。", "聽猨吟島寺，待月上江樓。", "醉別醒惆悵，雲帆滿亂流。"]'),
('7d4f838a-a563-49da-822e-f3b7a7b446c1','商山道中','張喬','唐','唐诗','tang','','[]','春去計秋期，長安在夢思。',48,'全唐诗/poet.tang.35000.json','["春去計秋期，長安在夢思。", "多逢山好處，少值客行時。", "雲起爭峰勢，花交隱澗枝。", "停驂一惆悵，應秪嶺猨知。"]'),
('0c2d197a-aeb7-4134-9819-60598dc05330','吳江旅次','張喬','唐','唐诗','tang','','[]','行人愁落日，去鳥倦遙林。',48,'全唐诗/poet.tang.35000.json','["行人愁落日，去鳥倦遙林。", "曠野鳴流水，空山響暮砧。", "旅途歸計晚，鄉樹別年深。", "寂寞逢村酒，漁家一醉吟。"]'),
('9b8077d3-da95-431b-b6e9-f2510303935a','寄南中友人','張喬','唐','唐诗','tang','','[]','相夢如相見，相思去後頻。',48,'全唐诗/poet.tang.35000.json','["相夢如相見，相思去後頻。", "舊時行處斷，華髪別來新。", "浪動三湘月，煙藏五嶺春。", "又無歸北客，書札寄何人。"]'),
('7ffa8288-5c0e-4f8d-9658-f33c9bc0377c','寄績溪陳明府','張喬','唐','唐诗','tang','','[]','古邑猨聲裏，空城只半存。',48,'全唐诗/poet.tang.35000.json','["古邑猨聲裏，空城只半存。", "岸移無舊路，沙漲別成村。", "鼓角喧京口，江山盡汝濆。", "六朝興廢地，行子一銷魂。"]'),
('a3f5e0c5-5fed-45bc-b03a-12c11491761b','試月中桂','張喬','唐','唐诗','tang','','[]','與月轉洪濛，扶疎萬古同。',72,'全唐诗/poet.tang.35000.json','["與月轉洪濛，扶疎萬古同。", "根非生下土，葉不墜秋風。", "每以圓時足，還隨缺處空。", "影高羣木外，香滿一輪中。", "未種丹霄日，應虛玉兔宮。", "何當因羽化，細得問玄功。"]'),
('5dc10764-f488-4f16-8b47-033e829eb20c','遊歙州興唐寺','張喬','唐','唐诗','tang','','[]','山橋通絕境，到此憶天台。',48,'全唐诗/poet.tang.35000.json','["山橋通絕境，到此憶天台。", "竹裏尋幽徑，雲邊上古臺。", "鳥歸殘照出，鐘斷細泉來。", "爲愛澄溪月，因成隔宿迴。"]'),
('bff8dfde-34fb-410c-8cbe-90601ca2f855','題詮律師院','張喬','唐','唐诗','tang','','[]','院涼松雨聲，相對有山情。',48,'全唐诗/poet.tang.35000.json','["院涼松雨聲，相對有山情。", "未許谿邊老，猶思嶽頂行。", "紗燈留火細，石井灌瓶清。", "欲問吾師外，何人得此生。"]'),
('d1b869eb-0d87-4dbc-be12-8c3611e6891c','金山寺空上人院','張喬','唐','唐诗','tang','','[]','已老金山頂，無心上石橋。',48,'全唐诗/poet.tang.35000.json','["已老金山頂，無心上石橋。", "講移三楚遍，梵譯五天遙。", "板閣禪秋月，銅瓶汲夜潮。", "自慙昏醉客，來坐亦通宵。"]'),
('d1a0eac0-10ae-4c0a-bada-91f07b7deb60','題廣信寺','張喬','唐','唐诗','tang','','[]','亭北敞靈溪，林梢與檻齊。',48,'全唐诗/poet.tang.35000.json','["亭北敞靈溪，林梢與檻齊。", "野雲來影遠，沙鳥去行低。", "晚渡明村火，晴山響郡鼙。", "思鄉值搖落，賴不有猨啼。"]'),
('173b8948-228c-469d-b296-a1f2c161f8ca','興善寺貝多樹','張喬','唐','唐诗','tang','','[]','還應毫末長，始見拂丹霄。',96,'全唐诗/poet.tang.35000.json','["還應毫末長，始見拂丹霄。", "得子從西國，成陰見昔朝。", "勢隨雙剎直，寒出四墻遙。", "帶月啼春鳥，連空噪暝蜩。", "遠根穿古井，高頂起涼飆。", "影動懸燈夜，聲繁過雨朝。", "靜遲松桂老，堅任雪霜凋。", "永共終南在，應隨劫火燒。"]'),
('ef373170-25e6-47be-a989-a1040dd4584f','華山','張喬','唐','唐诗','tang','','[]','青蒼河一隅，氣狀杳難圖。',144,'全唐诗/poet.tang.35000.json','["青蒼河一隅，氣狀杳難圖。", "卓傑三峰出，高奇四岳無。", "力疑擎上界，勢獨壓中區。", "衆水東西走，羣山遠近趨。", "天迴諸宿照，地聳百靈扶。", "石壁煙霞麗，龍潭雨雹麤。", "澄凝臨甸服，險固束神都。", "淺覺川原異，深應日月殊。", "鶴歸青靄合，仙去白雲孤。", "瀑漏斜飛凍，松長倒挂枯。", "每來尋洞穴，不擬返江湖。", "儻有芝田種，巖間老一夫。"]'),
('b79a22b2-0db9-4a47-bf47-595bd438e5ca','送何道士歸山','張喬','唐','唐诗','tang','','[]','身非絕粒本清羸，束挂仙經杖一枝。',64,'全唐诗/poet.tang.35000.json','["身非絕粒本清羸，束挂仙經杖一枝。", "落葉獨尋流水去，深山長與白雲期。", "樹臨丹竈寒花疾，壇近清嵐夜月遲。", "樵客若能隨洞裏，迴歸人世始應悲。"]'),
('b5198cf6-e149-4edc-8bbf-74377ac47449','城東寓居寄知己','張喬','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','花木閑門苔蘚生，滻川特去得吟情。',64,'全唐诗/poet.tang.35000.json','["花木閑門苔蘚生，滻川特去得吟情。", "病來久絕洞庭信，年長卻思廬岳耕。", "落日獨歸林下宿，暮雲多遶水邊行。", "干時退出長如此，頻愧相憂道姓名。"]'),
('bb671b1c-3850-416e-8fc4-cfa4c2cda3f7','再書邊事','張喬','唐','唐诗','tang','','[]','萬里沙西寇已平，犬羊羣外築空城。',64,'全唐诗/poet.tang.35000.json','["萬里沙西寇已平，犬羊羣外築空城。", "分營夜火燒雲遠，校獵秋鵰掠草輕。", "秦將力隨胡馬竭，蕃河流入漢家清。", "羌戎不識干戈老，須賀當時聖主明。"]'),
('741ea37f-d711-4905-8a29-5456ae82b2b8','遊邊感懷二首 一','張喬','唐','唐诗','tang','','[]','貧遊繚繞困邊沙，却被遼陽戰士嗟。',32,'全唐诗/poet.tang.35000.json','["貧遊繚繞困邊沙，却被遼陽戰士嗟。", "不是無家歸不得，有家歸去似無家。"]'),
('6fbae0d2-65b4-42da-8a84-c73f9e1541f8','遊邊感懷二首 二','張喬','唐','唐诗','tang','','[]','兄弟江南身塞北，鴈飛猶自半年餘。',32,'全唐诗/poet.tang.35000.json','["兄弟江南身塞北，鴈飛猶自半年餘。", "夜來因得思鄉夢，重讀前秋轉海書。"]'),
('013ea317-616c-4455-a5f4-70c6fa19b393','無題','張喬','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','九霄無詔下，何事觸清塵。',48,'全唐诗/poet.tang.35000.json','["九霄無詔下，何事觸清塵。", "宅帶松蘿僻，身惟猨鳥親。", "吟看仙掌月，期有洞庭人。", "莫問煙霞句，懸知見岳神。"]'),
('8a678775-f915-49b4-90ec-10684835be2a','蟬','張喬','唐','唐诗','tang','','[]','先秋蟬一悲，長是客行時。',48,'全唐诗/poet.tang.35000.json','["先秋蟬一悲，長是客行時。", "曾感去年者，又鳴何處枝。", "細聽殘韻在，迴望舊聲遲。", "斷續誰家樹，涼風送別離。"]'),
('9e2878d7-d77b-4ed7-bc30-4945f48182e3','江上逢進士許棠','張喬','唐','唐诗','tang','','[]','詩人推上第，新榜又無君。',48,'全唐诗/poet.tang.35000.json','["詩人推上第，新榜又無君。", "鶴髪他鄉老，漁歌故國聞。", "平江流曉月，獨鳥伴餘雲。", "且了髫年志，沙鷗未可羣。"]'),
('0879d94f-3cc1-4458-8bcf-3b5d2206cb08','送河西從事','張喬','唐','唐诗','tang','','[]','結束佐戎旃，河西住幾年。',48,'全唐诗/poet.tang.35000.json','["結束佐戎旃，河西住幾年。", "隴頭隨日去，磧裏寄星眠。", "水近沙連帳，程遙馬入天。", "聖朝思上策，重待奏安邊。"]'),
('f2d574dd-045f-4cef-a102-77d22289f6ec','河湟舊卒','張喬','唐','唐诗','tang','','["\u6218\u4e89", "\u8fb9\u585e"]','少年隨將討河湟，頭白時清返故鄉。',32,'全唐诗/poet.tang.35000.json','["少年隨將討河湟，頭白時清返故鄉。", "十萬漢軍零落盡，獨吹邊曲向殘陽。"]'),
('dfa1699d-1936-42d7-bb1c-716ced12fdb2','促織','張喬','唐','唐诗','tang','','[]','念爾無機自有情，迎寒辛苦弄梭聲。',32,'全唐诗/poet.tang.35000.json','["念爾無機自有情，迎寒辛苦弄梭聲。", "椒房金屋何曾識，偏向貧家壁下鳴。"]'),
('3df47d70-81a0-42ab-8a8b-87f11fba968f','猨','張喬','唐','唐诗','tang','','[]','挂月棲雲向楚林，取來全是爲清音。',32,'全唐诗/poet.tang.35000.json','["挂月棲雲向楚林，取來全是爲清音。", "誰知繫在黃金索，翻畏侯家不敢吟。"]'),
('f111b723-9679-4381-a8b9-3183f55bac2a','寄薦福寺棲白大師','張喬','唐','唐诗','tang','','[]','高塔六街無不見，塔邊名出秪吾師。',32,'全唐诗/poet.tang.35000.json','["高塔六街無不見，塔邊名出秪吾師。", "嘗聞朝客多相□，記得□□數句詩。"]'),
('a8fac468-9df3-4e36-8f96-8ab61172fffd','越中贈別','張喬','唐','唐诗','tang','','[]','東越相逢幾醉眠，滿樓明月鏡湖邊。',32,'全唐诗/poet.tang.35000.json','["東越相逢幾醉眠，滿樓明月鏡湖邊。", "別離吟斷西陵渡，楊柳秋風兩岸蟬。"]'),
('72561e12-6f17-4f35-96cb-fc591e621567','寄清越上人','張喬','唐','唐诗','tang','','[]','大道本來無所染，白雲那得有心期。',32,'全唐诗/poet.tang.35000.json','["大道本來無所染，白雲那得有心期。", "遠公獨刻蓮花漏，猶向空山禮六時。"]'),
('b9b71b83-daeb-4af4-a4b6-7683d664fd88','宿齊山僧舍','張喬','唐','唐诗','tang','','[]','一宿經窗臥白波，萬重歸夢隔煙蘿。',32,'全唐诗/poet.tang.35000.json','["一宿經窗臥白波，萬重歸夢隔煙蘿。", "若言不得南宗要，長在禪牀事更多。"]'),
('dbd5b98b-d62a-4efb-bc61-ff102d7d09c9','宿齊山僧舍','張喬','唐','唐诗','tang','','[]','一宿經窗望白波，曉隨山月出煙蘿。',32,'全唐诗/poet.tang.35000.json','["一宿經窗望白波，曉隨山月出煙蘿。", "若言不得南宗要，長在禪牀事更多。"]'),
('7572fbc6-e028-4516-bd45-69f12a0861b8','春日遊曲江','張喬','唐','唐诗','tang','','[]','日暖鴛鴦拍浪春，蒹葭浦際聚青蘋。',32,'全唐诗/poet.tang.35000.json','["日暖鴛鴦拍浪春，蒹葭浦際聚青蘋。", "若論來往鄉心切，須是煙波島上人。"]'),
('1d5921ec-d74f-413b-b0fc-a114076c747c','漁家','張喬','唐','唐诗','tang','','[]','擁棹思悠悠，更深泛積流。',24,'全唐诗/poet.tang.35000.json','["擁棹思悠悠，更深泛積流。", "唯將一星火，何處宿蘆洲。"]'),
('11300d0c-362c-4b25-8df1-7e5f6963e30b','送人及第歸海東','張喬','唐','唐诗','tang','','[]','東風日邊起，草木一時春。',24,'全唐诗/poet.tang.35000.json','["東風日邊起，草木一時春。", "自笑中華路，年年送遠人。"]'),
('c0af0529-265c-4969-9acc-0d9bec5cf709','題河中鸛雀樓','張喬','唐','唐诗','tang','','[]','高樓懷古動悲歌，鸛雀今無野燕過。',64,'全唐诗/poet.tang.35000.json','["高樓懷古動悲歌，鸛雀今無野燕過。", "樹隔五陵秋色早，水連三晉夕陽多。", "漁人遺火成寒燒，牧笛吹風起夜波。", "十載重來值搖落，天涯歸計欲如何。"]'),
('1a76b693-e322-4688-9dd7-098cf380991b','宿洛都門','張喬','唐','唐诗','tang','','[]','山川馬上度邊禽，一宿都門永夜吟。',32,'全唐诗/poet.tang.35000.json','["山川馬上度邊禽，一宿都門永夜吟。", "客路不歸秋又晚，西風吹動洛陽砧。"]'),
('aee4ebe2-0939-4c49-b8bd-d88471711e2a','對月二首 一','張喬','唐','唐诗','tang','','["\u4e2d\u79cb\u8282", "\u54f2\u7406", "\u6708\u4eae"]','圓魄上寒空，皆言四海同。',24,'全唐诗/poet.tang.35000.json','["圓魄上寒空，皆言四海同。", "安知千里外，不有雨兼風。"]'),
('87a6e89f-5d94-4d06-921a-539f5f057611','對月二首 二','張喬','唐','唐诗','tang','','[]','盈缺青冥外，東風萬古吹。',24,'全唐诗/poet.tang.35000.json','["盈缺青冥外，東風萬古吹。", "何人種丹桂，不長出輪枝。"]'),
('aa22688e-e812-418b-8b6b-7fbd45950086','贈友人','張喬','唐','唐诗','tang','','[]','自說安貧歸未得，竹邊門掩小池冰。',64,'全唐诗/poet.tang.35000.json','["自說安貧歸未得，竹邊門掩小池冰。", "典琴賒酒吟過寺，送客思鄉上灞陵。", "待月夜留煙島客，憶雲閑訪翠微僧。", "幾時獻了相如賦，共向嵩山採茯苓。"]'),
('5f5d644c-3353-4329-b751-1aca34836c4d','笛','張喬','唐','唐诗','tang','','[]','剪雨裁煙一節秋，落梅楊柳曲中愁。',32,'全唐诗/poet.tang.35000.json','["剪雨裁煙一節秋，落梅楊柳曲中愁。", "尊前暫借殷勤看，明日曾聞向隴頭。"]'),
('d2a98f6d-e367-43a4-b173-4a3fdf5dcca0','漁者','張喬','唐','唐诗','tang','','[]','首戴圓荷髪不梳，葉舟爲宅水爲居。',32,'全唐诗/poet.tang.35000.json','["首戴圓荷髪不梳，葉舟爲宅水爲居。", "沙頭聚看人如市，釣得澄江一丈魚。"]'),
('40165616-5d7a-4119-969e-099cf6fe8147','宿潺湲亭','張喬','唐','唐诗','tang','','[]','走月流煙疊樹西，聽來愁甚聽猨啼。',32,'全唐诗/poet.tang.35000.json','["走月流煙疊樹西，聽來愁甚聽猨啼。", "幾時御水聲邊住，却夢潺湲宿此溪。"]'),
('8c0106d1-6b21-468a-bfdc-2ca84a4cb4a4','臺城','張喬','唐','唐诗','tang','','[]','宮殿餘基長草花，景陽宮樹噪村鴉。',32,'全唐诗/poet.tang.35000.json','["宮殿餘基長草花，景陽宮樹噪村鴉。", "雲屯雉堞依然在，空繞漁樵四五家。"]'),
('dec4f514-9027-4764-b3d5-7de9107f3269','寄山僧','張喬','唐','唐诗','tang','','[]','閑倚蒲團向日眠，不能歸老岳雲邊。',32,'全唐诗/poet.tang.35000.json','["閑倚蒲團向日眠，不能歸老岳雲邊。", "舊時僧侶無人在，惟有長松見少年。"]'),
('b737f57b-3510-49cd-8415-628f307bde52','題上元許棠所任王昌齡廳','張喬','唐','唐诗','tang','','[]','瑠璃堂裏當時客，久絕吟聲繼後塵。',32,'全唐诗/poet.tang.35000.json','["瑠璃堂裏當時客，久絕吟聲繼後塵。", "百四十年庭樹老，如今重得見詩人。"]'),
('c8c492ce-b641-4f65-9b0d-ef79257e63f8','自誚','張喬','唐','唐诗','tang','','[]','每到花時恨道窮，一生光景半成空。',32,'全唐诗/poet.tang.35000.json','["每到花時恨道窮，一生光景半成空。", "只應抱璞非良玉，豈得年年不至公。"]'),
('50b93005-b78c-4c14-b219-9b0d0e802e49','贈河南詩友','張喬','唐','唐诗','tang','','[]','山東令族玉無塵，裁剪煙花筆下春。',32,'全唐诗/poet.tang.35000.json','["山東令族玉無塵，裁剪煙花筆下春。", "不把瑤華借風月，洛陽才子更何人。"]'),
('0648c317-8e84-4ff6-814f-123c0b9d9a04','寄維揚故人','張喬','唐','唐诗','tang','','[]','離別河邊綰柳條，千山萬水玉人遙。',32,'全唐诗/poet.tang.35000.json','["離別河邊綰柳條，千山萬水玉人遙。", "月明記得相尋處，城鎖東風十五橋。"]'),
('36bde069-941f-4103-be62-321d7cf0fd74','孤雲','張喬','唐','唐诗','tang','','[]','舒卷因風何所之，碧天孤影勢遲遲。',32,'全唐诗/poet.tang.35000.json','["舒卷因風何所之，碧天孤影勢遲遲。", "莫言長是無心物，還有隨龍作雨時。"]'),
('d9fc1ad3-4fce-4ba4-8582-bb6ec792ab67','詠棋子贈弈僧','張喬','唐','唐诗','tang','','[]','黑白誰能用入玄，千回生死體方圓。',32,'全唐诗/poet.tang.35000.json','["黑白誰能用入玄，千回生死體方圓。", "空門說得恆沙劫，應笑終年爲一先。"]'),
('9de5f7bf-6476-4d34-9439-8ba3a0934b4c','谷口作','張喬','唐','唐诗','tang','','[]','巴客青冥過嶺塵，雪崖交映一川春。',32,'全唐诗/poet.tang.35000.json','["巴客青冥過嶺塵，雪崖交映一川春。", "晴朝採藥尋源去，必恐雲深見異人。"]'),
('5ab9bb2c-10ce-4a2a-817a-38ba1c2f325a','寄弟','張喬','唐','唐诗','tang','','[]','故里行人戰後疎，青崖萍寄白雲居。',32,'全唐诗/poet.tang.35000.json','["故里行人戰後疎，青崖萍寄白雲居。", "那堪又是傷春日，把得長安落第書。"]'),
('e1bab312-82d5-413a-b0e5-5a77be070edc','春日有懷','張喬','唐','唐诗','tang','','[]','高下尋花春景遲，汾陽臺榭白雲詩。',32,'全唐诗/poet.tang.35000.json','["高下尋花春景遲，汾陽臺榭白雲詩。", "看山懷古翻惆悵，未勝遙傳不到時。"]'),
('d3341c9e-c49b-4f83-a084-175106ac0e0e','鷺鷥障子','張喬','唐','唐诗','tang','','[]','剪得機中如雪素，畫爲江上帶絲禽。',32,'全唐诗/poet.tang.35000.json','["剪得機中如雪素，畫爲江上帶絲禽。", "閑來相對茅堂下，引出煙波萬里心。"]'),
('d08e4bd5-7af6-48a0-9263-6740114e3041','甘露寺僧房','張喬','唐','唐诗','tang','','[]','臨水登山路，重尋旅思勞。',48,'全唐诗/poet.tang.35000.json','["臨水登山路，重尋旅思勞。", "竹陰行處密，僧臘別來高。", "遠岫明寒火，危樓響夜濤。", "悲秋不成寐，明月上千舠。"]'),
('b2d377ce-4f11-4de1-b7ef-c7b71ccbfeb2','宿江叟島居','張喬','唐','唐诗','tang','','[]','一家煙島隈，竹裏夜窗開。',48,'全唐诗/poet.tang.35000.json','["一家煙島隈，竹裏夜窗開。", "數派分潮去，千檣聚月來。", "石樓雲斷續，澗渚鴈徘徊。", "了得平生志，還歸築釣臺。"]'),
('47d2fb63-14b0-4633-995b-158213cd4380','江村','張喬','唐','唐诗','tang','','[]','貧遊無定蹤，鄉信轉難逢。',48,'全唐诗/poet.tang.35000.json','["貧遊無定蹤，鄉信轉難逢。", "寒渚暮煙闊，去帆歸思重。", "潮平低戍火，木落遠山鐘。", "況是漁家宿，疎籬響夜舂。"]'),
('7f095bdc-f572-422f-bea4-1076af9dfeb4','贈進士顧雲','張喬','唐','唐诗','tang','','[]','潮檻煙波別釣津，西京同□荻□貧。',64,'全唐诗/poet.tang.35000.json','["潮檻煙波別釣津，西京同□荻□貧。", "不知守道歸何日，相對無言盡幾春。", "晴景遠山花外暮，雲邊高蓋水邊□。", "與君愁寂無消處，賒酒青門送楚人。"]'),
('e68d7f43-5046-4c5a-a7b6-074e1783ba38','贈頭陀僧','張喬','唐','唐诗','tang','','[]','自說年深別石橋，遍遊靈跡熟南朝。',64,'全唐诗/poet.tang.35000.json','["自說年深別石橋，遍遊靈跡熟南朝。", "已知世路皆虛幻，不覺空門是寂寥。", "滄海附船浮浪久，碧山尋塔上雲遙。", "如今竹院藏衰老，一點寒燈弟子燒。"]'),
('17ffe0e8-195d-4f2a-b378-40658be1beac','尋陽村舍','張喬','唐','唐诗','tang','','[]','荒林寄遠居，坐臥見樵漁。',48,'全唐诗/poet.tang.35000.json','["荒林寄遠居，坐臥見樵漁。", "夜火隨船遠，寒更出郡疎。", "雪迷登岳路，風阻轉江書。", "寂寞高窗下，思鄉歲欲除。"]'),
('2c01d6b1-945b-45df-bc02-3cd671b258a9','江樓作','張喬','唐','唐诗','tang','','[]','憑檻見天涯，非秋亦可悲。',48,'全唐诗/poet.tang.35000.json','["憑檻見天涯，非秋亦可悲。", "晚天帆去疾，春雪燕來遲。", "山水分鄉縣，干戈足別離。", "南人廢耕織，早晚罷王師。"]'),
('cf0ff1fe-2c03-4b3e-8dd0-ad2a223416c2','回鸞閣寫望','張喬','唐','唐诗','tang','','[]','古閣上空半，寥寥千里心。',48,'全唐诗/poet.tang.35000.json','["古閣上空半，寥寥千里心。", "多年爲客路，盡日倚欄吟。", "山壓秦川重，河來虜塞深。", "回鑾今不見，煙霧杳沉沉。"]'),
('3bd75b1f-9924-4ee8-bd23-9aafb516ec3d','題宣州開元寺','張喬','唐','唐诗','tang','','[]','誰家煙徑長莓苔，金碧虛欄竹上開。',64,'全唐诗/poet.tang.35000.json','["誰家煙徑長莓苔，金碧虛欄竹上開。", "流水遠分山色斷，清猨時帶角聲來。", "六朝明月唯詩在，三楚空山有鴈迴。", "達理始應盡惆悵，僧閑應得話天台。"]'),
('2bcc1839-e35b-4608-89cb-316bc863911f','題友人草堂','張喬','唐','唐诗','tang','','[]','空山卜隱初，生計亦無餘。',48,'全唐诗/poet.tang.35000.json','["空山卜隱初，生計亦無餘。", "三畝水邊竹，一床琴畔書。", "深林收晚果，絕頂拾秋蔬。", "堅話長如此，何年獻子虛。"]'),
('8398ff87-94b9-420a-a5f4-6d3239431fec','七松亭','張喬','唐','唐诗','tang','','[]','七松亭上望秦川，高鳥閑雲滿目前。',64,'全唐诗/poet.tang.35000.json','["七松亭上望秦川，高鳥閑雲滿目前。", "已比子真耕谷口，豈同陶令臥江邊。", "臨崖把卷驚迴燒，掃石留僧聽遠泉。", "明月影中宮漏近，珮聲應宿使朝天。"]'),
('3745325f-2413-45a3-b19b-4fff8e023cc2','題友人林齋','張喬','唐','唐诗','tang','','[]','喬木帶涼蟬，來吟暑雨天。',48,'全唐诗/poet.tang.35000.json','["喬木帶涼蟬，來吟暑雨天。", "不離高枕上，似宿遠山邊。", "簟冷窗中月，茶香竹裏泉。", "吾廬近溪島，憶別動經年。"]'),
('7800bf54-49ad-46cd-8488-95bd78200e8d','經宣城元員外山居','張喬','唐','唐诗','tang','','["\u9ec4\u6cb3"]','無人襲仙隱，石室閉空山。',48,'全唐诗/poet.tang.35000.json','["無人襲仙隱，石室閉空山。", "避燒猨猶到，隨雲鶴不還。", "澗荒巖影在，橋斷樹陰閑。", "但有黃河賦，長留在世間。"]'),
('6af878e9-cdd4-459a-a05a-603fe49909cf','經九華山費徵君故居','張喬','唐','唐诗','tang','','["\u4e5d\u534e\u5c71"]','草堂蕪沒後，來往問樵翁。',48,'全唐诗/poet.tang.35000.json','["草堂蕪沒後，來往問樵翁。", "斷石荒林外，孤墳晚照中。", "數溪分大野，九子立寒空。", "煙壁曾行處，青雲路不通。"]'),
('0814b58c-879d-4e70-bbe1-29ec7e9bf37b','題賈島吟詩臺','張喬','唐','唐诗','tang','','["\u957f\u6c5f"]','吟魂不復遊，臺亦似荒丘。',48,'全唐诗/poet.tang.35000.json','["吟魂不復遊，臺亦似荒丘。", "一徑草中出，長江天外流。", "暝煙寒鳥集，殘月夜蟲愁。", "願得生禾黍，鋤平恨即休。"]'),
('3805cb81-114a-40ca-8eb5-028c0c9d0165','遊南岳','張喬','唐','唐诗','tang','','[]','入巖仙境清，行盡復重行。',48,'全唐诗/poet.tang.35000.json','["入巖仙境清，行盡復重行。", "若得閑無事，長來寄此生。", "澗松閑易老，籠燭晚生明。", "一宿泉聲裏，思鄉夢不成。"]'),
('51a4c495-3f07-4d11-b30a-5ccfc6210734','尋桃源','張喬','唐','唐诗','tang','','[]','武林春草齊，花影隔澄溪。',48,'全唐诗/poet.tang.35000.json','["武林春草齊，花影隔澄溪。", "路遠無人去，山空有鳥啼。", "水垂青靄斷，松偃綠蘿低。", "世上迷途客，經茲盡不迷。"]'),
('afcba299-a46b-4b5d-bd57-7f5df0787cd3','青鳥泉','張喬','唐','唐诗','tang','','[]','祗此沉仙翼，瑤池似不遙。',48,'全唐诗/poet.tang.35000.json','["祗此沉仙翼，瑤池似不遙。", "有聲懸翠壁，無勢下丹霄。", "淨瀨煙霞古，寒原草木凋。", "山河幾更變，幽咽到唐朝。"]'),
('9079d2a2-4ca7-440f-90c0-fbb73330e997','望巫山','張喬','唐','唐诗','tang','','[]','溪疊雲深轉谷遲，暝投孤店草蟲悲。',64,'全唐诗/poet.tang.35000.json','["溪疊雲深轉谷遲，暝投孤店草蟲悲。", "愁連遠水波濤夜，夢斷空山雨雹時。", "邊海故園荒後買，入關玄髪夜來衰。", "東歸未必勝羈旅，況是東歸未有期。"]'),
('3060f939-c1df-4b2b-9dcf-fad407145f75','省中偶作','張喬','唐','唐诗','tang','','[]','二轉郎曹自勉旃，莎階吟步想前賢。',64,'全唐诗/poet.tang.35000.json','["二轉郎曹自勉旃，莎階吟步想前賢。", "不如何遜無佳句，若比馮唐是壯年。", "捧制名題黃紙尾，約僧心在白雲邊。", "乳毛松雪春來好，直夜清閑且學禪。"]'),
('3e22fdfe-3e2f-4130-a417-bb748a736edd','秋夕','張喬','唐','唐诗','tang','','[]','春恨復秋悲，秋悲難到時。',48,'全唐诗/poet.tang.35000.json','["春恨復秋悲，秋悲難到時。", "每逢明月夜，長起故山思。", "巷僻行吟遠，蛩多獨臥遲。", "溪僧與樵客，動別十年期。"]'),
('6d853633-4327-42cd-aed2-ee371fe58ec5','山中冬夜','張喬','唐','唐诗','tang','','[]','寒葉風搖盡，空林鳥宿稀。',36,'全唐诗/poet.tang.35000.json','["寒葉風搖盡，空林鳥宿稀。", "澗冰妨鹿飲，山雪阻僧歸。", "夜坐塵心定，長吟語力微。"]'),
('3f6705ee-8be3-43e1-a22e-e8fadb9fe06a','宿劉溫書齋','張喬','唐','唐诗','tang','','[]','不掩盈窗月，天然格調高。',48,'全唐诗/poet.tang.35000.json','["不掩盈窗月，天然格調高。", "涼風移蟋蟀，落葉在離騷。", "迴筆挑燈燼，懸圖見海濤。", "因論三國志，空載幾英豪。"]'),
('98014159-5660-4ef0-bdce-16012d97b35c','歸舊山','張喬','唐','唐诗','tang','','[]','昔年山下結茅茨，村落重來野徑移。',64,'全唐诗/poet.tang.35000.json','["昔年山下結茅茨，村落重來野徑移。", "樵客相逢悲往事，林僧閑坐問歸期。", "異藤遍樹無空處，幽草緣溪少歇時。", "此景一拋吟欲老，可能文字聖朝知。"]'),
('2617d2ea-5a0f-4485-b0cf-07203461453d','潭上作','張喬','唐','唐诗','tang','','[]','竹島殘陽映翠微，雪翎禽過碧潭飛。',32,'全唐诗/poet.tang.35000.json','["竹島殘陽映翠微，雪翎禽過碧潭飛。", "人間未有關身事，每到漁家不欲歸。"]'),
('29c9bfc7-5f9b-4585-af8b-a1634cc298b2','楊花落','張喬','唐','唐诗','tang','','["\u6625\u5929", "\u559c\u60a6", "\u82b1", "\u5199\u82b1"]','北斗南回春物老，紅英落盡綠尚早。',112,'全唐诗/poet.tang.35000.json','["北斗南回春物老，紅英落盡綠尚早。", "韶風澹蕩無所依，偏惜垂楊作春好。", "此時可憐楊柳花，縈盈豔曳滿人家。", "人家女兒出羅幕，淨掃玉除看花落。", "寶環纖手捧更飛，翠羽輕裙承不著。", "歷歷瑤琴舞袖陳，飛紅拂黛憐玉人。", "東園桃李芳已歇，猶有楊花嬌暮春。"]'),
('a71457b4-1633-488e-8ba4-1265f0a20156','九華樓晴望','張喬','唐','唐诗','tang','','[]','一夜江潭風雨後，九華晴望倚天秋。',32,'全唐诗/poet.tang.35000.json','["一夜江潭風雨後，九華晴望倚天秋。", "重來此地知何日，欲別殷勤更上樓。"]'),
('a3c5b0a0-b08a-4ae7-b60a-b877ce9a18b7','終南山','張喬','唐','唐诗','tang','','["\u7ec8\u5357\u5c71"]','帶雪復銜春，橫天占半秦。',48,'全唐诗/poet.tang.35000.json','["帶雪復銜春，橫天占半秦。", "勢奇看不定，景變寫難真。", "洞遠皆通岳，川多更有神。", "白雲幽絕處，自古屬樵人。"]'),
('5feeaa1c-7e0d-4bc7-809c-02a71ce5c376','哭陳陶','張喬','唐','唐诗','tang','','[]','先生抱衰疾，不起茂陵間。',72,'全唐诗/poet.tang.35000.json','["先生抱衰疾，不起茂陵間。", "夕臨諸孤少，荒居弔客還。", "遺文禪東岳，留語葬鄉山。", "多雨銘旌故，殘燈素帳閑。", "樂章誰與集，隴樹即堪攀。", "神理今難問，予將呌帝關。"]'),
('f3e2ecc5-b67a-4498-ab42-781a23bb2c27','長門怨','張喬','唐','唐诗','tang','','[]','御泉長繞鳳皇樓，自是恩波別處流。',32,'全唐诗/poet.tang.35000.json','["御泉長繞鳳皇樓，自是恩波別處流。", "閑揲舞衣歸未得，夜來砧杵六宮秋。"]'),
('a103eda0-b3fd-4504-ab3c-6fb4a0b26f3d','昇平詞五首 一','曹唐','唐','唐诗','tang','','[]','瑞氣遶宮樓，皇居上苑游。',48,'全唐诗/poet.tang.35000.json','["瑞氣遶宮樓，皇居上苑游。", "遠岡連聖祚，平地載神州。", "會合兼重譯，潺湲近八流。", "中興豈假問，據此自千秋。"]'),
('9eac73d8-38fa-4810-bf49-7f90608883a5','昇平詞五首 二','曹唐','唐','唐诗','tang','','[]','寥泬敞延英，朝班立位橫。',48,'全唐诗/poet.tang.35000.json','["寥泬敞延英，朝班立位橫。", "宣傳無草動，拜舞有衣聲。", "鴛瓦霜消濕，蟲絲日照明。", "辛勤自不到，遙見似前程。"]'),
('83117785-1aae-4dd3-b3ca-cf2e0ca678b2','昇平詞五首 三','曹唐','唐','唐诗','tang','','[]','處處是歡心，時康歲已深。',48,'全唐诗/poet.tang.35000.json','["處處是歡心，時康歲已深。", "不同三尺劒，應似五弦琴。", "壽笑山猶盡，明嫌日有陰。", "何當憐一物，亦遺斷愁吟。"]'),
('22730830-cf5b-4f48-9302-ce9c898bee23','昇平詞五首 四','曹唐','唐','唐诗','tang','','[]','日日聽歌謠，區中盡祝堯。',48,'全唐诗/poet.tang.35000.json','["日日聽歌謠，區中盡祝堯。", "蟲蝗初不害，夷狄近全銷。", "史筆唯書瑞，天臺絕見妖。", "因令匹夫志，轉欲事清朝。"]'),
('75f8b040-292d-4630-ae51-86b5365e6b38','昇平詞五首 五','曹唐','唐','唐诗','tang','','[]','五帝三皇主，蕭曹魏邴臣。',48,'全唐诗/poet.tang.35000.json','["五帝三皇主，蕭曹魏邴臣。", "文章唯返朴，戈甲盡生塵。", "諫紙應無用，朝綱自有倫。", "昇平不可記，所見是閑人。"]'),
('cb35531c-3751-4dc0-9505-7ccbe39a504f','洛東蘭若歸','曹唐','唐','唐诗','tang','','[]','一衲老禪床，吾生半異鄉。',48,'全唐诗/poet.tang.35000.json','["一衲老禪床，吾生半異鄉。", "管弦愁裏老，書劒夢中忙。", "鳥急山初暝，蟬稀樹正涼。", "又歸何處去，塵路月蒼蒼。"]'),
('c347c7aa-4e3b-49dc-ba59-ebd7da87f872','仙都即景','曹唐','唐','唐诗','tang','','[]','黃帝登真處，青青不記年。',48,'全唐诗/poet.tang.35000.json','["黃帝登真處，青青不記年。", "孤峰應礙日，一柱自擎天。", "石怪長棲鶴，雲閑若有仙。", "鼎湖看不見，零落數枝蓮。"]'),
('de9fcd28-5e5b-4322-a8fe-ba67cf1c3f90','漢武帝將候西王母下降','曹唐','唐','唐诗','tang','','[]','崑崙凝想最高峰，王母來乘五色龍。',64,'全唐诗/poet.tang.35000.json','["崑崙凝想最高峰，王母來乘五色龍。", "歌聽紫鸞猶縹緲，語來青鳥許從容。", "風迴水落三清月，漏苦霜傳五夜鐘。", "樹影悠悠花悄悄，若聞簫管是行蹤。"]'),
('d21e0ad6-2739-41bc-8476-7af65282a844','漢武帝於宮中宴西王母','曹唐','唐','唐诗','tang','','[]','鼇岫雲低太一壇，武皇齋潔不勝懽。',64,'全唐诗/poet.tang.35000.json','["鼇岫雲低太一壇，武皇齋潔不勝懽。", "長生碧字期親署，延壽丹泉許細看。", "劒佩有聲宮樹靜，星河無影禁花寒。", "秋風褭褭月朗朗，玉女清歌一夜闌。"]'),
('c3ef8154-75da-4136-a018-36b95fba1bd4','劉晨阮肇遊天台','曹唐','唐','唐诗','tang','','[]','樹入天台石路新，雲和草靜迥無塵。',64,'全唐诗/poet.tang.35000.json','["樹入天台石路新，雲和草靜迥無塵。", "煙霞不省生前事，水木空疑夢後身。", "往往雞鳴巖下月，時時犬吠洞中春。", "不知此地歸何處，須就桃源問主人。"]'),
('a6bdbc47-6fcd-459a-a52b-441714614a87','劉阮洞中遇仙子','曹唐','唐','唐诗','tang','','[]','天和樹色靄蒼蒼，霞重嵐深路渺茫。',64,'全唐诗/poet.tang.35000.json','["天和樹色靄蒼蒼，霞重嵐深路渺茫。", "雲實滿山無鳥雀，水聲沿澗有笙簧。", "碧沙洞裏乾坤別，紅樹枝前日月長。", "願得花間有人出，免令仙犬吠劉郎。"]'),
('26fa2cba-4c75-4b87-83e5-4f941cc54540','仙子送劉阮出洞','曹唐','唐','唐诗','tang','','[]','殷勤相送出天台，仙境那能却再來。',64,'全唐诗/poet.tang.35000.json','["殷勤相送出天台，仙境那能却再來。", "雲液每歸須強飲，玉書無事莫頻開。", "花當洞口應長在，水到人間定不迴。", "惆悵溪頭從此別，碧山明月閉蒼苔。"]'),
('a5b6e597-69ab-48d4-b1e1-ad180c6dcb2a','仙子洞中有懷劉阮','曹唐','唐','唐诗','tang','','[]','不將清瑟理霓裳，塵夢那知鶴夢長。',64,'全唐诗/poet.tang.35000.json','["不將清瑟理霓裳，塵夢那知鶴夢長。", "洞裏有天春寂寂，人間無路月茫茫。", "玉沙瑤草連溪碧，流水桃花滿澗香。", "曉露風燈零落盡，此生無處訪劉郎。"]'),
('623e9184-c669-4bad-8a09-96faa95732f1','劉阮再到天台不復見仙子','曹唐','唐','唐诗','tang','','[]','再到天台訪玉真，青苔白石已成塵。',64,'全唐诗/poet.tang.35000.json','["再到天台訪玉真，青苔白石已成塵。", "笙歌冥寞閑深洞，雲鶴蕭條絕舊隣。", "草樹總非前度色，煙霞不似昔年春。", "桃花流水依然在，不見當時勸酒人。"]'),
('9997089f-74db-4739-9d9a-8e632fc48490','織女懷牽牛','曹唐','唐','唐诗','tang','','[]','北斗佳人雙淚流，眼穿腸斷爲牽牛。',64,'全唐诗/poet.tang.35000.json','["北斗佳人雙淚流，眼穿腸斷爲牽牛。", "封題錦字凝新恨，拋擲金梭織舊愁。", "桂樹三春煙漠漠，銀河一水夜悠悠。", "欲將心向仙郎說，借問榆花早晚秋。"]'),
('64b63980-020d-45a5-b71f-a6d75cd40645','王遠宴麻姑蔡經宅','曹唐','唐','唐诗','tang','','[]','好風吹樹杏花香，花下真人道姓王。',64,'全唐诗/poet.tang.35000.json','["好風吹樹杏花香，花下真人道姓王。", "大篆龍蛇隨筆札，小天星斗滿衣裳。", "閑拋南極歸期晚，笑指東溟飲興長。", "要喚麻姑同一醉，使人沽酒向餘杭。"]'),
('cc724846-47d8-4ebe-9b3a-017a1b0b2aeb','萼綠華將歸九疑留別許真人','曹唐','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','九點秋煙黛色空，綠華歸思頗無窮。',64,'全唐诗/poet.tang.35000.json','["九點秋煙黛色空，綠華歸思頗無窮。", "每悲馭鶴身難任，長恨臨霞語未終。", "河影暗吹雲夢月，花聲閑落洞庭風。", "藍絲重勒金條脫，留與人間許侍中。"]'),
('9fd4dfc0-30a5-461e-a773-1e1ae708669b','穆王宴王母於九光流霞館','曹唐','唐','唐诗','tang','','[]','桑葉扶疎閉日華，穆王邀命宴流霞。',64,'全唐诗/poet.tang.35000.json','["桑葉扶疎閉日華，穆王邀命宴流霞。", "霓旌著地雲初駐，金奏掀天月欲斜。", "歌咽細風吹粉蕊，飲餘清露濕瑤砂。", "不知白馬紅韁解，偷喫東田碧玉花。"]'),
('34805ce9-6ec1-4637-9395-1426e04d5f8f','紫河張休真','曹唐','唐','唐诗','tang','','[]','琪樹扶疎壓瑞煙，玉皇朝客滿花前。',64,'全唐诗/poet.tang.35000.json','["琪樹扶疎壓瑞煙，玉皇朝客滿花前。", "山川到處成三月，絲竹經時即萬年。", "樹石冥茫初縮地，杯盤狼籍未朝天。", "東風小飲人皆醉，從聽黃龍枕水眠。"]'),
('6750faf7-0641-4e38-85c7-097e7cdcf93c','張碩重寄杜蘭香','曹唐','唐','唐诗','tang','','[]','碧落香銷蘭露秋，星河無夢夜悠悠。',64,'全唐诗/poet.tang.35000.json','["碧落香銷蘭露秋，星河無夢夜悠悠。", "靈妃不降三清駕，仙鶴空成萬古愁。", "浩月隔花追欵別，瑞煙籠樹省淹留。", "人間何事堪惆悵，海色西風十二樓。"]'),
('3f65f20f-056b-4a05-bc38-7b05ce3f428a','玉女杜蘭香下嫁於張碩','曹唐','唐','唐诗','tang','','[]','天上人間兩渺茫，不知誰識杜蘭香。',64,'全唐诗/poet.tang.35000.json','["天上人間兩渺茫，不知誰識杜蘭香。", "來經玉樹三山遠，去隔銀河一水長。", "怨入清塵愁錦瑟，酒傾玄露醉瑤觴。", "遺情更說何珍重，擘破雲鬟金鳳皇。"]'),
('e4ef6636-167c-4e76-874d-b6011d689809','蕭史攜弄玉上昇','曹唐','唐','唐诗','tang','','[]','豈是丹臺歸路遙，紫鸞煙駕不同飄。',64,'全唐诗/poet.tang.35000.json','["豈是丹臺歸路遙，紫鸞煙駕不同飄。", "一聲洛水傳幽咽，萬片宮花共寂寥。", "紅粉美人愁未散，清華公子笑相邀。", "緱山碧樹青樓月，腸斷春風爲玉簫。"]'),
('1db3af61-7f6b-451f-90f2-47c03ff2f7dc','皇初平將入金華山','曹唐','唐','唐诗','tang','','[]','莫道真遊煙景賒，瀟湘有路入京華。',64,'全唐诗/poet.tang.35000.json','["莫道真遊煙景賒，瀟湘有路入京華。", "溪頭鶴樹春常在，洞口人家日易斜。", "一水暗鳴閑遶澗，五雲長往不還家。", "白羊成隊難收拾，喫盡溪邊巨勝花。"]'),
('16b38c69-8483-4e41-b359-ceadd408aeb1','漢武帝思李夫人','曹唐','唐','唐诗','tang','','[]','惆悵冰顏不復歸，晚秋黃葉滿天飛。',64,'全唐诗/poet.tang.35000.json','["惆悵冰顏不復歸，晚秋黃葉滿天飛。", "迎風細荇傳香粉，隔水殘霞見畫衣。", "白玉帳寒鴛夢絕，紫陽宮遠雁書稀。", "夜深池上蘭橈歇，斷續歌聲徹太微。"]'),
('d0934c60-d894-408e-8b53-614e0ed3412f','送羽人王錫歸羅浮','曹唐','唐','唐诗','tang','','[]','風前整頓紫荷巾，常向羅浮保養神。',64,'全唐诗/poet.tang.35000.json','["風前整頓紫荷巾，常向羅浮保養神。", "石磴倚天行帶月，鐵橋通海入無塵。", "龍蛇出洞閑邀雨，犀象眠花不避人。", "最愛葛洪尋藥處，露苗煙蕊滿山春。"]'),
('2ec81852-3ed9-4e2f-a6b2-8e2dd8d0c1b5','送劉尊師祗詔闕庭三首 一','曹唐','唐','唐诗','tang','','[]','海風葉葉駕霓旌，天路悠悠接上清。',64,'全唐诗/poet.tang.35000.json','["海風葉葉駕霓旌，天路悠悠接上清。", "錦誥淒涼遺去恨，玉簫哀絕醉離情。", "五湖夜月幡幢濕，雙闕清風劒珮輕。", "從此暫辭華表柱，便應千載是歸程。"]'),
('f43b7380-4f3b-4b8f-ab2d-1fbfecad43b9','送劉尊師祗詔闕庭三首 二','曹唐','唐','唐诗','tang','','[]','五峰已別隔人間，雙闕何年許再還。',64,'全唐诗/poet.tang.35000.json','["五峰已別隔人間，雙闕何年許再還。", "既埽山川收地脉，須留日月駐天顏。", "霞觴共飲身雖在，風馭難陪跡未閑。", "從此枕中唯有夢，夢魂何處訪三山。"]'),
('420aa1d7-a1ea-4676-b7d0-a61a08f80293','送劉尊師祗詔闕庭三首 三','曹唐','唐','唐诗','tang','','[]','仙老閑眠碧草堂，帝書徵入白雲鄉。',64,'全唐诗/poet.tang.35000.json','["仙老閑眠碧草堂，帝書徵入白雲鄉。", "龜臺欲署長生籍，鸞殿還論不死方。", "紅露想傾延命酒，素煙思爇降真香。", "五千言外無文字，更有何詞贈武皇。"]'),
('2693a9bf-a0ba-44bd-b308-4de0b9925856','三年冬大禮五首 一','曹唐','唐','唐诗','tang','','[]','皇帝齋心潔素誠，自朝真祖報升平。',64,'全唐诗/poet.tang.35000.json','["皇帝齋心潔素誠，自朝真祖報升平。", "華山秋草多歸馬，滄海寒波絕洗兵。", "銀箭水殘河勢斷，玉爐煙盡日華生。", "千官整肅三天夜，劒佩初聞入太清。"]'),
('efc07ef1-651f-4c45-9125-010ad5982816','三年冬大禮五首 二','曹唐','唐','唐诗','tang','','[]','海日西飛度禁林，太清宮殿月沉沉。',64,'全唐诗/poet.tang.35000.json','["海日西飛度禁林，太清宮殿月沉沉。", "不聞北斗傾堯酒，空覺南風入舜琴。", "歌壓鈞天閑夢盡，詔歸秋水道情深。", "雪風更起古杉葉，時送步虛清磬音。"]'),
('0e7f2b31-b1e2-4579-a77d-e038dd8512d7','三年冬大禮五首 三','曹唐','唐','唐诗','tang','','[]','太一天壇降紫君，屬車龍鶴夜成羣。',64,'全唐诗/poet.tang.35000.json','["太一天壇降紫君，屬車龍鶴夜成羣。", "春浮玉藻寒初落，露拂金莖曙欲分。", "三代樂迴風入律，四溟歌駐水成文。", "千官不動旌旗下，日照南山萬樹雲。"]'),
('5f2ac80b-014e-485a-a6d1-0968c1466b39','三年冬大禮五首 四','曹唐','唐','唐诗','tang','','[]','山擁飛雲海水清，天壇未夕仗先成。',64,'全唐诗/poet.tang.35000.json','["山擁飛雲海水清，天壇未夕仗先成。", "千官不起金縢議，萬國空瞻玉藻聲。", "禁火曙然煙焰褭，宮衣寒拂雪花輕。", "側聞左右皆周呂，看取從容致太平。"]'),
('f8b618be-e9b4-48aa-8408-f626a6737e7b','三年冬大禮五首 五','曹唐','唐','唐诗','tang','','[]','太和琴暖發南薰，水闊風高得細聞。',64,'全唐诗/poet.tang.35000.json','["太和琴暖發南薰，水闊風高得細聞。", "滄海舉歌夔是相，歷山迴禪舜爲君。", "翠微呼處生丹障，清靜封中起白雲。", "今日病身慙小隱，欲將泉石勒移文。"]'),
('91ba5715-a6d7-4ffc-b38b-01fd6c37d1fe','暮春戲贈吳端公','曹唐','唐','唐诗','tang','','[]','年少英雄好丈夫，大家望拜執金吾。',64,'全唐诗/poet.tang.35000.json','["年少英雄好丈夫，大家望拜執金吾。", "閑眠曉日聽鶗鴂，笑倚春風仗轆轤。", "深院吹笙聞漢婢，靜街調馬任奚奴。", "牡丹花下簾鉤外，獨凭紅肌捋虎鬚。"]'),
('e0fca6bb-3db4-476d-a052-a47ead7b87ae','奉送嚴大夫再領容府二首 一','曹唐','唐','唐诗','tang','','[]','海風捲樹凍嵐消，憂國寧辭嶺外遙。',64,'全唐诗/poet.tang.35000.json','["海風捲樹凍嵐消，憂國寧辭嶺外遙。", "自顧勤勞甘百戰，不將功業負三朝。", "劒澄黑水曾芟虎，箭劈黃雲慣射鵰。", "代北天南盡成事，肯將心許霍嫖姚。"]'),
('d6a6bdae-51a9-4f5a-903a-ac72b298e06e','奉送嚴大夫再領容府二首 二','曹唐','唐','唐诗','tang','','[]','日照雙旌射火山，笑迎賓從却南還。',64,'全唐诗/poet.tang.35000.json','["日照雙旌射火山，笑迎賓從却南還。", "風雲暗發談諧外，感會潛生氣概間。", "蘄竹水翻臺榭濕，刺桐花落管弦閑。", "無因得靸真珠履，親從新侯定八蠻。"]'),
('501d63f0-e30d-4006-9524-c7c013540132','贈南嶽馮處士二首 一','曹唐','唐','唐诗','tang','','["\u8861\u5c71"]','白石溪邊自結廬，風泉滿院稱幽居。',64,'全唐诗/poet.tang.35000.json','["白石溪邊自結廬，風泉滿院稱幽居。", "鳥啼深樹斸靈藥，花落閑窗看道書。", "煙嵐晚過鹿裘濕，水月夜明山舍虛。", "支頤冷笑緣名出，終日王門強曳裾。"]'),
('3e64c186-49c7-4352-8b70-28c7211aa361','贈南嶽馮處士二首 二','曹唐','唐','唐诗','tang','','["\u8861\u5c71"]','寂寥深木閉煙霞，洞裏相知有幾家。',64,'全唐诗/poet.tang.35000.json','["寂寥深木閉煙霞，洞裏相知有幾家。", "笑看潭魚吹水沫，醉嗔溪鹿吃蕉花。", "穿廚歷歷泉聲細，繞屋悠悠樹影斜。", "夜靜著灰封釜竈，自添文武養丹砂。"]'),
('1811949c-c4d2-4279-b776-b2c87c225331','題子姪書院雙松','曹唐','唐','唐诗','tang','','[]','自種雙松費幾錢，頓令院落似秋天。',64,'全唐诗/poet.tang.35000.json','["自種雙松費幾錢，頓令院落似秋天。", "能藏此地新晴雨，却惹空山舊燒煙。", "枝壓細風過枕上，影籠殘月到窗前。", "莫教取次成閑夢，使汝悠悠十八年。"]'),
('fcb3cdef-69cc-4b4a-94e1-49704bfaa4b8','羽林賈中丞','曹唐','唐','唐诗','tang','','[]','四十年前百戰身，曾驅虎隊掃胡塵。',64,'全唐诗/poet.tang.35000.json','["四十年前百戰身，曾驅虎隊掃胡塵。", "風悲鼓角榆關暮，日暖旌旗隴草春。", "鐵馬慣牽邀上客，金魚多解乞佳人。", "胸中別有安邊計，誰睬髭鬚白似銀。"]'),
('f6ff95f0-d92f-4414-a409-46cb0d088510','送康祭酒赴輪臺','曹唐','唐','唐诗','tang','','[]','灞水橋邊酒一杯，送君千里赴輪臺。',64,'全唐诗/poet.tang.35000.json','["灞水橋邊酒一杯，送君千里赴輪臺。", "霜黏海眼旗聲凍，風射犀文甲縫開。", "斷磧簇煙山似米，野營軒地鼓如雷。", "分明會得將軍意，不斬樓蘭不擬迴。"]'),
('e39e7275-e294-410f-a36d-e848290d9d27','南遊','曹唐','唐','唐诗','tang','','[]','盡興南遊卒未迴，水工舟子不須催。',48,'全唐诗/poet.tang.35000.json','["盡興南遊卒未迴，水工舟子不須催。", "政思碧樹關心句，難放紅螺蘸甲杯。", "漲海潮生陰火滅，蒼梧風暖瘴雲開。"]'),
('cefbdf8b-9dda-4024-8d4c-0b51d8f82379','哭陷邊許兵馬使','曹唐','唐','唐诗','tang','','[]','北風裂地黯邊霜，戰敗桑乾日色黃。',64,'全唐诗/poet.tang.35000.json','["北風裂地黯邊霜，戰敗桑乾日色黃。", "故國暗迴殘士卒，新墳空葬舊衣裳。", "散牽細馬嘶青草，任去佳人弔白楊。", "除却陰符與兵法，更無一物在儀牀。"]'),
('a963f58e-ac9f-498d-96fb-6e15ec249d80','和周侍御買劍','曹唐','唐','唐诗','tang','','[]','將軍溢價買吳鉤，要與中原靜寇讐。',64,'全唐诗/poet.tang.35000.json','["將軍溢價買吳鉤，要與中原靜寇讐。", "試挂窗前驚電轉，略拋牀下怕泉流。", "青天露拔雲霓泣，黑地潛擎鬼魅愁。", "見說夜深星斗畔，等閑期尅月支頭。"]'),
('f7edff69-936c-44c3-8d2e-15217629e066','病馬五首呈鄭校書章三吳十五先輩 一','曹唐','唐','唐诗','tang','','[]','騄駬何年別渥洼。',64,'全唐诗/poet.tang.35000.json','["騄駬何年別渥洼。", "病來顏色半泥沙，四蹄不鑿金砧裂。", "雙眼慵開玉筯斜，墮月兔毛乾觳𧥆。", "失雲龍骨瘦牙槎，平原好放無人放。", "嘶向秋風苜蓿花。"]'),
('5710a187-8b53-40fe-87be-4e5633d8712f','病馬五首呈鄭校書章三吳十五先輩 二','曹唐','唐','唐诗','tang','','[]','隴上沙蔥葉正齊，騰黃猶自跼羸蹄。',64,'全唐诗/poet.tang.35000.json','["隴上沙蔥葉正齊，騰黃猶自跼羸蹄。", "尾蟠夜雨紅絲脆，頭捽秋風白練低。", "力憊未思金絡腦，影寒空望錦障泥。", "階前莫怪垂雙淚，不遇孫陽不敢嘶。"]'),
('25131a88-021a-4321-82ed-b8612738959c','病馬五首呈鄭校書章三吳十五先輩 三','曹唐','唐','唐诗','tang','','[]','不剪焦毛鬣半翻，何人別是古龍孫。',64,'全唐诗/poet.tang.35000.json','["不剪焦毛鬣半翻，何人別是古龍孫。", "霜侵病骨無驕氣，土蝕驄花見臥痕。", "未噴斷雲歸漢苑，曾追輕練過吳門。", "一朝千里心猶在，爭肯潛忘秣飼恩。"]'),
('d40daf0a-349c-428f-a8d5-d292ca483ef2','病馬五首呈鄭校書章三吳十五先輩 四','曹唐','唐','唐诗','tang','','[]','空被秋風吹病毛，無因濯浪刷洪濤。',64,'全唐诗/poet.tang.35000.json','["空被秋風吹病毛，無因濯浪刷洪濤。", "臥來總怪龍蹄跙，瘦盡誰驚虎口高。", "追電有心猶欵段，逢人相骨強嘶號。", "欲將鬐鬣重裁剪，乞借新成利鉸刀。"]'),
('69ac559f-09b2-47c1-80e3-9aa78c7966ae','病馬五首呈鄭校書章三吳十五先輩 五','曹唐','唐','唐诗','tang','','[]','病久無人著意看，玉華衫色欲凋殘。',64,'全唐诗/poet.tang.35000.json','["病久無人著意看，玉華衫色欲凋殘。", "飲驚白露泉花冷，喫怕清秋荳葉寒。", "長襜敢辭紅錦重，舊韁寧畏紫絲蟠。", "王良若許相擡策，千里追風也不難。"]'),
('15dbfa5b-036e-4af5-be46-14c2bf2adb1d','長安客舍敘邵陵舊宴寄永州蕭使君五首 一','曹唐','唐','唐诗','tang','','[]','邵陵佳樹碧蔥蘢，河漢西沈宴未終。',64,'全唐诗/poet.tang.35000.json','["邵陵佳樹碧蔥蘢，河漢西沈宴未終。", "殘漏五更傳海月，清笳三會揭天風。", "香熏舞席雲鬟綠，光射頭盤蠟燭紅。", "今日却懷行樂處，兩床絲竹水樓中。"]'),
('4b1913e9-9086-4d5d-a4a9-096b2a4917ac','長安客舍敘邵陵舊宴寄永州蕭使君五首 二','曹唐','唐','唐诗','tang','','[]','不知何路却飛翻，虛受賢侯鄭重恩。',64,'全唐诗/poet.tang.35000.json','["不知何路却飛翻，虛受賢侯鄭重恩。", "五夜清歌敲玉樹，三年洪飲倒金尊。", "招攜永感雙魚在，報荅空知一劒存。", "狼籍棃花滿城月，當時長醉信陵門。"]'),
('5c30c2cb-23be-4dc8-8b40-902f121c1864','長安客舍敘邵陵舊宴寄永州蕭使君五首 三','曹唐','唐','唐诗','tang','','[]','粉堞彤軒畫障西，水雲紅樹窣璇題。',64,'全唐诗/poet.tang.35000.json','["粉堞彤軒畫障西，水雲紅樹窣璇題。", "鷓鴣欲絕歌聲定，鸜鵒初驚舞袖齊。", "坐對玉山空甸線，細聽金石怕低迷。", "東風夜月三年飲，不省非時不似泥。"]'),
('fe929876-6e1c-4a62-891c-9c302a5154ee','長安客舍敘邵陵舊宴寄永州蕭使君五首 四','曹唐','唐','唐诗','tang','','[]','木魚金鑰鎖春城，夜上紅樓縱酒情。',64,'全唐诗/poet.tang.35000.json','["木魚金鑰鎖春城，夜上紅樓縱酒情。", "竹葉水繁更漏促，桐花風軟管弦清。", "百分散打銀船溢，十指寬催玉筯輕。", "星斗漸稀賓客散，碧雲猶戀豔歌聲。"]'),
('975f674b-37c5-4e60-9974-cd0c7e2e2ce5','長安客舍敘邵陵舊宴寄永州蕭使君五首 五','曹唐','唐','唐诗','tang','','[]','三年身逐漢諸侯，賓榻容居最上頭。',64,'全唐诗/poet.tang.35000.json','["三年身逐漢諸侯，賓榻容居最上頭。", "飽聽笙歌陪痛飲，熟尋雲水縱閑遊。", "朱門鎖閉煙嵐暮，鈴閣清冷水木秋。", "月滿前山圓不動，更邀詩客上高樓。"]'),
('cc1f27bd-d0da-43d9-adb3-c33c9c9b02c7','勗劒','曹唐','唐','唐诗','tang','','[]','古物神光雪見羞，未能擎出恐泉流。',64,'全唐诗/poet.tang.35000.json','["古物神光雪見羞，未能擎出恐泉流。", "暗臨黑水蛟螭泣，潛倚空山鬼魅愁。", "生怕雷霆號澗底，長聞風雨在牀頭。", "垂情不用將閑氣，惱亂司空犯斗牛。"]'),
('a973a52b-b7e5-4c37-b247-c1d7a89a43b2','仙都即景','曹唐','唐','唐诗','tang','','[]','蟠桃花老華陽東，軒后登真謝六宮。',64,'全唐诗/poet.tang.35000.json','["蟠桃花老華陽東，軒后登真謝六宮。", "旌節暗迎歸碧落，笙歌遙聽隔崆峒。", "衣冠留葬橋山月，劒履將隨浪海風。", "看却龍髯攀不得，紅霞零落鼎湖空。"]'),
('13227c7a-3367-4bdc-a362-094c8ff6e94b','望九華寄池陽杜員外','曹唐','唐','唐诗','tang','','[]','戴月早辭三秀館，遲明初識九華峰。',64,'全唐诗/poet.tang.35000.json','["戴月早辭三秀館，遲明初識九華峰。", "差差玉劒寒鋩利，褭褭青蓮翠葉重。", "奇狀却疑人畫出，嵐光如爲客添濃。", "行春若到五溪上，此處褰帷正面逢。"]'),
('1b1ade71-4a27-4fdf-9956-d72894160f51','小遊仙詩九十八首 一','曹唐','唐','唐诗','tang','','[]','玉簫金瑟發商聲，桑葉枯乾海水清。',32,'全唐诗/poet.tang.35000.json','["玉簫金瑟發商聲，桑葉枯乾海水清。", "淨埽蓬萊山下路，略邀王母話長生。"]'),
('9baeafdd-69f2-46c2-933a-8ce96b2502cc','小遊仙詩九十八首 二','曹唐','唐','唐诗','tang','','[]','上元元日豁明堂，五帝望空拜玉皇。',32,'全唐诗/poet.tang.35000.json','["上元元日豁明堂，五帝望空拜玉皇。", "萬樹琪花千圃藥，心知不敢輒形相。"]'),
('d064aaeb-2832-4d34-b7cf-2cb9b2d967ca','小遊仙詩九十八首 三','曹唐','唐','唐诗','tang','','[]','騎龍重過玉溪頭，紅葉還春碧水流。',32,'全唐诗/poet.tang.35000.json','["騎龍重過玉溪頭，紅葉還春碧水流。", "省得壺中見天地，壺中天地不曾秋。"]'),
('b259d59b-4adc-470b-b561-cc2ea4231800','小遊仙詩九十八首 四','曹唐','唐','唐诗','tang','','[]','真王未許久從容，立在花前別甯封。',32,'全唐诗/poet.tang.35000.json','["真王未許久從容，立在花前別甯封。", "手把玉簫頭不舉，自愁如醉倚黃龍。"]'),
('9e8c29bd-15b1-4875-9eb6-d3309884efe6','小遊仙詩九十八首 五','曹唐','唐','唐诗','tang','','[]','金殿無人鏁絳煙，玉郎並不賞丹田。',32,'全唐诗/poet.tang.35000.json','["金殿無人鏁絳煙，玉郎並不賞丹田。", "白龍蹀躞難迴跋，爭下紅綃碧玉鞭。"]'),
('be1499d3-f9ec-4820-8dd3-2fc40129d692','小遊仙詩九十八首 六','曹唐','唐','唐诗','tang','','[]','玄洲草木不知黃，甲子初開浩劫長。',32,'全唐诗/poet.tang.35000.json','["玄洲草木不知黃，甲子初開浩劫長。", "無限萬年年少女，手攀紅樹滿殘陽。"]'),
('730d3e9d-6128-4ab0-9357-99bd7463bab4','小遊仙詩九十八首 七','曹唐','唐','唐诗','tang','','[]','宮闕重重閉玉林，崑崙高闢彩雲深。',32,'全唐诗/poet.tang.35000.json','["宮闕重重閉玉林，崑崙高闢彩雲深。", "黄龍掉尾引郎去，使妾月眀何處尋。"]'),
('c25f6713-1db4-410c-9567-47f7d6a74c5f','小遊仙詩九十八首 八','曹唐','唐','唐诗','tang','','[]','風滿塗山玉蕊稀，赤龍閑臥鶴東飛。',32,'全唐诗/poet.tang.35000.json','["風滿塗山玉蕊稀，赤龍閑臥鶴東飛。", "紫棃爛盡無人喫，何事韓君去不歸。"]'),
('5e980d63-2a35-436d-bcc9-0deb97bfd097','小遊仙詩九十八首 九','曹唐','唐','唐诗','tang','','[]','武帝徒勞厭暮年，不曾清淨不精專。',32,'全唐诗/poet.tang.35000.json','["武帝徒勞厭暮年，不曾清淨不精專。", "上元少女絕還往，滿竈丹成白玉煙。"]'),
('02db2c92-3745-4d56-86b6-5482956b8541','小遊仙詩九十八首 十','曹唐','唐','唐诗','tang','','[]','百辟朝回閉玉除，露風清宴桂花疎。',32,'全唐诗/poet.tang.35000.json','["百辟朝回閉玉除，露風清宴桂花疎。", "西歸使者騎金虎，嚲鞚垂鞭唱步虛。"]'),
('399a4873-ea86-43e3-b82f-1c86e1fdd1d4','小遊仙詩九十八首 十一','曹唐','唐','唐诗','tang','','[]','南斗闌珊北斗稀，茅君夜著紫霞衣。',32,'全唐诗/poet.tang.35000.json','["南斗闌珊北斗稀，茅君夜著紫霞衣。", "朝騎白鹿趁朝去，鳳押笙歌逐後飛。"]'),
('56c6faaa-3e91-4a4b-a503-89971a034fe7','小遊仙詩九十八首 十二','曹唐','唐','唐诗','tang','','[]','焚香獨自上天壇，桂樹風吹玉簡寒。',32,'全唐诗/poet.tang.35000.json','["焚香獨自上天壇，桂樹風吹玉簡寒。", "長怕嵇康乏僊骨，與將僊籍再尋看。"]'),
('08884bd9-1832-48a3-ab03-376eb0234672','小遊仙詩九十八首 十三','曹唐','唐','唐诗','tang','','[]','冰屋朱扉曉未開，誰將金策扣瓊臺。',32,'全唐诗/poet.tang.35000.json','["冰屋朱扉曉未開，誰將金策扣瓊臺。", "碧花紅尾小僊犬，閑吠五雲嗔客來。"]'),
('b0f90606-fbbc-425c-8364-53f29dfa8cd3','小遊仙詩九十八首 十四','曹唐','唐','唐诗','tang','','[]','酒釅春濃瓊草齊，真公飲散醉如泥。',32,'全唐诗/poet.tang.35000.json','["酒釅春濃瓊草齊，真公飲散醉如泥。", "朱輪軋軋入雲去，行到半天聞馬嘶。"]'),
('ab077cee-5726-42f6-a888-6d46b8b15078','小遊仙詩九十八首 十五','曹唐','唐','唐诗','tang','','[]','白石山中自有天，竹花藤葉隔溪煙。',32,'全唐诗/poet.tang.35000.json','["白石山中自有天，竹花藤葉隔溪煙。", "朝來洞口圍碁了，賭得青龍直幾錢。"]'),
('57f3c7a7-adc7-4757-9cfd-ea1f20128959','小遊仙詩九十八首 十六','曹唐','唐','唐诗','tang','','[]','海水西飛照柏林，青雲斜倚錦雲深。',32,'全唐诗/poet.tang.35000.json','["海水西飛照柏林，青雲斜倚錦雲深。", "水風暗入古山葉，吹斷步虛清磬音。"]'),
('e5ca2871-c1e9-4956-9187-830d37b1399e','小遊仙詩九十八首 十七','曹唐','唐','唐诗','tang','','[]','玉詔新除沈侍郎，便分茅土鎮東方。',32,'全唐诗/poet.tang.35000.json','["玉詔新除沈侍郎，便分茅土鎮東方。", "不知今夕游何處，侍從皆騎白鳳凰。"]'),
('698e79de-d181-44ba-b407-a875130650af','小遊仙詩九十八首 十八','曹唐','唐','唐诗','tang','','[]','洞裏煙霞無歇時，洞中天地足金芝。',32,'全唐诗/poet.tang.35000.json','["洞裏煙霞無歇時，洞中天地足金芝。", "月明朗朗溪頭樹，白髮老人相對棊。"]'),
('e6506ffd-fea9-46dd-ad19-0fc99023a3db','小遊仙詩九十八首 十九','曹唐','唐','唐诗','tang','','[]','飢即餐霞悶即行，一聲長嘯萬山青。',32,'全唐诗/poet.tang.35000.json','["飢即餐霞悶即行，一聲長嘯萬山青。", "穿花渡水來相訪，珍重多才阮步兵。"]'),
('f272c7e0-719f-4c40-9c48-b1a38f5c13be','小遊仙詩九十八首 二十','曹唐','唐','唐诗','tang','','[]','東妃閑著翠霞裙，自領笙歌出五雲。',32,'全唐诗/poet.tang.35000.json','["東妃閑著翠霞裙，自領笙歌出五雲。", "清思密談誰第一，不過邀取小茅君。"]'),
('1fede091-6a7f-4bba-92bc-fde38ab07b0a','小遊仙詩九十八首 二十一','曹唐','唐','唐诗','tang','','[]','月影悠悠秋樹明，露吹犀簟象牀輕。',32,'全唐诗/poet.tang.35000.json','["月影悠悠秋樹明，露吹犀簟象牀輕。", "嬪妃久立帳門外，暗笑夫人推酒聲。"]'),
('a57330ac-3d46-4d64-b3c9-95b2f3f80838','小遊仙詩九十八首 二十二','曹唐','唐','唐诗','tang','','[]','九天天路入雲長，燕使何由到上方。',32,'全唐诗/poet.tang.35000.json','["九天天路入雲長，燕使何由到上方。", "玉女暗來花下立，手挼裙帶問昭王。"]'),
('5682d0fe-9c5e-4f3e-8eab-019e8bc35607','小遊仙詩九十八首 二十三','曹唐','唐','唐诗','tang','','[]','玉皇賜妾紫衣裳，教向桃源嫁阮郎。',32,'全唐诗/poet.tang.35000.json','["玉皇賜妾紫衣裳，教向桃源嫁阮郎。", "爛煮瓊花勸君喫，恐君毛鬢暗成霜。"]'),
('1a9fd3a8-6222-41fb-967f-1073d97d5d42','小遊仙詩九十八首 二十四','曹唐','唐','唐诗','tang','','[]','花底休傾綠玉巵，雲中含笑向安期。',32,'全唐诗/poet.tang.35000.json','["花底休傾綠玉巵，雲中含笑向安期。", "窮陽有數不知數，大似人間年少兒。"]'),
('2adb16a0-ab53-4730-8f5a-32a05038347d','小遊仙詩九十八首 二十五','曹唐','唐','唐诗','tang','','[]','玉色雌龍金絡頭，真妃騎出縱閑遊。',32,'全唐诗/poet.tang.35000.json','["玉色雌龍金絡頭，真妃騎出縱閑遊。", "崑崙山上桃花底，一曲商歌天地秋。"]'),
('f138f395-d02f-423f-a9a8-f009e4dac3c5','小遊仙詩九十八首 二十六','曹唐','唐','唐诗','tang','','[]','偷來洞口訪劉君，緩步輕擡玉線裙。',32,'全唐诗/poet.tang.35000.json','["偷來洞口訪劉君，緩步輕擡玉線裙。", "細擘桃花逐流水，更無言語倚彤雲。"]'),
('4bc9e6bc-732f-4af0-a93e-81438f68bb36','小遊仙詩九十八首 二十七','曹唐','唐','唐诗','tang','','[]','西漢夫人下太虛，九霞裙幅五雲輿。',32,'全唐诗/poet.tang.35000.json','["西漢夫人下太虛，九霞裙幅五雲輿。", "欲將碧字相教示，自解盤囊出素書。"]'),
