('e8d6113a-85cf-49b1-a2d5-2f20aef89ae5','小遊仙詩九十八首 六十九','曹唐','唐','唐诗','tang','','[]','笑擎雲液紫瑤觥，共請雲和碧玉笙。',32,'全唐诗/poet.tang.35000.json','["笑擎雲液紫瑤觥，共請雲和碧玉笙。", "花下偶然吹一曲，人間因織董雙成。"]'),
('238ab7ce-a409-4223-8dc4-171cdf1caa9d','小遊仙詩九十八首 七十','曹唐','唐','唐诗','tang','','[]','東皇長女沒多年，從洗金芝到水邊。',32,'全唐诗/poet.tang.35000.json','["東皇長女沒多年，從洗金芝到水邊。", "無事伴他棊一局，等閑輸却賣花錢。"]'),
('4ea38e73-388d-4b20-96de-ea11881611eb','小遊仙詩九十八首 七十一','曹唐','唐','唐诗','tang','','[]','紅草青林日半斜，閑乘小鳳出彤霞。',32,'全唐诗/poet.tang.35000.json','["紅草青林日半斜，閑乘小鳳出彤霞。", "略尋舊路過西國，因得冰園一尺瓜。"]'),
('a1ef90db-93b9-4ee7-b649-a9b63a5953f8','小遊仙詩九十八首 七十二','曹唐','唐','唐诗','tang','','[]','樹下星沉月欲高，前溪水影濕龍毛。',32,'全唐诗/poet.tang.35000.json','["樹下星沉月欲高，前溪水影濕龍毛。", "洞天雲冷玉花發，公子盡披雙錦袍。"]'),
('d2d41c2a-1a38-40dc-b50d-9f19964c1751','小遊仙詩九十八首 七十三','曹唐','唐','唐诗','tang','','[]','紫水風吹劒樹寒，水邊年少下紅鸞。',32,'全唐诗/poet.tang.35000.json','["紫水風吹劒樹寒，水邊年少下紅鸞。", "未知百一窮陽數，略請先生止的看。"]'),
('da6ed26b-d068-43a8-9431-d13925524fc5','小遊仙詩九十八首 七十四','曹唐','唐','唐诗','tang','','[]','武皇含笑把金觥，更請霓裳一兩聲。',32,'全唐诗/poet.tang.35000.json','["武皇含笑把金觥，更請霓裳一兩聲。", "護帳宮人最年少，舞腰時挈繡裙輕。"]'),
('932b9b54-8768-41e2-8cce-bb41b1f3b29d','小遊仙詩九十八首 七十五','曹唐','唐','唐诗','tang','','[]','瓊樹扶疎壓瑞煙，玉皇朝客滿花前。',32,'全唐诗/poet.tang.35000.json','["瓊樹扶疎壓瑞煙，玉皇朝客滿花前。", "東風小飲人皆醉，短尾青龍枕水眠。"]'),
('8b56272f-fb13-42c9-90a1-f5f302e67e35','小遊仙詩九十八首 七十六','曹唐','唐','唐诗','tang','','[]','彤閣鐘鳴碧鷺飛，皇君催熨紫霞衣。',32,'全唐诗/poet.tang.35000.json','["彤閣鐘鳴碧鷺飛，皇君催熨紫霞衣。", "丹房玉女心慵甚，貪看投壺不肯歸。"]'),
('25a25e6b-022d-4c7f-8baa-df3f2061b8e9','小遊仙詩九十八首 七十七','曹唐','唐','唐诗','tang','','[]','崑崙山上自雞啼，羽客爭昇碧玉梯。',32,'全唐诗/poet.tang.35000.json','["崑崙山上自雞啼，羽客爭昇碧玉梯。", "因駕五龍看較藝，白鸞功用不如妻。"]'),
('e8d7cdbf-9733-4cb5-b1f8-a61e030e92d9','小遊仙詩九十八首 七十八','曹唐','唐','唐诗','tang','','[]','沙野先生閉玉虛，焚香夜寫紫微書。',32,'全唐诗/poet.tang.35000.json','["沙野先生閉玉虛，焚香夜寫紫微書。", "供承童子閑無事，教剉瓊花餵白驢。"]'),
('5938baf6-a1c5-4cb8-883f-86f7ef8d5115','小遊仙詩九十八首 七十九','曹唐','唐','唐诗','tang','','[]','雲隴瓊花滿地香，碧沙紅水遍朱堂。',32,'全唐诗/poet.tang.35000.json','["雲隴瓊花滿地香，碧沙紅水遍朱堂。", "外人欲壓長生籍，拜請飛瓊報玉皇。"]'),
('facc02ca-055a-4a1d-a0a8-3a917c5a19ec','小遊仙詩九十八首 八十','曹唐','唐','唐诗','tang','','[]','玉洞長春風景鮮，丈人私宴就芝田。',32,'全唐诗/poet.tang.35000.json','["玉洞長春風景鮮，丈人私宴就芝田。", "笙歌暫向花間盡，便是人間一萬年。"]'),
('eeb03285-f3f7-47c1-b1dd-0b8931b512b1','小遊仙詩九十八首 八十一','曹唐','唐','唐诗','tang','','[]','青童傳語便須回，報道麻姑玉蘂開。',32,'全唐诗/poet.tang.35000.json','["青童傳語便須回，報道麻姑玉蘂開。", "滄海成塵等閑事，且乘龍鶴看花來。"]'),
('a40936c2-8ace-4cad-9e2c-c9ce95bc38d4','小遊仙詩九十八首 八十二','曹唐','唐','唐诗','tang','','[]','絳樹彤雲戶半開，守花童子怪人來。',32,'全唐诗/poet.tang.35000.json','["絳樹彤雲戶半開，守花童子怪人來。", "青牛臥地喫瓊草，知道先生朝未回。"]'),
('96200dc1-96cf-46b6-b160-0b76afcd4672','小遊仙詩九十八首 八十三','曹唐','唐','唐诗','tang','','[]','石洞沙溪二十年，向明杭日夜朝天。',32,'全唐诗/poet.tang.35000.json','["石洞沙溪二十年，向明杭日夜朝天。", "白礬煙盡水銀冷，不覺小龍牀下眠。"]'),
('dd1d2438-bfba-4eb9-853d-debef47a366f','小遊仙詩九十八首 八十四','曹唐','唐','唐诗','tang','','[]','紫微深鎖敞丹軒，太帝親談不死門。',32,'全唐诗/poet.tang.35000.json','["紫微深鎖敞丹軒，太帝親談不死門。", "從此百寮俱拜後，走龍鞭虎下崑崙。"]'),
('702ee2ff-7191-44ff-8c55-2d25cc5a6a4e','小遊仙詩九十八首 八十五','曹唐','唐','唐诗','tang','','[]','雲衫玉帶好威儀，三洞真人入奏時。',32,'全唐诗/poet.tang.35000.json','["雲衫玉帶好威儀，三洞真人入奏時。", "頻着金鞭打龍角，爲嗔西去上天遲。"]'),
('dca30bd2-ad66-4f22-8476-513998b07056','小遊仙詩九十八首 八十六','曹唐','唐','唐诗','tang','','[]','太子真娥相領行，當天合曲玉簫清。',32,'全唐诗/poet.tang.35000.json','["太子真娥相領行，當天合曲玉簫清。", "棃花新折東風軟，猶在緱山樂笑聲。"]'),
('538c1dac-686c-4cc5-b39d-10f1eb5d9368','小遊仙詩九十八首 八十七','曹唐','唐','唐诗','tang','','[]','洞裏月明瓊樹風，畫簾青室影朦朧。',32,'全唐诗/poet.tang.35000.json','["洞裏月明瓊樹風，畫簾青室影朦朧。", "香殘酒冷玉妃睡，不覺七真歸海中。"]'),
('27c0570a-5dd7-4036-b84c-25c2df80e2fe','小遊仙詩九十八首 八十八','曹唐','唐','唐诗','tang','','[]','青苑紅堂壓瑞雲，月明閑宴九陽君。',32,'全唐诗/poet.tang.35000.json','["青苑紅堂壓瑞雲，月明閑宴九陽君。", "不知昨夜誰先醉，書破明霞八幅裙。"]'),
('47674538-d3e4-4ba4-8476-0de4c576dcee','小遊仙詩九十八首 八十九','曹唐','唐','唐诗','tang','','[]','東溟兩度作塵飛，一萬年來會面稀。',32,'全唐诗/poet.tang.35000.json','["東溟兩度作塵飛，一萬年來會面稀。", "千樹棃花百壺酒，共君論飲莫論詩。"]'),
('00ee808a-abd0-42e9-9be0-ebf4d37cfdef','小遊仙詩九十八首 九十','曹唐','唐','唐诗','tang','','[]','滄海令拋即未能，且緣鸞鶴立相仍。',32,'全唐诗/poet.tang.35000.json','["滄海令拋即未能，且緣鸞鶴立相仍。", "蔡家新婦莫嫌少，領取真珠三五升。"]'),
('389bbb28-98a3-4944-9b85-f1ece5b7cebe','小遊仙詩九十八首 九十一','曹唐','唐','唐诗','tang','','[]','溪影沉沙樹影清，人家皆踏五音行。',32,'全唐诗/poet.tang.35000.json','["溪影沉沙樹影清，人家皆踏五音行。", "可憐三十六天路，星月滿空瓊草青。"]'),
('93715a3c-0494-4fde-9cbe-f62af5ee8f76','小遊仙詩九十八首 九十二','曹唐','唐','唐诗','tang','','[]','北斗西風吹白榆，穆公相笑夜投壺。',32,'全唐诗/poet.tang.35000.json','["北斗西風吹白榆，穆公相笑夜投壺。", "花前玉女來相問，賭得青龍許贖無。"]'),
('285a439d-79b5-451f-992a-3431e35d0546','小遊仙詩九十八首 九十三','曹唐','唐','唐诗','tang','','[]','九天王母皺蛾眉，惆悵無言倚桂枝。',32,'全唐诗/poet.tang.35000.json','["九天王母皺蛾眉，惆悵無言倚桂枝。", "悔不長留穆天子，任將妻妾住瑤池。"]'),
('2ae01b23-96f7-44e9-a32d-e9ef0ceb0577','小遊仙詩九十八首 九十四','曹唐','唐','唐诗','tang','','[]','暫隨鳧伯縱閑遊，飲鹿因過翠水頭。',32,'全唐诗/poet.tang.35000.json','["暫隨鳧伯縱閑遊，飲鹿因過翠水頭。", "宮殿寂寥人不見，碧花菱角滿潭秋。"]'),
('e58c5aea-de33-48ed-822f-b716bf2c0732','小遊仙詩九十八首 九十五','曹唐','唐','唐诗','tang','','[]','新授金書八素章，玉皇教妾主扶桑。',32,'全唐诗/poet.tang.35000.json','["新授金書八素章，玉皇教妾主扶桑。", "與君一別三千歲，却厭仙家日月長。"]'),
('66ddca6a-fb9d-439e-b66e-4fde9b847d6f','小遊仙詩九十八首 九十六','曹唐','唐','唐诗','tang','','[]','八海風涼水影高，上卿教製赤霜袍。',32,'全唐诗/poet.tang.35000.json','["八海風涼水影高，上卿教製赤霜袍。", "蛟絲玉線難裁割，須借玉妃金剪刀。"]'),
('ac1fd190-947e-4617-b98d-0f29b01018de','小遊仙詩九十八首 九十七','曹唐','唐','唐诗','tang','','[]','海上風來吹杏枝，崑崙山上看花時。',32,'全唐诗/poet.tang.35000.json','["海上風來吹杏枝，崑崙山上看花時。", "紅龍錦襜黃金勒，不是元君不得騎。"]'),
('b2f3c108-0507-40ff-afef-3662164c0eb9','小遊仙詩九十八首 九十八','曹唐','唐','唐诗','tang','','[]','絳闕夫人下北方，細環清珮響丁當。',32,'全唐诗/poet.tang.35000.json','["絳闕夫人下北方，細環清珮響丁當。", "攀花笑入春風裏，偷折紅桃寄阮郎。"]'),
('8ca3f847-34a1-46f4-ba4a-4c7cd0d8dc7e','又遊仙詩一絕','曹唐','唐','唐诗','tang','','[]','靖節先生幾代孫，青娥曾接玉郎魂。',32,'全唐诗/poet.tang.35000.json','["靖節先生幾代孫，青娥曾接玉郎魂。", "春風流水還無賴，偷放桃花出洞門。"]'),
('c4f1f2e0-ae1f-41ab-970f-9de7cf4d61a0','題武陵洞五首 一','曹唐','唐','唐诗','tang','','[]','此生終使此身閑，不是春時且要還。',32,'全唐诗/poet.tang.35000.json','["此生終使此身閑，不是春時且要還。", "寄語桃花與流水，莫辭相送到人間。"]'),
('97b079cb-568a-44cb-8715-0fe895f6226d','題武陵洞五首 二','曹唐','唐','唐诗','tang','','[]','溪口回舟日已昏，却聽雞犬隔前村。',32,'全唐诗/poet.tang.35000.json','["溪口回舟日已昏，却聽雞犬隔前村。", "殷勤重與秦人別，莫使桃花閉洞門。"]'),
('75e857c8-8f39-495c-bf82-971bcd6ef3a2','題武陵洞五首 三','曹唐','唐','唐诗','tang','','[]','却恐重來路不通，殷勤回首謝春風。',32,'全唐诗/poet.tang.35000.json','["却恐重來路不通，殷勤回首謝春風。", "白雞黃犬不將去，且寄桃花深洞中。"]'),
('72a74391-ef14-4e13-9869-a3bcbc97d4bf','題武陵洞五首 四','曹唐','唐','唐诗','tang','','[]','桃花夾岸杳何之，花滿春山水去遲。',32,'全唐诗/poet.tang.35000.json','["桃花夾岸杳何之，花滿春山水去遲。", "三宿武陵溪上月，始知人世有秦時。"]'),
('f3f37780-9663-48cf-9404-57f7e320d453','題武陵洞五首 五','曹唐','唐','唐诗','tang','','[]','渡水傍山尋絕壁，白雲飛處洞天開。',32,'全唐诗/poet.tang.35000.json','["渡水傍山尋絕壁，白雲飛處洞天開。", "仙人來往無行跡，石逕春風長綠苔。"]'),
('3861407e-9699-4fdf-b7b7-897a86f14ca5','句','曹唐','唐','唐诗','tang','','[]','斬蛟青海上，射虎黑山頭。',60,'全唐诗/poet.tang.35000.json','["斬蛟青海上，射虎黑山頭。", "簫聲欲盡月色苦，依舊漢家宮樹秋。", "一曲哀歌茂陵道，漢家天子葬秋風。", "誰知漢武無仙骨，滿竈黃金成白煙。"]'),
('52bb5a86-1af9-4f85-bfe7-977a7e11f247','聖政紀頌','來鵠','唐','唐诗','tang','','[]','三皇不書，五帝不紀。',248,'全唐诗/poet.tang.35000.json','["三皇不書，五帝不紀。", "有聖有神，風銷日已。", "何教何師，生來死止。", "無典無法，頑肩奡比。", "三皇實作，五帝實治。", "成天造地，不昏不圯。", "言得非排，文得聖齒。", "表表如見者，莫若乎史。", "是知朴繩休結，正簡斯若。", "君誥臣箴，觚編毫絡。", "前書後經，規善鑒惡。", "國之大章，如何寢略。", "嗚呼！貞觀多吁，永徽多俞。", "廷日發論，殿日發謨。", "牙孽不作，鳥鼠不除。", "論出不蓋，謨行不紆。", "楹然史臣，蛇然史裾。", "瞠瞠而視，逶逶而窶。", "翹筆當面，決防納污。", "不梏爾智，不息我愚。", "執言直注，史文直敷。", "故得粲粲朝典，落落廷謇。", "聖牘既多，堯風不淺。", "頌編坦軸，君出臣顯。"]'),
('ac77a741-d6cc-4047-9e9e-e708f0f2d22e','宛陵送李明府罷任歸江州','來鵠','唐','唐诗','tang','','[]','菊花村晚雁來天，共把離觴向水邊。',64,'全唐诗/poet.tang.35000.json','["菊花村晚雁來天，共把離觴向水邊。", "官滿便尋垂釣侶，家貧已用賣琴錢。", "浪生湓浦千層雪，雲起爐峰一炷煙。", "倘見吾鄉舊知己，爲言顦顇過年年。"]'),
('b70cb525-c13d-410e-b14d-d625f88d3eab','清明日與友人遊玉粒塘莊','來鵠','唐','唐诗','tang','','[]','幾宿春山逐陸郎，清明時節好煙光。',64,'全唐诗/poet.tang.35000.json','["幾宿春山逐陸郎，清明時節好煙光。", "歸穿細荇船頭滑，醉踏殘花屐齒香。", "風急嶺雲飄迥野，雨餘田水落方塘。", "不堪吟罷東回首，滿耳蛙聲正夕陽。"]'),
('52a2c2ba-ca07-461d-8c95-58bc5dfe64f8','寒食山館書情','來鵠','唐','唐诗','tang','','[]','獨把一杯山館中，每經時節恨飄蓬。',64,'全唐诗/poet.tang.35000.json','["獨把一杯山館中，每經時節恨飄蓬。", "侵堦草色連朝雨，滿地梨花昨夜風。", "蜀魄啼來春寂寞，楚魂吟後月朦朧。", "分明記得還家夢，徐孺宅前湖水東。"]'),
('f9bc20c3-5663-4c2e-bcca-1c8e25820147','病起','來鵠','唐','唐诗','tang','','[]','春初一臥到秋深，不見紅芳與綠陰。',64,'全唐诗/poet.tang.35000.json','["春初一臥到秋深，不見紅芳與綠陰。", "窗下展書難久讀，池邊扶杖欲閑吟。", "藕穿平地生荷葉，笋過東家作竹林。", "在舍渾如遠鄉客，詩僧酒伴鎮相尋。"]'),
('291649a3-b0c3-4d02-b55f-21927738cc04','鄂渚除夜書懷','來鵠','唐','唐诗','tang','','[]','鸚鵡洲頭夜泊船，此時形影共淒然。',64,'全唐诗/poet.tang.35000.json','["鸚鵡洲頭夜泊船，此時形影共淒然。", "難歸故國干戈後，欲告何人雨雪天。", "筯撥冷灰書悶字，枕陪寒席帶愁眠。", "自嗟落魄無成事，明日春風又一年。"]'),
('f573c0f4-72e6-4e2c-9eb2-f690c7422808','鄂渚清明日與鄉友登頭陀山','來鵠','唐','唐诗','tang','','[]','冷酒一杯相勸頻，異鄉相遇轉相親。',64,'全唐诗/poet.tang.35000.json','["冷酒一杯相勸頻，異鄉相遇轉相親。", "落花風裏數聲笛，芳草煙中無限人。", "都大此時深悵望，豈堪高處更逡巡。", "思量費子真仙子，不作頭陀山下塵。"]'),
('491e12d6-4fb9-4c00-b315-9fdf952f3f6d','蠶婦','來鵠','唐','唐诗','tang','','["\u5199\u4eba", "\u8bbd\u55bb", "\u5199\u4eba\u8bd7"]','曉夕採桑多苦辛，好花時節不閑身。',32,'全唐诗/poet.tang.35000.json','["曉夕採桑多苦辛，好花時節不閑身。", "若教解愛繁華事，凍殺黃金屋裏人。"]'),
('bb09880b-688f-4f60-9f3c-d2edf32782fd','題廬山雙劒峰','來鵠','唐','唐诗','tang','','["\u5e90\u5c71"]','倚天雙劒古今閑，三尺高於四面山。',32,'全唐诗/poet.tang.35000.json','["倚天雙劒古今閑，三尺高於四面山。", "若使火雲燒得動，始應農器滿人間。"]'),
('6d32b372-5481-4ac0-b0f1-580ab50d05c9','雲','來鵠','唐','唐诗','tang','','[]','千形萬象竟還空，映水藏山片復重。',32,'全唐诗/poet.tang.35000.json','["千形萬象竟還空，映水藏山片復重。", "無限旱苗枯欲盡，悠悠閑處作奇峰。"]'),
('0b823010-6edb-4594-8db7-98b47827647c','金錢花','來鵠','唐','唐诗','tang','','[]','也無稜郭也無神，露洗還同鑄出新。',32,'全唐诗/poet.tang.35000.json','["也無稜郭也無神，露洗還同鑄出新。", "青帝若教花裏用，牡丹應是得錢人。"]'),
('b9e2f62e-e42c-4223-9e16-e976a8ac36ae','曉雞','來鵠','唐','唐诗','tang','','[]','黯黯嚴城罷鼓鼙，數聲相續出寒栖。',32,'全唐诗/poet.tang.35000.json','["黯黯嚴城罷鼓鼙，數聲相續出寒栖。", "不嫌驚破紗窗夢，却怕爲妖半夜啼。"]'),
('75dd09a5-71b9-47d8-9f49-593cfed39750','山中避難作','來鵠','唐','唐诗','tang','','[]','山頭烽火水邊營，鬼哭人悲夜夜聲。',32,'全唐诗/poet.tang.35000.json','["山頭烽火水邊營，鬼哭人悲夜夜聲。", "唯有碧天無一事，日還西下月還明。"]'),
('385dbd50-8382-43c6-ae37-d50a354ae07a','早春','來鵠','唐','唐诗','tang','','[]','新曆才將半紙開，小庭猶聚爆竿灰。',32,'全唐诗/poet.tang.35000.json','["新曆才將半紙開，小庭猶聚爆竿灰。", "偏憎楊柳難鈐轄，又惹東風意緒來。"]'),
('b21b53c7-b74b-4ac4-b7a1-168a86e3a2f7','鷺鷥','來鵠','唐','唐诗','tang','','[]','褭絲翹足傍澄瀾，消盡年光佇思間。',32,'全唐诗/poet.tang.35000.json','["褭絲翹足傍澄瀾，消盡年光佇思間。", "若使見魚無羨意，向人姿態更應閑。"]'),
('3b7c7212-79b7-4d89-bfb6-763add437897','子規','來鵠','唐','唐诗','tang','','[]','雨恨花愁同此冤，啼時聞處正春繁。',32,'全唐诗/poet.tang.35000.json','["雨恨花愁同此冤，啼時聞處正春繁。", "千聲萬血誰哀爾，爭得如花笑不言。"]'),
('925263e8-e4f6-4a92-bab9-263e10418963','新安官舍閑坐','來鵠','唐','唐诗','tang','','[]','寂寞空階草亂生，簟涼風動若爲情。',32,'全唐诗/poet.tang.35000.json','["寂寞空階草亂生，簟涼風動若爲情。", "不知獨坐閑多少，看得蜘蛛結網成。"]'),
('0b54c55e-4d58-4be6-bf67-052ff111c06a','除夜','來鵠','唐','唐诗','tang','','[]','事關休戚已成空，萬里相思一夜中。',32,'全唐诗/poet.tang.35000.json','["事關休戚已成空，萬里相思一夜中。", "愁到曉雞聲絕後，又將顦顇見春風。"]'),
('5926bdfb-7c59-4ecf-9ec8-c6b6050227f1','游魚','來鵠','唐','唐诗','tang','','[]','弄萍隈荇思夷猶，掉尾揚鬐逐慢流。',32,'全唐诗/poet.tang.35000.json','["弄萍隈荇思夷猶，掉尾揚鬐逐慢流。", "應怕碧巖巖下水，浮藤如線月如鉤。"]'),
('a49e6c91-9d64-47a5-8cab-3060d1b3ed94','鸚鵡','來鵠','唐','唐诗','tang','','[]','色白還應及雪衣，觜紅毛綠語仍奇。',32,'全唐诗/poet.tang.35000.json','["色白還應及雪衣，觜紅毛綠語仍奇。", "年年鎖在金籠裏，何似隴山閑處飛。"]'),
('8bfb96cb-6d18-434c-b802-1c34a49e12a6','偶題二首 一','來鵠','唐','唐诗','tang','','[]','近來靈鵲語何疎，獨凭欄干恨有殊。',32,'全唐诗/poet.tang.35000.json','["近來靈鵲語何疎，獨凭欄干恨有殊。", "一夜綠荷霜翦破，賺他秋雨不成珠。"]'),
('a60d0ee3-d3f3-44ed-87c3-d1c60ce06cb5','偶題二首 二','來鵠','唐','唐诗','tang','','[]','水邊箕踞靜書空，欲解愁腸酒不濃。',32,'全唐诗/poet.tang.35000.json','["水邊箕踞靜書空，欲解愁腸酒不濃。", "可惜青天好雷雹，只能驅趂懶蛟龍。"]'),
('04ccab35-217d-4866-9c52-03449ddfe5b3','惜花','來鵠','唐','唐诗','tang','','[]','東風漸急夕陽斜，一樹夭桃數日花。',32,'全唐诗/poet.tang.35000.json','["東風漸急夕陽斜，一樹夭桃數日花。", "爲惜紅芳今夜裏，不知和月落誰家。"]'),
('59cf3dc1-497f-48e1-b4f9-f6acb2b1978e','洞庭隐','來鵠','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','高臥洞庭三十春，芰荷香裏獨垂綸。',32,'全唐诗/poet.tang.35000.json','["高臥洞庭三十春，芰荷香裏獨垂綸。", "莫嫌無事閑銷日，有事始憐無事人。"]'),
('bfc49d49-4140-4650-b28f-1de9792fdde7','古劒池','來鵠','唐','唐诗','tang','','[]','秋水蓮花三四枝，我來慷慨步遲遲。',32,'全唐诗/poet.tang.35000.json','["秋水蓮花三四枝，我來慷慨步遲遲。", "不決浮雲斬邪佞，直成龍去欲何爲。"]'),
('a1bf254c-171e-4842-89f0-2f616b635cdb','梅花','來鵠','唐','唐诗','tang','','[]','枝枝倚檻照池冰，粉薄香殘恨不勝。',32,'全唐诗/poet.tang.35000.json','["枝枝倚檻照池冰，粉薄香殘恨不勝。", "占得早芳何所利，與他霜雪助威稜。"]'),
('c5acc0ee-6f84-4905-a0ec-791cf855d91a','聞蟬','來鵠','唐','唐诗','tang','','[]','綠槐陰裏一聲新，霧薄風輕力未勻。',32,'全唐诗/poet.tang.35000.json','["綠槐陰裏一聲新，霧薄風輕力未勻。", "莫道聞時總惆悵，有愁人有不愁人。"]'),
('3c82ff83-d0a2-4c1d-bddf-4dc8ad9d88b8','賣花謠','來鵠','唐','唐诗','tang','','[]','紫豔紅苞價不同，匝街羅列起香風。',32,'全唐诗/poet.tang.35000.json','["紫豔紅苞價不同，匝街羅列起香風。", "無言無語呈顏色，知落誰家池館中。"]'),
('91a8a81a-bc86-4fc2-96c9-57ea31235e29','子規','來鵠','唐','唐诗','tang','','[]','月落空山聞數聲，此時孤館酒初醒。',32,'全唐诗/poet.tang.35000.json','["月落空山聞數聲，此時孤館酒初醒。", "投人語若似伊淚，口畔血流應始聽。"]'),
('c6d55862-018e-4602-9f98-3ee3123133e4','句','來鵠','唐','唐诗','tang','','[]','回眸綠水波初起，合掌白蓮花未開。',16,'全唐诗/poet.tang.35000.json','["回眸綠水波初起，合掌白蓮花未開。"]'),
('fd364eb0-a4f3-42ef-87b3-bc568f503e1a','菊','李山甫','唐','唐诗','tang','','[]','籬下霜前偶得存，忍教遲晚避蘭蓀。',64,'全唐诗/poet.tang.35000.json','["籬下霜前偶得存，忍教遲晚避蘭蓀。", "也銷造化無多力，未受陽和一點恩。", "栽處不容依玉砌，要時還許上金尊。", "陶潛歿後誰知己，露滴幽叢見淚痕。"]'),
('20f92b56-d7f3-4553-94f1-9a5570d20018','風','李山甫','唐','唐诗','tang','','[]','喜怒寒暄直不勻，終無形狀始無因。',64,'全唐诗/poet.tang.35000.json','["喜怒寒暄直不勻，終無形狀始無因。", "能將塵土平欺客，愛把波瀾枉陷人。", "飄樂遰香隨日在，綻花開柳逐年新。", "深知造化由君力，試爲吹噓借與春。"]'),
('e76e36ea-75e8-43b2-b8aa-2df21dcb6946','月','李山甫','唐','唐诗','tang','','[]','狡兔頑蟾死復生，度雲經漢澹還明。',64,'全唐诗/poet.tang.35000.json','["狡兔頑蟾死復生，度雲經漢澹還明。", "夜長雖耐對君坐，年少不禁隨爾行。", "玉桂影搖烏鵲動，金波寒注鬼神驚。", "人間半被虛拋擲，唯向孤吟客有情。"]');
